/* EXAMEN GLOBAL: Todas las preguntas de IPLEI */
const EXAM_DATA = [
// --- PREGUNTAS DE LA PLATAFORMA (MOODLE) ---
    { u: "IPLE T1", q: "¿Cuáles son los tres elementos que componen el mercado laboral?", opts: ["La oferta, los demandantes de empleo y los intermediarios", "Los trabajadores por cuenta propia, los trabajadores por cuenta ajena y los funcionarios", "Las pymes, las grandes empresas y las administraciones públicas", "La empleabilidad, la demanda empresarial y la FP"], ans: 0, exp: "El mercado laboral está formado por la oferta (empresas que ofrecen puestos), la demanda (personas que buscan empleo) y los intermediarios (agencias, SEPE)." },
    { u: "IPLE T1", q: "La incorporación al mercado laboral:", opts: ["No requiere una formación previa apropiada", "Ha dejado de ser un desafío para los trabajadores españoles", "Hace referencia a la entrada de individuos en edad de trabajar a la actividad económica", "Todas son correctas"], ans: 2, exp: "La inserción o incorporación es el proceso por el cual las personas en edad activa comienzan a participar en la economía productiva." },
    { u: "IPLE T1", q: "Los autónomos económicamente dependientes (TRADE):", opts: ["Son aquellos cuya facturación en un 75 % o más depende de un solo cliente, ya sea persona física o jurídica", "Son aquellos que desarrollan actividades que están categorizadas como profesionales", "Son aquellos que administran sociedades mercantiles con un 75 % o más de su facturación dependiente de ellos", "Son aquellos que generan de manera propia, al menos, un 75 % del valor del total de su actividad profesional"], ans: 0, exp: "La figura del TRADE está legalmente definida para aquellos autónomos que obtienen al menos el 75% de sus ingresos de un único pagador/cliente." },
    { u: "IPLE T1", q: "El tipo de relación laboral que se da cuando el trabajo se hace de forma voluntaria, personal y directa, pero organizado por una tercera persona, y a cambio se percibe un salario, se denomina:", opts: ["Trabajo por cuenta propia", "Trabajo autónomo", "Trabajo profesional", "Trabajo por cuenta ajena"], ans: 3, exp: "El trabajo por cuenta ajena implica ajenidad en los riesgos y en los frutos, subordinación y remuneración." },
    { u: "IPLE T1", q: "El sistema selectivo de acceso a la función pública consistente en la celebración de algunas pruebas o exámenes que determinan la capacidad y aptitud de los solicitantes, generando un orden de clasificación, se denomina:", opts: ["Concurso", "Evaluación funcionarial", "Oposición", "Conculcación"], ans: 2, exp: "La oposición es el sistema basado estrictamente en la superación de pruebas objetivas para medir mérito y capacidad." },
    { u: "IPLE T1", q: "Señala cuál de las siguientes no es una de las categorías de personal al servicio de la Administración Pública:", opts: ["Funcionario interino", "Funcionario autónomo dependiente", "Personal laboral temporal", "Funcionario de carrera"], ans: 1, exp: "No existe la figura de 'funcionario autónomo dependiente' en la Administración Pública; los autónomos TRADE pertenecen al sector privado." },
    { u: "IPLE T1", q: "Engloba los cinco documentos que permiten comunicar en toda la UE, de manera simple y comprensible, las habilidades, capacidades, titulaciones y certificaciones adquiridas por un profesional:", opts: ["Tu Europa", "Europass", "DocUE", "EURES CV"], ans: 1, exp: "El Europass es el estándar de la UE para presentar de forma unificada el currículum, competencias e idiomas." },
    { u: "IPLE T1", q: "El principal programa de promoción y financiación educativa en la Unión Europea es:", opts: ["Programa Erasmus+ 2021-2027", "Fondos Next Generation UE", "Acciones Jean Monet", "Red EURES"], ans: 0, exp: "Erasmus+ es el programa estrella de la UE para apoyar la educación, la formación, la juventud y el deporte." },
    { u: "IPLE T1", q: "La disposición mental y emocional de una persona hacia una situación, persona, objeto o tarea se denomina:", opts: ["Aptitud", "Competencia", "Actitud", "Proactividad"], ans: 2, exp: "La actitud (con C) refleja el comportamiento y la predisposición emocional, a diferencia de la aptitud (conocimiento/habilidad)." },
    { u: "IPLE T1", q: "La Zona de Desarrollo Próximo:", opts: ["Sirve para guiar e inspirar a equipos de trabajo cercanos, estableciendo una meta compartida", "Ayuda a expresar ideas claramente y practicar la escucha activa", "Se ubica en el entorno laboral del trabajador y se compone de las herramientas que debe manejar en su puesto", "Permite enfocarse en habilidades y competencias que están al alcance y se pueden desarrollar"], ans: 3, exp: "La ZDP es el espacio entre lo que sabes hacer solo y lo que puedes llegar a hacer con la ayuda, guía o aprendizaje adecuado." },

    // --- BLOQUE CUESTIONARIO DE AUTOEVALUACIÓN (60 PREGUNTAS) ---
    { u: "IPLE T1", q: "¿A qué hace referencia el proceso de incorporación o inserción al mercado laboral?", opts: ["A la jubilación de los trabajadores senior.", "A la entrada de individuos en edad de trabajar a la actividad económica.", "Únicamente al primer empleo de un recién graduado.", "A la solicitud de prestaciones por desempleo."], ans: 1, exp: "Se define como el proceso por el cual las personas activas se integran a la fuerza laboral económica." },
    { u: "IPLE T1", q: "¿Qué factores suelen implicar una inserción laboral efectiva?", opts: ["Solo tener contactos personales.", "Formación previa, gestión de experiencia y uso de vías ajustadas al perfil.", "Depender exclusivamente del azar del mercado.", "Evitar la formación continua y buscar cualquier puesto al azar."], ans: 1, exp: "Requiere una estrategia combinada de buena formación, habilidades y búsqueda activa enfocada en el perfil del candidato." },
    { u: "IPLE T1", q: "¿Cuál es un desafío persistente para los jóvenes en el mercado laboral español?", opts: ["La falta de títulos universitarios.", "Alta tasa de desempleo, precariedad y sobrecualificación.", "El exceso de ofertas de empleo estable.", "La prohibición legal de trabajar antes de los 25 años."], ans: 1, exp: "El desempleo juvenil, los contratos temporales y estar sobrecualificado para el puesto son los mayores retos en España." },
    { u: "IPLE T1", q: "¿Qué tecnología ha impactado significativamente la naturaleza del trabajo en la última década?", opts: ["El fax y el telegrama.", "La Inteligencia Artificial (IA) y la automatización.", "La radiofrecuencia analógica.", "Las máquinas de escribir eléctricas."], ans: 1, exp: "La automatización y la IA están transformando aceleradamente los procesos en casi todas las industrias." },
    { u: "IPLE T1", q: "¿Qué beneficio principal aporta la IA en industrias como la medicina o el Derecho?", opts: ["La eliminación total de los profesionales humanos.", "Incrementar la eficiencia y acelerar o adaptar procesos.", "Reducir la productividad para evitar el estrés laboral.", "Duplicar el tiempo necesario para las tareas rutinarias."], ans: 1, exp: "La IA sirve como herramienta de apoyo para procesar datos más rápido y mejorar la eficiencia, sin reemplazar al experto." },
    { u: "IPLE T1", q: "¿En qué se centra principalmente el sector cuaternario?", opts: ["En la agricultura y ganadería extensiva.", "En la ampliación del conocimiento, la investigación y el desarrollo.", "En el comercio minorista tradicional.", "En la extracción de materias primas naturales."], ans: 1, exp: "El sector cuaternario engloba la investigación (I+D), la tecnología y la gestión avanzada del conocimiento." },
    { u: "IPLE T1", q: "¿Cuál de los siguientes es un perfil requerido por el sector cuaternario?", opts: ["Peón agrícola.", "Experto en ciberseguridad o desarrollador de software.", "Repartidor de mensajería básica.", "Operario de cadena de montaje tradicional."], ans: 1, exp: "Al basarse en el conocimiento, demanda profesionales altamente tecnológicos (TIC)." },
    { u: "IPLE T1", q: "¿Por qué existe una gran demanda de especialistas en sostenibilidad?", opts: ["Por la escasez de recursos naturales en todo el mundo.", "Debido al empuje de Europa hacia las energías renovables y campos verdes.", "Porque es una moda pasajera sin impacto económico real.", "Por la prohibición total de usar plásticos en las empresas."], ans: 1, exp: "El Pacto Verde Europeo y las nuevas normativas fuerzan a las empresas a buscar expertos medioambientales." },
    { u: "IPLE T1", q: "¿Qué paradoja se detecta actualmente en el mercado laboral nacional español?", opts: ["Hay demasiados electricistas y soldadores.", "Una escasez preocupante de profesionales en oficios tradicionales (metalurgia, construcción).", "Nadie quiere trabajar en el sector tecnológico.", "Existe un exceso de programadores de Inteligencia Artificial."], ans: 1, exp: "A pesar del alto paro juvenil, faltan trabajadores cualificados en oficios técnicos y manuales básicos." },
    { u: "IPLE T1", q: "¿Qué oficios técnicos se mencionan como difíciles de cubrir para las empresas?", opts: ["Filósofos y poetas.", "Soldadores, electricistas, mecánicos industriales y fontaneros.", "Auxiliares de biblioteca únicamente.", "Administrativos y recepcionistas."], ans: 1, exp: "La Formación Profesional industrial es actualmente una de las vías de empleo con mayor déficit de trabajadores." },
    { u: "IPLE T1", q: "¿Qué tipo de relación laboral se define como voluntaria, personal y organizada por un tercero a cambio de salario?", opts: ["Trabajo por cuenta propia.", "Trabajo por cuenta ajena.", "Voluntariado no remunerado.", "Trabajo en régimen de cooperativa."], ans: 1, exp: "Esa es la definición jurídica exacta de un trabajador por cuenta ajena recogido en el Estatuto de los Trabajadores." },
    { u: "IPLE T1", q: "¿Qué se considera un trabajador autónomo?", opts: ["El que trabaja para una multinacional con contrato fijo.", "Quien tiene un pequeño negocio o desempeña un trabajo habitual por sí mismo.", "El personal que limpia oficinas por cuenta ajena.", "El empleado público que obtiene una plaza de carrera."], ans: 1, exp: "El autónomo trabaja por cuenta propia, asumiendo el riesgo y organizando sus propios medios de producción." },
    { u: "IPLE T1", q: "¿Quiénes son los profesionales autónomos?", opts: ["Trabajadores sin formación específica.", "Aquellos que desarrollan actividades categorizadas como profesionales en el IAE (ej. abogados, arquitectos).", "Solo los dueños de grandes fábricas y naves industriales.", "Únicamente los artistas y artesanos locales."], ans: 1, exp: "Pertenecen a colegios profesionales o epígrafes específicos del Impuesto de Actividades Económicas." },
    { u: "IPLE T1", q: "¿Qué caracteriza al autónomo económicamente dependiente (TRADE)?", opts: ["Su facturación depende de al menos diez clientes distintos por igual.", "Su facturación depende en un 75% o más de un solo cliente.", "No paga impuestos de autónomo en su primer año.", "Su facturación es 100% libre de retenciones IRPF."], ans: 1, exp: "Para evitar la figura del falso autónomo y darle protección, se define legalmente a quien depende económicamente de un solo pagador (>75%)." },
    { u: "IPLE T1", q: "¿Qué garantía especial ofrece el contrato de un TRADE?", opts: ["Ninguna, es un contrato civil común.", "Garantías similares a las de un trabajador por cuenta ajena (vacaciones, jornada máxima).", "Exención de trabajar más de cuatro horas al día.", "Jubilación anticipada a los 50 años garantizada."], ans: 1, exp: "La ley le otorga protecciones como derecho a 18 días de vacaciones e indemnizaciones por fin de contrato." },
    { u: "IPLE T1", q: "¿Qué es un autónomo colaborador?", opts: ["Un socio externo que invierte capital en la empresa.", "El cónyuge o familiar directo del autónomo que trabaja con él regularmente.", "Una empresa de trabajo temporal subcontratada.", "Un estudiante en prácticas no remuneradas."], ans: 1, exp: "Es el familiar directo (hasta 2º grado) que convive y trabaja habitualmente en el negocio familiar." },
    { u: "IPLE T1", q: "¿Cómo se denomina al administrador de una sociedad mercantil que debe darse de alta como autónomo?", opts: ["Autónomo de carrera.", "Autónomo societario.", "Autónomo interino.", "Autónomo dependiente."], ans: 1, exp: "Quienes poseen el control de una S.L. o S.A. y trabajan en ella tributan en el RETA como autónomos societarios." },
    { u: "IPLE T1", q: "¿Qué norma rige principalmente a los funcionarios en España?", opts: ["El Código de Comercio.", "El Estatuto Básico del Empleado Público (EBEP).", "El Estatuto de los Trabajadores exclusivamente.", "El convenio colectivo del sector metalúrgico."], ans: 1, exp: "El EBEP es la ley marco que regula los derechos y deberes de todos los empleados públicos." },
    { u: "IPLE T1", q: "¿Qué principios rigen el ingreso a la función pública según la Constitución?", opts: ["Contactos personales y antigüedad.", "Igualdad, mérito y capacidad.", "Solo el orden de llegada a la solicitud telemática.", "Nivel de ingresos y patrimonio personal."], ans: 1, exp: "La Constitución Española garantiza el acceso al empleo público basándose estrictamente en los principios de igualdad, mérito y capacidad." },
    { u: "IPLE T1", q: "¿Qué elementos componen el mercado laboral?", opts: ["Salario, oficina y transporte público.", "Oferta, demanda e intermediarios.", "Jefe, empleado y representantes sindicales.", "Estado, empresas privadas y sindicatos."], ans: 1, exp: "Estos tres agentes interactúan para formar y equilibrar el mercado de trabajo." },
    { u: "IPLE T1", q: "En el mercado laboral, ¿qué es la demanda?", opts: ["Los puestos de trabajo disponibles en las empresas.", "Las personas que están en búsqueda de empleo y quieren trabajar.", "Las leyes que regulan las condiciones de despido.", "El conjunto de ofertas publicadas por las empresas."], ans: 1, exp: "Ojo con los términos: la 'demanda de empleo' la hacen los trabajadores que buscan un puesto, la 'oferta de empleo' la ponen las empresas." },
    { u: "IPLE T1", q: "¿Cuál es el papel de los intermediarios laborales?", opts: ["Pagar los salarios a cuenta de los empresarios.", "Unir la demanda con la oferta de forma rápida y efectiva.", "Sancionar a las empresas que no contratan de forma indefinida.", "Dictar las leyes laborales y convenios colectivos."], ans: 1, exp: "Actúan como puente (ej. Infojobs, SEPE, ETTs) para que el que busca empleo encuentre a la empresa que lo necesita." },
    { u: "IPLE T1", q: "¿Cuál de los siguientes es un intermediario laboral?", opts: ["Una administración pública de justicia.", "Empresas de Trabajo Temporal (ETT) o servicios públicos de empleo.", "Una tienda de ropa al por menor.", "Un sindicato de trabajadores interinos."], ans: 1, exp: "Las ETTs y oficinas del SEPE son los intermediarios clásicos." },
    { u: "IPLE T1", q: "¿Qué suele incluir una oferta de trabajo por cuenta ajena en el sector privado?", opts: ["Los antecedentes penales de todos los miembros de la directiva.", "Requisitos mínimos, habilidades necesarias y descripción del puesto.", "El presupuesto anual de la empresa detallado.", "El número de cuenta bancaria del futuro empleado."], ans: 1, exp: "La oferta describe qué perfil se busca y qué tareas se realizarán en la empresa." },
    { u: "IPLE T1", q: "¿Qué tres niveles administrativos existen en España para el empleo público?", opts: ["Municipal, provincial y nacional.", "Estatal, autonómico y local.", "Europeo, nacional y privado.", "Internacional, nacional y regional."], ans: 1, exp: "Se dividen en Administración del Estado (nacional), Comunidades Autónomas y Administración Local (Ayuntamientos/Diputaciones)." },
    { u: "IPLE T1", q: "¿Qué titulación se exige para acceder al Grupo B de funcionarios?", opts: ["Título universitario de Grado.", "Título de Técnico Superior (FP de Grado Superior).", "Graduado en ESO.", "Doctorado o Máster Oficial."], ans: 1, exp: "El Grupo B es específico para quienes poseen el título de Técnico Superior." },
    { u: "IPLE T1", q: "¿Qué título se requiere generalmente para el acceso al Grupo A?", opts: ["Bachillerato.", "Título universitario de Grado.", "Ciclo Formativo de Grado Medio.", "Graduado en ESO."], ans: 1, exp: "El Grupo A (subdividido en A1 y A2) es el de mayor rango y exige titulación universitaria." },
    { u: "IPLE T1", q: "¿Para qué grupo de funcionarios se exige el título de Bachiller o Técnico (FP Grado Medio)?", opts: ["Grupo A.", "Grupo C1.", "Grupo E.", "Grupo B."], ans: 1, exp: "El Grupo C1 requiere Bachillerato o título de Técnico (Grado Medio). El C2 exige solo la ESO." },
    { u: "IPLE T1", q: "¿Qué determina la clasificación en subgrupos como A1/A2 o C1/C2?", opts: ["La edad de los candidatos presentados.", "El nivel de responsabilidad, las funciones del puesto y las características de las pruebas.", "El lugar geográfico donde se encuentre la plaza.", "La nota de corte del examen de conducir."], ans: 1, exp: "Los subgrupos jerarquizan la dificultad de la oposición y el salario según las competencias del puesto." },
    { u: "IPLE T1", q: "¿En qué consiste el sistema selectivo de oposición?", opts: ["Solo en presentar el currículum vitae y esperar llamada.", "En la realización de pruebas o exámenes para determinar la capacidad y aptitud de los solicitantes.", "En una entrevista personal sin contenido técnico ni temario.", "En un sorteo público ante notario."], ans: 1, exp: "Es el sistema más justo donde la nota del examen marca el orden de selección." },
    { u: "IPLE T1", q: "¿Qué se valora en un concurso para el empleo público?", opts: ["La rapidez en entregar el examen completado.", "Los méritos acreditados (experiencia previa, formación, idiomas, etc.).", "La suerte en un sorteo.", "El resultado de un examen tipo test de cultura general."], ans: 1, exp: "En el concurso no hay examen, solo baremación por puntos del currículum y vida laboral." },
    { u: "IPLE T1", q: "¿Qué es el concurso-oposición?", opts: ["Un sorteo entre los candidatos que tienen más méritos.", "La celebración sucesiva de exámenes (oposición) y valoración posterior de méritos (concurso).", "Un sistema exclusivo de nombramiento para cargos políticos.", "Una entrevista personal de recursos humanos sin valoración objetiva."], ans: 1, exp: "Combina ambos sistemas: primero hay que aprobar el examen para que después te sumen los puntos de tus méritos." },
    { u: "IPLE T1", q: "¿Quiénes son los funcionarios interinos?", opts: ["Los que tienen una plaza fija otorgada para siempre.", "Personal temporal que atiende razones justificadas de urgencia o necesidad, ocupando plazas vacantes.", "El personal externo que trabaja en empresas privadas subcontratadas.", "Los funcionarios de carrera en periodo de prácticas pre-nombramiento."], ans: 1, exp: "El interino cubre el puesto temporalmente hasta que la plaza es ocupada por un funcionario de carrera o se elimina." },
    { u: "IPLE T1", q: "¿Qué rige al personal laboral de las Administraciones Públicas?", opts: ["Solo el Reglamento del Congreso de los Diputados.", "El Derecho laboral (Estatuto de los Trabajadores) y su convenio colectivo.", "No tienen leyes específicas que los amparen.", "El Código Penal y Civil."], ans: 1, exp: "El personal laboral firma un contrato de trabajo normal, aunque la empresa que les contrate sea el Estado." },
    { u: "IPLE T1", q: "¿Qué portal europeo ofrece información sobre voluntariado y trabajo fuera de Europa?", opts: ["Portal de la Transparencia.", "Portal Europeo de la Juventud.", "Infojobs Europa.", "Portal SEPE Internacional."], ans: 1, exp: "Está diseñado para orientar a los jóvenes en oportunidades de movilidad, voluntariado solidario y empleo." },
    { u: "IPLE T1", q: "¿Qué información proporciona el portal 'Tu Europa'?", opts: ["La previsión meteorológica de todos los países miembros.", "Información práctica sobre residir, estudiar, trabajar, becas y ayudas en distintos países de la UE.", "Reservas de hoteles con descuento para funcionarios.", "Los trámites para obtener la nacionalidad estadounidense."], ans: 1, exp: "Es el portal oficial para conocer tus derechos y obligaciones legales al mudarte a otro país de la Unión." },
    { u: "IPLE T1", q: "¿Cuál es el objetivo principal de Europass?", opts: ["Vender cursos privados de idiomas.", "Unificar criterios para comunicar habilidades, experiencia y titulaciones en toda la UE de forma estandarizada y comprensible.", "Crear un pasaporte físico único para cruzar fronteras al trabajar.", "Obligar a todos los ciudadanos a hablar inglés en el entorno laboral."], ans: 1, exp: "Homologa el formato de currículum para que las empresas de cualquier país europeo lo entiendan fácilmente." },
    { u: "IPLE T1", q: "¿Cuál de estos es un documento oficial de Europass?", opts: ["El DNI europeo.", "El CV Europass y el Pasaporte de las Lenguas Europass.", "La Tarjeta Sanitaria Europea.", "El pasaporte diplomático de la Unión Europea."], ans: 1, exp: "El portfolio Europass incluye el CV, el pasaporte de idiomas, el documento de movilidad y los suplementos al título." },
    { u: "IPLE T1", q: "¿Qué periodo abarca el actual programa Erasmus+ mencionado en el texto?", opts: ["2010-2020.", "2021-2027.", "2000-2015.", "2024-2030."], ans: 1, exp: "Es el marco financiero temporal actual dotado de fondos para becar la movilidad europea." },
    { u: "IPLE T1", q: "¿En qué se centra la Acción Clave 1 (KA1) de Erasmus+?", opts: ["En la investigación científica sobre el espacio.", "En la movilidad educativa de los ciudadanos (estudiantes y profesores).", "En la compra de material tecnológico escolar.", "En la construcción de nuevas escuelas públicas."], ans: 1, exp: "La Acción KA1 está destinada específicamente a becar los viajes y estancias formativas en el extranjero." },
    { u: "IPLE T1", q: "¿Qué meta fundamental tiene la red EURES?", opts: ["Controlar la entrada en las aduanas y fronteras exteriores.", "Facilitar la cooperación laboral, la movilidad y la libre circulación de trabajadores en la UE y países asociados.", "Imponer salarios mínimos idénticos en toda Europa.", "Prohibir el trabajo a los ciudadanos fuera de su país de origen."], ans: 1, exp: "European Employment Services conecta los servicios públicos de empleo para ofrecer ofertas de trabajo a nivel transnacional." },
    { u: "IPLE T1", q: "¿Qué servicios concretos ofrece EURES?", opts: ["Préstamos bancarios a bajo interés para jóvenes.", "Información sobre condiciones de vida, orientación laboral e intermediación de ofertas y demandas de empleo.", "Transporte gratuito en tren para mudanzas internacionales.", "Alojamiento gratuito para todos los jóvenes europeos que viajen."], ans: 1, exp: "Los consejeros EURES asesoran sobre el coste de vida, impuestos y cómo adaptar el CV al país de destino." },
    { u: "IPLE T1", q: "¿Qué es la 'actitud' en el entorno laboral?", opts: ["Los conocimientos técnicos o universitarios adquiridos.", "La disposición mental, el comportamiento y la respuesta emocional hacia una tarea o situación.", "El título académico obtenido tras años de estudio.", "El sueldo que se espera ganar en el puesto."], ans: 1, exp: "La actitud es el 'cómo' nos enfrentamos a las cosas (optimismo, resiliencia, negatividad)." },
    { u: "IPLE T1", q: "¿Qué actitud implica anticiparse a los problemas, tomar la iniciativa y proponer soluciones?", opts: ["Flexibilidad.", "Proactividad.", "Empatía.", "Pasividad reflexiva."], ans: 1, exp: "Un trabajador proactivo no espera a que le den órdenes; prevé las necesidades y actúa de antemano." },
    { u: "IPLE T1", q: "¿Qué es la flexibilidad y adaptabilidad en el puesto de trabajo?", opts: ["Trabajar siempre las mismas horas en el mismo sitio pase lo que pase.", "Amoldarse a los cambios, nuevas situaciones y desafíos de un entorno profesional dinámico.", "Hacer estrictamente solo las tareas indicadas en el contrato original.", "Rechazar cualquier innovación tecnológica por miedo al cambio."], ans: 1, exp: "Es una de las 'Soft Skills' más demandadas hoy en día debido a lo rápido que evoluciona la tecnología y los mercados." },
    { u: "IPLE T1", q: "¿A qué hace referencia la 'aptitud' profesional?", opts: ["A la sonrisa constante que se tiene en el trabajo de cara al público.", "A la capacidad (innata o adquirida), destreza y habilidad para realizar tareas de forma idónea.", "A la vestimenta profesional que se usa para la entrevista.", "A la puntualidad exclusiva del trabajador al inicio de la jornada."], ans: 1, exp: "Aptitud (con P) engloba lo que 'sabemos y podemos hacer' (habilidades duras y destrezas)." },
    { u: "IPLE T1", q: "¿Qué aptitud implica el dominio de herramientas, software y técnicas de un campo específico?", opts: ["Habilidades de comunicación.", "Conocimientos técnicos (Hard Skills).", "Positividad y resiliencia.", "Gestión de las emociones y el estrés."], ans: 1, exp: "Saber programar, usar AutoCAD o conocer contabilidad son aptitudes puramente técnicas." },
    { u: "IPLE T1", q: "¿Qué requiere la 'capacidad de aprendizaje continuo' (Lifelong learning)?", opts: ["Dejar de estudiar definitivamente una vez se tiene el título oficial.", "Estar siempre dispuesto a aprender, reciclarse y actualizarse ante los rápidos avances tecnológicos y metodológicos.", "Hacer únicamente un curso al año porque la empresa obliga a ello.", "Memorizar todos los manuales teóricos de la empresa el primer día."], ans: 1, exp: "En el sector cuaternario y TIC, si no sigues aprendiendo constantemente, tus conocimientos se quedan obsoletos rápido." },
    { u: "IPLE T1", q: "¿Qué permiten las 'competencias personales y sociales' (Soft Skills)?", opts: ["Trabajar de forma totalmente aislada frente a un ordenador sin hablar con nadie.", "Desenvolverse de forma eficaz, comunicarse bien y resolver conflictos en diferentes contextos públicos y privados.", "Solo sirven para integrarse en las fiestas de la empresa.", "Evitar el contacto visual con clientes problemáticos."], ans: 1, exp: "Incluyen empatía, comunicación asertiva, negociación y liderazgo, fundamentales para la convivencia en la empresa." },
    { u: "IPLE T1", q: "¿Qué implica 'trabajar en equipo' de forma efectiva?", opts: ["Que una sola persona asuma la carga y haga todo el trabajo.", "Colaborar coordinadamente con otros compañeros para la consecución de un objetivo común.", "Competir agresivamente con los compañeros para destacar ante el jefe.", "Trabajar en el mismo espacio físico pero sin comunicarse ni compartir datos."], ans: 1, exp: "Requiere sumar esfuerzos, comunicarse y apoyarse mutuamente para lograr el éxito colectivo." },
    { u: "IPLE T1", q: "¿Qué es la 'empatía' en el entorno laboral?", opts: ["Ignorar las opiniones personales de los demás para terminar los proyectos más rápido.", "La capacidad de entender, comprender y valorar los sentimientos, problemas y perspectivas de los compañeros o clientes.", "Ser el jefe que da órdenes estrictas sin admitir réplica.", "Delegar todo el trabajo emocional en los compañeros de Recursos Humanos."], ans: 1, exp: "Es 'ponerse en los zapatos del otro', clave para la atención al cliente y evitar conflictos internos." },
    { u: "IPLE T1", q: "¿Qué busca maximizar la 'gestión del tiempo'?", opts: ["El número de descansos y cafés que se toman durante la jornada.", "La productividad y el cumplimiento de plazos mediante la priorización y organización de tareas.", "Las horas extras no remuneradas que se pueden acumular.", "Terminar antes la jornada laboral saltándose los protocolos de calidad."], ans: 1, exp: "Organizar bien la agenda permite sacar adelante el trabajo sin estrés y llegar a los 'deadlines'." },
    { u: "IPLE T1", q: "¿Qué define al verdadero 'liderazgo'?", opts: ["Mandar, ordenar y exigir a todos sin escuchar sugerencias.", "Guiar, motivar e inspirar a los equipos hacia una meta compartida, potenciando sus habilidades.", "Ser la persona que más años de antigüedad lleva en la empresa.", "Evitar tomar decisiones importantes para no equivocarse nunca."], ans: 1, exp: "El líder empuja al grupo con el ejemplo y la motivación, no solo basándose en su autoridad jerárquica." },
    { u: "IPLE T1", q: "¿Qué es la Zona de Desarrollo Próximo (ZDP) introducida por Vygotsky?", opts: ["El área geográfica de la ciudad donde se concentran las mayores empresas del sector.", "El espacio psicológico y de aprendizaje entre lo que alguien puede hacer solo y lo que puede lograr con guía o colaboración.", "La oficina más cercana a la residencia del trabajador.", "El horario de mayor productividad del día para una persona."], ans: 1, exp: "Es el 'punto dulce' del aprendizaje: retos que no sabes hacer solo aún, pero que puedes resolver si un experto te enseña." },
    { u: "IPLE T1", q: "¿Por qué es útil identificar tu propia ZDP en el trabajo?", opts: ["Para saber en qué lugares están los mejores restaurantes y evitar aburrirte.", "Porque permite un mayor crecimiento profesional al enfocarte en habilidades que son alcanzables con el apoyo adecuado.", "Porque te indica matemáticamente cuándo hay que exigir un aumento de sueldo.", "Para evitar hacer tareas complejas y conformarte con lo fácil."], ans: 1, exp: "Saber qué te falta aprender y a quién pedir ayuda te saca de la zona de confort sin caer en la frustración." },
    { u: "IPLE T1", q: "¿Cuál es el primer paso lógico para determinar tu Zona de Desarrollo Próximo?", opts: ["Pedir inmediatamente una beca económica de formación.", "Realizar una evaluación de tus competencias actuales (un autodiagnóstico honesto de lo que ya dominas).", "Empezar a practicar la tarea más difícil sin saber nada de teoría.", "Contratar obligatoriamente a un mentor externo privado."], ans: 1, exp: "Para saber hacia dónde puedes crecer, primero debes saber exactamente dónde estás parado ahora mismo." },
    { u: "IPLE T1", q: "¿Qué paso sigue a la 'evaluación de competencias' en el proceso de la ZDP?", opts: ["Comprar manuales y libros muy caros.", "La definición de objetivos de aprendizaje que sean claros, específicos y alcanzables a corto/medio plazo.", "Irse de vacaciones para despejar la mente.", "Abandonar el puesto de trabajo actual por frustración."], ans: 1, exp: "Una vez sabes qué dominas, debes fijarte una meta clara de hacia dónde quieres progresar." },
    { u: "IPLE T1", q: "¿Qué se busca en el tercer paso de determinación de la ZDP?", opts: ["Conseguir dinero prestado del banco.", "Identificar y acceder a recursos y apoyos externos (un compañero más experto, consejo, capacitación, vídeos).", "Hacer nuevos amigos fuera del entorno laboral.", "Trabajar sin descanso durante el fin de semana en solitario."], ans: 1, exp: "La ZDP requiere el andamiaje (scaffolding) proporcionado por un recurso externo que sirva de guía." },
    { u: "IPLE T1", q: "¿En qué consiste el paso final de 'Práctica y aplicación' de la ZDP?", opts: ["En leer solo la teoría hasta memorizarla por completo.", "En implementar los nuevos conocimientos y habilidades arriesgándose en situaciones reales de trabajo.", "En enseñar el concepto a otros antes de dominarlo uno mismo.", "En redactar un ensayo extenso sobre el aprendizaje."], ans: 1, exp: "La teoría no sirve si no se atreve uno a ejecutarla en un proyecto real para consolidar el conocimiento." },
    { u: "IPLE T1", q: "¿Qué contribución principal tiene para el profesional trabajar constantemente en la expansión de su ZDP?", opts: ["Garantiza que nunca más tenga que volver a estudiar o hacer cursos en su vida.", "Asegura un crecimiento continuo, mejorando la adaptación al mercado laboral y favoreciendo el éxito personal y organizacional.", "Permite ganar un premio extraordinario de lotería.", "Provoca ser despedido por sobrecualificación técnica."], ans: 1, exp: "Empujar continuamente los límites del conocimiento asegura que el profesional no se quede obsoleto nunca." },
// --- PREGUNTAS DE LA PLATAFORMA (MOODLE) ---
    { u: "IPLE T2", q: "¿Qué son las condiciones de trabajo?", opts: ["Las características generales de las instalaciones y equipos", "Los elementos integrados en los principios generales de la acción preventiva", "Cualquier particularidad laboral que pueda generar riesgos para la seguridad y la salud del trabajador", "Las responsabilidades que asume cada una de las partes implicadas en la actividad laboral"], ans: 2, exp: "La Ley de Prevención de Riesgos Laborales define la condición de trabajo como cualquier característica del mismo que pueda tener una influencia significativa en la generación de riesgos para la seguridad y la salud del trabajador." },
    { u: "IPLE T2", q: "Cuando hablamos de salud, hacemos referencia a:", opts: ["La salud real, percibida y asociada", "La salud física, social y psíquica", "La salud personal, laboral e interpersonal", "La salud interior, exterior y contextual"], ans: 1, exp: "Según la OMS, la salud es un estado de completo bienestar físico, mental (psíquico) y social, y no solamente la ausencia de afecciones o enfermedades." },
    { u: "IPLE T2", q: "Dentro de la organización del trabajo, la carga de trabajo incluye:", opts: ["Exigencias físicas y mentales", "Exigencias directas e indirectas", "Elementos tangibles, intangibles y neutrales del puesto", "Las responsabilidades asumidas con respecto a los medios y actividades"], ans: 0, exp: "La carga de trabajo se divide habitualmente en dos grandes bloques: la carga física (esfuerzos musculares, posturas) y la carga mental (exigencias cognitivas y psicológicas)." },
    { u: "IPLE T2", q: "La enfermedad profesional:", opts: ["Debe estar recogida en el listado de la Directiva Marco", "Se define como toda lesión corporal que sufre el trabajador por cuenta ajena como consecuencia del trabajo", "Incluye las que sean por dolo o imprudencia temeraria del trabajador", "Ninguna es correcta"], ans: 3, exp: "Ninguna de las opciones anteriores (A, B, C) define correctamente la enfermedad profesional. La opción B define el 'accidente de trabajo', y el listado oficial en España es el RD 1299/2006 (CEPRO), no la Directiva Marco." },
    { u: "IPLE T2", q: "Las dimensiones del burnout son:", opts: ["El agotamiento emocional, la despersonalización y la baja realización personal", "La manifestación general, la manifestación local y la intensidad", "El desinterés, la agresividad y el bajo rendimiento", "La baja atención, el aumento de los conflictos laborales y la irascibilidad"], ans: 0, exp: "El Síndrome de Burnout (estar quemado) se diagnostica evaluando estas tres dimensiones psicológicas principales: agotamiento emocional, despersonalización (cinismo) y falta de realización personal." },
    { u: "IPLE T2", q: "Aquellos agentes que al entrar en contacto con tejidos vivos los pueden destruir se denominan:", opts: ["Irritantes", "Corrosivos", "Inflamables", "Tóxicos"], ans: 1, exp: "Los agentes químicos corrosivos (como ácidos fuertes o bases) tienen la capacidad de destruir o quemar irreversiblemente los tejidos humanos por contacto directo." },
    { u: "IPLE T2", q: "Aquellos agentes que, por inhalación, ingestión o penetración cutánea, pueden provocar efectos agudos o crónicos e incluso la muerte se denominan:", opts: ["Irritantes", "Corrosivos", "Inflamables", "Tóxicos"], ans: 3, exp: "La toxicidad de una sustancia se mide por su capacidad de envenenar el cuerpo humano tras introducirse por vías respiratorias, digestivas o dérmicas, pudiendo ser mortal." },
    { u: "IPLE T2", q: "Determina si el tono es agudo o grave y se mide en hercios (Hz):", opts: ["Frecuencia", "Duración", "Intensidad", "Volumen"], ans: 0, exp: "La frecuencia del sonido, medida en Hertzios (Hz), determina si percibimos un ruido como grave (baja frecuencia) o agudo (alta frecuencia)." },
    { u: "IPLE T2", q: "El factor que permite que el ruido pueda ser continuo, discontinuo o de impacto, se denomina:", opts: ["Frecuencia", "Duración", "Intensidad", "Volumen"], ans: 1, exp: "La duración (y su distribución en el tiempo) es lo que clasifica el ruido en continuo, intermitente o de impacto/impulso." },
    { u: "IPLE T2", q: "El instrumento de medida utilizado para medir la cantidad de luz es el:", opts: ["Lumen", "Lux", "Luxómetro", "Lumenógeno"], ans: 2, exp: "El luxómetro es el dispositivo o sensor fotométrico que mide la iluminancia real o nivel de luz (en luxes) en el puesto de trabajo." },

    // --- BLOQUE CUESTIONARIO DE AUTOEVALUACIÓN (60 PREGUNTAS) ---
    { u: "IPLE T2", q: "Según la OMS, la salud es un estado de completo bienestar:", opts: ["Físico y social únicamente.", "Físico, mental y social, y no solo la ausencia de afecciones o enfermedades.", "Físico y ausencia de lesiones.", "La ausencia de estrés laboral."], ans: 1, exp: "La definición histórica de la Organización Mundial de la Salud abarca el bienestar integral en sus tres esferas: física, mental y social." },
    { u: "IPLE T2", q: "¿Qué ley define los daños derivados del trabajo como enfermedades, patologías o lesiones sufridas con motivo del trabajo?", opts: ["Ley General de la Seguridad Social.", "Ley de Prevención de Riesgos Laborales (LPRL).", "Constitución Española.", "Ley de Derechos Laborales."], ans: 1, exp: "La LPRL (Ley 31/1995) es el marco jurídico fundamental que define todos los conceptos sobre prevención y daños laborales en España." },
    { u: "IPLE T2", q: "El accidente de trabajo se define legalmente como toda lesión corporal que el trabajador sufra:", opts: ["En su tiempo libre.", "Con ocasión o por consecuencia del trabajo que ejecute por cuenta ajena.", "Solo si ocurre dentro de la fábrica.", "Durante su período de vacaciones."], ans: 1, exp: "Para que un accidente sea considerado laboral, debe existir un nexo causal directo entre el trabajo realizado por cuenta ajena y la lesión sufrida." },
    { u: "IPLE T2", q: "¿Qué elemento es IMPRESCINDIBLE para que exista un accidente de trabajo legal?", opts: ["Que haya testigos.", "La existencia de una lesión corporal.", "Que el trabajador sea autónomo.", "La intervención de los servicios de emergencia."], ans: 1, exp: "Sin lesión física, psicológica o secuela demostrable en el trabajador, legalmente solo estaríamos ante un 'incidente' y no un 'accidente de trabajo'." },
    { u: "IPLE T2", q: "El accidente ocurrido al ir o al volver del lugar de trabajo se denomina:", opts: ["Accidente en misión.", "Accidente in itinere.", "Accidente por imprudencia.", "Accidente fortuito."], ans: 1, exp: "El término latino 'in itinere' (en el camino) define a los accidentes que ocurren en el desplazamiento habitual y lógico entre el domicilio y el puesto de trabajo." },
    { u: "IPLE T2", q: "Se considera también accidente de trabajo aquel que ocurre durante:", opts: ["El desempeño de funciones sindicales.", "Las vacaciones pagadas.", "Una pelea personal fuera del horario.", "La participación en huelgas ilegales."], ans: 0, exp: "La ley ampara como accidente laboral aquellos que sufre el trabajador al ir, volver o ejercer tareas propias de representación sindical." },
    { u: "IPLE T2", q: "¿Qué se entiende por 'accidente en misión'?", opts: ["El que ocurre en el trayecto habitual a casa.", "El sufrido durante desplazamientos para realizar una actividad encomendada por la empresa.", "Un accidente ocurrido en el comedor de la empresa.", "El provocado por una fuerza mayor externa."], ans: 1, exp: "Si el jefe te envía a otra ciudad a hacer un recado de la empresa y sufres un accidente en el trayecto, es un accidente 'en misión'." },
    { u: "IPLE T2", q: "La 'imprudencia profesional' del trabajador (por exceso de confianza):", opts: ["Anula la consideración de accidente de trabajo.", "No impide la calificación de la lesión como accidente de trabajo.", "Se considera negligencia criminal siempre.", "Obliga a la empresa a despedir al trabajador sin indemnización."], ans: 1, exp: "El exceso de confianza tras años haciendo la misma tarea se considera 'imprudencia profesional' y SÍ está protegida, a diferencia de la 'imprudencia temeraria' que te excluye de la cobertura." },
    { u: "IPLE T2", q: "¿Qué suceso NO se considera accidente de trabajo?", opts: ["Los ocurridos por 'fuerza mayor extraña al trabajo' (ej. un terremoto).", "Los debidos a la imprudencia profesional.", "Los ocurridos al ir al trabajo.", "Los incidentes sufridos realizando tareas de salvamento en la empresa."], ans: 0, exp: "Una fuerza mayor extraña (como la caída de un meteorito o un rayo imprevisto sin relación con el entorno laboral) no tiene nexo con el trabajo." },
    { u: "IPLE T2", q: "La 'enfermedad profesional' debe estar causada por:", opts: ["Un golpe repentino.", "La acción de elementos o sustancias indicadas en el cuadro legal de enfermedades profesionales (CEPRO).", "El estrés de una sola tarde.", "La falta de uso de equipos de protección individual."], ans: 1, exp: "Solo se reconocen como enfermedades profesionales aquellas que aparecen explícitamente en el Real Decreto oficial asociadas a ciertos agentes." },
    { u: "IPLE T2", q: "El ruido se define por tres parámetros: intensidad, duración y:", opts: ["Color.", "Frecuencia.", "Distancia al PLC.", "Velocidad."], ans: 1, exp: "El ruido se mide en función de lo fuerte que es (intensidad), lo agudo/grave que es (frecuencia) y cuánto tiempo dura." },
    { u: "IPLE T2", q: "¿En qué unidad se mide la intensidad del ruido?", opts: ["Hertzios (Hz).", "Decibelios (dB).", "Voltios.", "Amperios."], ans: 1, exp: "El decibelio (dB) es la unidad logarítmica que expresa el nivel de presión acústica o volumen." },
    { u: "IPLE T2", q: "Las vibraciones que afectan a todo el cuerpo suelen transmitirse a través de:", opts: ["Herramientas manuales como martillos.", "Plataformas, suelos o asientos de vehículos.", "La luz de la oficina.", "Los auriculares de protección."], ans: 1, exp: "La vibración 'cuerpo entero' se sufre al ir sentado en tractores, carretillas o trabajar sobre grandes máquinas vibratorias." },
    { u: "IPLE T2", q: "¿Qué tipo de radiación es la más peligrosa por su capacidad de alterar la materia?", opts: ["Radiación no ionizante (microondas).", "Radiación ionizante (Rayos X, partículas alfa/beta).", "Radiación infrarroja.", "Radiación visible."], ans: 1, exp: "Las radiaciones ionizantes tienen energía suficiente para arrancar electrones a los átomos, modificando el ADN y causando cáncer." },
    { u: "IPLE T2", q: "¿Qué puede causar la exposición a radiaciones infrarrojas o ultravioletas?", opts: ["Pérdida de memoria.", "Daños oculares y quemaduras en la piel.", "Fibrilación ventricular.", "Tetanización muscular."], ans: 1, exp: "Típicas en los trabajos de soldadura, los rayos UV/IR provocan 'arco ocular' (conjuntivitis actínica) y graves quemaduras dérmicas." },
    { u: "IPLE T2", q: "En cuanto a la iluminación, el principal riesgo es:", opts: ["La falta de bombillas LED.", "El deslumbramiento y la fatiga visual por niveles inadecuados.", "Que la luz sea de color amarillo.", "La radiación gamma emitida por los fluorescentes."], ans: 1, exp: "Tanto el exceso (deslumbramiento) como el defecto (esfuerzo y fatiga visual) causan problemas de visión y dolores de cabeza." },
    { u: "IPLE T2", q: "El 'estrés térmico' ocurre cuando el cuerpo:", opts: ["Tiene frío en invierno.", "No es capaz de mantener su temperatura interna ante condiciones extremas de calor o frío.", "Toca un cable en tensión.", "Experimenta cambios de humor repentinos."], ans: 1, exp: "Se produce por la descompensación del cuerpo al intentar regular sus 37ºC internos frente a un ambiente adverso." },
    { u: "IPLE T2", q: "¿Qué parámetro ambiental se debe controlar para evitar la sequedad de las mucosas?", opts: ["El ruido.", "La humedad relativa.", "Las vibraciones.", "La presión atmosférica."], ans: 1, exp: "Ambientes por debajo del 30% de humedad relativa resecan las vías respiratorias y los ojos." },
    { u: "IPLE T2", q: "Un agente químico que puede explotar bajo el efecto de la llama o el calor es:", opts: ["Irritante.", "Explosivo.", "Comburente.", "Corrosivo."], ans: 1, exp: "Las sustancias explosivas reaccionan violentamente liberando gases y calor ante una mínima chispa o fricción." },
    { u: "IPLE T2", q: "Los agentes químicos 'corrosivos' se caracterizan por:", opts: ["Causar sueño.", "Destruir tejidos vivos con los que entran en contacto.", "Producir cáncer a largo plazo.", "Congelar las superficies de contacto."], ans: 1, exp: "Ácidos (como el sulfúrico) y bases (como la sosa cáustica) provocan quemaduras químicas inmediatas al tocar la piel." },
    { u: "IPLE T2", q: "¿Qué vía de entrada de contaminantes químicos es la más importante en el medio laboral?", opts: ["Vía dérmica (piel).", "Vía inhalatoria (respiratoria).", "Vía digestiva.", "Vía parenteral (heridas)."], ans: 1, exp: "El trabajador respira continuamente durante toda su jornada, inhalando vapores, gases o polvos tóxicos." },
    { u: "IPLE T2", q: "Los agentes biológicos del 'Grupo 4' son aquellos que:", opts: ["No causan enfermedades.", "Causan una enfermedad grave con gran peligro de propagación y sin tratamiento eficaz.", "Tienen una vacuna disponible para todos.", "Tienen un bajo riesgo de propagación en la sociedad."], ans: 1, exp: "Es el grupo de máximo peligro (ej. virus del Ébola), mortales y sin profilaxis médica conocida." },
    { u: "IPLE T2", q: "Un ejemplo de riesgo biológico en un laboratorio es la exposición a:", opts: ["Humos de soldadura.", "Virus, bacterias o hongos.", "Rayos X.", "Temperaturas bajo cero."], ans: 1, exp: "El riesgo biológico lo conforman siempre microorganismos vivos que pueden causar infección, alergia o toxicidad." },
    { u: "IPLE T2", q: "El 'estrés' se define como una respuesta del individuo para adaptarse a:", opts: ["Una silla incómoda.", "Presiones internas y externas.", "El ruido de la fábrica solamente.", "Los cambios de turno semanales."], ans: 1, exp: "Es la reacción fisiológica de adaptación del cuerpo frente a las excesivas demandas (presiones) del entorno." },
    { u: "IPLE T2", q: "¿Cuál es un síntoma FÍSICO del estrés mencionado en el resumen?", opts: ["Agresividad.", "Taquicardias y dolores musculares.", "Desinterés por el aspecto físico.", "Dificultad para concentrarse."], ans: 1, exp: "Las taquicardias, los dolores de cabeza, los trastornos gastrointestinales y las contracturas musculares son la somatización del estrés." },
    { u: "IPLE T2", q: "La fatiga laboral es la disminución de la capacidad física y mental tras un trabajo:", opts: ["Realizado durante años.", "Realizado en tiempo breve y sin posibilidad de recuperación integral.", "Realizado únicamente sentado.", "En un ambiente con exceso de iluminación."], ans: 1, exp: "Se produce por forzar la máquina (cuerpo y mente) sin otorgarle los tiempos de descanso necesarios." },
    { u: "IPLE T2", q: "El 'Mobbing' o acoso laboral se caracteriza por ser una violencia psicológica:", opts: ["Puntual y aislada.", "Reiterada hacia una persona desde una posición de poder o compañeros.", "Exclusivamente física.", "Causada por clientes externos de la empresa."], ans: 1, exp: "Debe ser sistemático, repetido en el tiempo y tener como fin aislar o hundir moralmente a la víctima." },
    { u: "IPLE T2", q: "¿Qué es el Síndrome de Burnout o 'estar quemado'?", opts: ["Una quemadura eléctrica de tercer grado.", "Una respuesta al estrés laboral crónico con agotamiento emocional.", "Perder el trabajo de forma repentina.", "El aburrimiento por falta de tareas asignadas."], ans: 1, exp: "Típico en oficios de atención directa (médicos, docentes), se sufre de fatiga crónica, cinismo y baja eficacia por estrés sostenido." },
    { u: "IPLE T2", q: "La 'carga de trabajo' se compone de requerimientos:", opts: ["Solo físicos.", "Psicofísicos (físicos y mentales).", "Mecánicos.", "Únicamente visuales."], ans: 1, exp: "Todo trabajo implica un esfuerzo doble: mover el cuerpo (carga física) y procesar información (carga mental)." },
    { u: "IPLE T2", q: "En ergonomía, ¿qué riesgo se asocia al uso de pantallas de visualización de datos (PVD)?", opts: ["Sordera.", "Fatiga visual y problemas posturales.", "Tetanización.", "Infecciones virales."], ans: 1, exp: "Trabajar horas frente al ordenador genera sequedad ocular, fatiga visual, dolores de cuello, espalda y tendinitis." },
    { u: "IPLE T2", q: "La manipulación manual de cargas superiores a ____ kg puede suponer un riesgo dorso-lumbar:", opts: ["1 kg.", "3 kg (o 25 kg para evitar riesgos generales según normativa).", "50 kg.", "10 kg."], ans: 1, exp: "La guía técnica del INSST establece que a partir de 3 kg ya existe riesgo dorso-lumbar potencial en condiciones desfavorables (y 25 kg es el límite máximo general recomendado)." },
    { u: "IPLE T2", q: "El paso de la corriente eléctrica por el cuerpo se llama:", opts: ["Inducción.", "Choque eléctrico.", "Convección.", "Arco eléctrico."], ans: 1, exp: "El cuerpo actúa como un cable conductor, cerrando el circuito y recibiendo el 'choque eléctrico'." },
    { u: "IPLE T2", q: "¿Qué efecto ocurre cuando los músculos se contraen y el trabajador no puede soltar el objeto en tensión?", opts: ["Fibrilación.", "Tetanización o agarrotamiento muscular.", "Electrólisis.", "Electrización."], ans: 1, exp: "La corriente anula las órdenes del cerebro; los músculos se contraen violentamente 'pegando' a la víctima al cable." },
    { u: "IPLE T2", q: "La 'fibrilación ventricular' es:", opts: ["Un corte en el dedo.", "Un ritmo cardiaco anormal donde el corazón no bombea sangre adecuadamente.", "La inflamación de las venas.", "Una parada respiratoria temporal."], ans: 1, exp: "La electricidad descoordina los latidos, provocando un temblor cardíaco inútil que, sin desfibrilación, causa la muerte." },
    { u: "IPLE T2", q: "La gravedad de un accidente eléctrico depende de la resistencia del cuerpo, la trayectoria y:", opts: ["La marca de las botas.", "La intensidad de la corriente y el tiempo de contacto.", "El precio de la electricidad.", "El tipo de enchufe utilizado."], ans: 1, exp: "A más amperios y más milisegundos 'pegado' a la corriente, las quemaduras y el daño orgánico son exponencialmente peores." },
    { u: "IPLE T2", q: "¿Qué daño produce la corriente al atravesar el cuerpo debido al efecto calorífico?", opts: ["Asfixia.", "Quemaduras (externas e internas).", "Mobbing.", "Tetanización."], ans: 1, exp: "Por el efecto Joule, la resistencia del cuerpo al paso de la electricidad genera altísimas temperaturas, cociendo los órganos internos." },
    { u: "IPLE T2", q: "Una quemadura de tercer grado se caracteriza por:", opts: ["Afectar solo a la capa externa.", "Destruir dermis y epidermis, pudiendo afectar a músculos y huesos.", "Desaparecer en 24 horas.", "Provocar un enrojecimiento leve sin ampollas."], ans: 1, exp: "Son las quemaduras eléctricas más graves, requiriendo cirugías reconstructivas o incluso amputaciones." },
    { u: "IPLE T2", q: "El contacto con una parte metálica que accidentalmente está en tensión (ej. carcasa de motor) se llama:", opts: ["Contacto directo.", "Contacto indirecto.", "Contacto por inducción.", "Contacto de masa."], ans: 1, exp: "Es 'indirecto' porque tocas algo que normalmente no lleva corriente, pero que por un fallo de aislamiento se ha electrificado." },
    { u: "IPLE T2", q: "¿Cuál es una medida preventiva fundamental contra el riesgo eléctrico?", opts: ["Pintar el cuadro de color verde.", "Uso de interruptores diferenciales y puesta a tierra.", "Abrir las ventanas.", "Instalar ventiladores en la zona."], ans: 1, exp: "El diferencial detecta la fuga de corriente y 'salta', cortando la luz antes de que la descarga hacia la 'toma de tierra' te mate." },
    { u: "IPLE T2", q: "¿Qué EPI es específico para proteger contra el riesgo eléctrico?", opts: ["Casco de cartón.", "Guantes aislantes y calzado dieléctrico.", "Gafas de sol.", "Arnés de seguridad anticaídas."], ans: 1, exp: "El material dieléctrico (goma, caucho especial) ofrece una alta resistencia para aislar el cuerpo del suelo y del cable vivo." },
    { u: "IPLE T2", q: "El documento que identifica los peligros y evalúa los riesgos en cada puesto es:", opts: ["El contrato de trabajo.", "La Evaluación de Riesgos.", "La nómina.", "El plan de emergencia."], ans: 1, exp: "Es el documento matriz y obligatorio de prevención en cualquier empresa, donde se analizan las máquinas, tareas y peligros de cada trabajador." },
    { u: "IPLE T2", q: "¿Qué significa 'Cultura Preventiva'?", opts: ["Leer libros sobre accidentes antiguos.", "La actitud y comportamientos de empresa y trabajadores para evitar daños.", "Multar siempre al trabajador.", "El presupuesto anual de prevención."], ans: 1, exp: "Es ir más allá de la ley: que la seguridad sea un valor fundamental y una costumbre diaria compartida por toda la plantilla." },
    { u: "IPLE T2", q: "La 'asfixia' por riesgo eléctrico se produce cuando:", opts: ["El trabajador tiene miedo.", "La tetanización en los pulmones impide la entrada de aire.", "Hay mucho humo en la sala.", "El corazón deja de latir."], ans: 1, exp: "Si la corriente atraviesa el pecho, paraliza el diafragma y los músculos pectorales, impidiendo respirar (paro respiratorio)." },
    { u: "IPLE T2", q: "Las vibraciones mano-brazo son típicas del uso de:", opts: ["Carretillas elevadoras.", "Martillos neumáticos o taladros.", "Ordenadores portátiles.", "Vehículos pesados de transporte."], ans: 1, exp: "Estas vibraciones locales se originan en máquinas rotativas y de percusión manuales, dañando las articulaciones de los brazos." },
    { u: "IPLE T2", q: "¿Cuál es el rango de audición estándar del ser humano mencionado en física del ruido?", opts: ["0 a 100 Hz.", "20 a 20.000 Hz.", "1 a 1.000.000 Hz.", "100 a 10.000 Hz."], ans: 1, exp: "Cualquier sonido por debajo de 20 Hz (infrasonido) o por encima de 20.000 Hz (ultrasonido) no es percibido por el oído humano." },
    { u: "IPLE T2", q: "Un agente químico 'sensibilizante' es aquel que:", opts: ["Produce sueño profundo.", "Puede causar una reacción alérgica tras el contacto.", "Limpia la grasa de los motores.", "Es altamente corrosivo."], ans: 1, exp: "Una vez que el cuerpo se sensibiliza a la sustancia, exposiciones futuras (incluso minúsculas) desatan asma o dermatitis alérgica." },
    { u: "IPLE T2", q: "El riesgo por 'falta de orden y limpieza' se clasifica dentro de:", opts: ["Factores psicosociales.", "Condiciones de seguridad (lugares de trabajo).", "Riesgo biológico.", "Carga de trabajo física."], ans: 1, exp: "Dejar cables por el suelo o cajas amontonadas provoca tropiezos y caídas, siendo uno de los mayores factores de riesgo físico de seguridad." },
    { u: "IPLE T2", q: "La señalización de seguridad es una medida de:", opts: ["Protección individual.", "Protección colectiva/complementaria.", "Mantenimiento correctivo.", "Prevención médica."], ans: 1, exp: "No elimina el riesgo, pero advierte a todos los trabajadores del entorno (forma colectiva) de que el peligro está ahí." },
    { u: "IPLE T2", q: "¿Qué efecto tiene la corriente de 1 a 3 mA en el cuerpo humano?", opts: ["Muerte inmediata.", "Umbral de percepción (ligero hormigueo).", "Paro cardiaco.", "Asfixia severa."], ans: 1, exp: "Es una intensidad muy baja, se nota un leve calambre o cosquilleo, pero no hay dolor ni pérdida de control muscular." },
    { u: "IPLE T2", q: "La 'negligencia temeraria' del trabajador:", opts: ["Es protegida por la Seguridad Social.", "Excluye la consideración de accidente de trabajo.", "Solo ocurre in itinere.", "Se considera un accidente in itinere."], ans: 1, exp: "Saltarse aposta las normas de seguridad (ej. quitar la carcasa de una sierra porque estorba) es un acto temerario y hace perder el derecho a baja laboral." },
    { u: "IPLE T2", q: "El listado oficial de enfermedades profesionales en España se divide en:", opts: ["2 grupos.", "6 grupos (según el agente causante).", "100 grupos.", "4 grupos."], ans: 1, exp: "El RD 1299/2006 las clasifica en 6 grupos: químicos, físicos, biológicos, inhalación de sustancias, de la piel, y agentes carcinógenos." },
    { u: "IPLE T2", q: "Un factor psicosocial derivado de la 'organización del trabajo' es:", opts: ["La marca del ordenador.", "El exceso de carga de trabajo y falta de autonomía.", "El tipo de enchufe.", "La iluminación deficiente."], ans: 1, exp: "Factores como el ritmo infernal, la falta de descanso, turnos rotativos y un jefe controlador merman gravemente la salud mental." },
    { u: "IPLE T2", q: "Para que un accidente sea 'in itinere', ¿qué debe cumplirse?", opts: ["Que el trabajador se desvíe para ir de compras.", "Que ocurra en el trayecto habitual, sin interrupciones por interés personal.", "Que el coche sea de la empresa obligatoriamente.", "Que se produzca siempre dentro del horario laboral."], ans: 1, exp: "Si el trabajador para a tomar unas cervezas o cambia su ruta habitual, se rompe el 'nexo' temporal-geográfico y ya no se considera laboral." },
    { u: "IPLE T2", q: "¿Qué es un 'incidente' de trabajo?", opts: ["Un accidente con baja de 30 días.", "Un suceso que no causa lesiones pero que podría haberlas causado.", "Una reunión de seguridad.", "Un accidente con lesiones leves."], ans: 1, exp: "Se le suele llamar 'casi accidente'. Ej: cae un ladrillo del techo pero no le da a nadie. Hay que investigarlo para que mañana no mate a alguien." },
    { u: "IPLE T2", q: "El 'aislamiento doble o reforzado' en máquinas sirve para:", opts: ["Ahorrar energía.", "Proteger contra contactos eléctricos sin necesidad de toma de tierra.", "Que la máquina no haga ruido.", "Evitar el sobrecalentamiento del equipo."], ans: 1, exp: "Los electrodomésticos con símbolo de 'doble cuadrado' tienen una carcasa plástica tan gruesa y aislada que no pueden derivar a masa." },
    { u: "IPLE T2", q: "¿Qué riesgo ergonómico es común en trabajos de montaje de precisión?", opts: ["Ruido excesivo.", "Posturas forzadas y movimientos repetitivos.", "Radiaciones ionizantes.", "Exposición a agentes biológicos."], ans: 1, exp: "Ensamblar piezas pequeñas obliga a mantener las manos en posturas antinaturales (cuello doblado, muñecas forzadas) generando trastornos musculoesqueléticos." },
    { u: "IPLE T2", q: "Las enfermedades derivadas del trabajo que NO están en la lista CEPRO:", opts: ["No se pueden reclamar.", "Pueden ser consideradas accidentes de trabajo si se prueba la relación causa-efecto.", "Se curan solas.", "Se denominan incidentes de trabajo automáticamente."], ans: 1, exp: "Si pillas una enfermedad por culpa del trabajo, pero no está en la lista oficial, la ley te permite demostrarlo en los juzgados para que la traten como 'accidente de trabajo'." },
    { u: "IPLE T2", q: "En el caso de 'paro cardiaco' por electrocución, es vital realizar:", opts: ["Una fotografía del cuadro eléctrico.", "Masaje cardiaco o desfibrilación inmediata.", "Un informe SAP PM.", "Dar de beber agua al accidentado."], ans: 1, exp: "Los primeros 4 minutos son críticos. Tras cortar la luz, aplicar RCP (Reanimación Cardiopulmonar) puede reactivar el corazón fibrilando." },
    { u: "IPLE T2", q: "La humedad relativa mínima recomendada en locales con riesgos eléctricos para evitar electricidad estática es:", opts: ["10%.", "50%.", "100%.", "80%."], ans: 1, exp: "Un ambiente demasiado seco (menos del 30-40%) favorece la acumulación de electricidad estática, que puede saltar en forma de chispa." },
    { u: "IPLE T2", q: "¿Cuál es el objetivo final de la evaluación de riesgos profesionales?", opts: ["Cumplir el trámite y archivar el papel.", "Eliminar o reducir los riesgos para proteger la salud del trabajador.", "Comprar EPIs más baratos.", "Determinar el salario del trabajador según su riesgo."], ans: 1, exp: "La evaluación no es un mero papel, es la hoja de ruta para aplicar medidas preventivas que salven vidas." },
// --- PREGUNTAS DE LA PLATAFORMA (MOODLE) ---
    { u: "IPLE T3", q: "En materia de prevención y protección, tanto el empresario como los trabajadores tienen una responsabilidad:", opts: ["Administrativa, civil y penal", "Directa, indirecta y asociada", "Criminal, procesal y judicial", "Laboral, administrativa y social"], ans: 0, exp: "El incumplimiento de la normativa de prevención puede derivar en responsabilidades administrativas (multas), civiles (indemnizaciones por daños) y penales (cárcel por poner en peligro la vida)." },
    { u: "IPLE T3", q: "Se constituirá un Comité de Seguridad y Salud en todas las empresas o centros de trabajo que cuenten con:", opts: ["10 o más trabajadores", "25 o más trabajadores", "50 o más trabajadores", "100 o más trabajadores"], ans: 2, exp: "La Ley 31/1995 establece la obligatoriedad de constituir un Comité de Seguridad y Salud (órgano paritario) a partir de los 50 trabajadores." },
    { u: "IPLE T3", q: "El desarrollo legislativo en materia de prevención parte desde:", opts: ["El Derecho consuetudinario", "La Organización Mundial de la Salud (OMS)", "Los reglamentos internos de las empresas", "El Derecho Comunitario y la Constitución española"], ans: 3, exp: "Toda la normativa española actual de prevención (LPRL 31/1995) nace de la transposición de Directivas Europeas (Derecho Comunitario) y del mandato de la Constitución Española." },
    { u: "IPLE T3", q: "La elección de los delegados de prevención se hará:", opts: ["De entre los miembros del Comité de Seguridad y Salud", "A través de los directivos de la empresa y de entre ellos", "A través de los representantes de los trabajadores y de entre ellos", "De entre los miembros más cualificados de la empresa en materia de trabajo y Seguridad Social."], ans: 2, exp: "Los Delegados de Prevención son los representantes de los trabajadores con funciones específicas en materia de prevención y son designados por y entre los representantes del personal." },
    { u: "IPLE T3", q: "En relación con las medidas de protección:", opts: ["Debe primar la seguridad individual sobre la colectiva", "Debe primar la seguridad colectiva sobre la individual", "Se centran en el uso de señalización de seguridad", "Son lo mismo que las técnicas de prevención"], ans: 1, exp: "Uno de los principios de la acción preventiva (Art. 15 LPRL) es anteponer siempre la protección colectiva (que protege a todos, ej. una barandilla) a la protección individual (EPI)." },
    { u: "IPLE T3", q: "Todo aquel equipo que el trabajador lleva puesto o sujeto a él mismo para que le proteja de uno o varios riesgos que amenacen su seguridad o su salud, además de cualquier complemento o accesorio que cumpla esa misma función, se denomina:", opts: ["Equipo de Prevención Interna", "Equipo de Protección Colectivo", "Equipo de Protección Individual", "Equipo de Protección Ergonómico"], ans: 2, exp: "Esta es la definición técnica y legal exacta de lo que es un Equipo de Protección Individual (EPI), como guantes, cascos o arneses." },
    { u: "IPLE T3", q: "La señalización de seguridad:", opts: ["Establece las condiciones relativas al tamaño del puesto de trabajo, es decir, las distancias y dimensiones óptimas", "Requiere, para un correcto almacenamiento, mantenimiento y reparación, seguir las instrucciones facilitadas por el fabricante", "Siempre incluye un pictograma que facilita la interpretación de su significado", "Nos da una indicación u obligación dependiendo del caso concreto, en relación con la seguridad o la salud en el puesto de trabajo"], ans: 3, exp: "La señalización no elimina el riesgo, pero cumple la función esencial de proporcionar una indicación, prohibición u obligación relativa a la seguridad." },
    { u: "IPLE T3", q: "Ante una situación de emergencia se debe:", opts: ["Mantener la calma y actuar de forma serena, pero con rapidez", "Examinar el lugar rápidamente y comprobar si existen otros peligros", "Intentar evitar lo que se conoce como shock", "Todas las respuestas anteriores son correctas"], ans: 3, exp: "Ante cualquier emergencia, todas las opciones descritas son pautas fundamentales de los primeros auxilios para garantizar la supervivencia del accidentado." },
    { u: "IPLE T3", q: "Para realizar una correcta actuación en la aplicación de los primeros auxilios y proceder en el orden adecuado, es fundamental:", opts: ["Proteger, Avisar y Socorrer", "Prevenir, Actuar y Socorrer", "Proteger, Ayudar y Solucionar", "Prevenir, Alentar y Solventar"], ans: 0, exp: "El protocolo universal PAS rige cualquier actuación de emergencia: primero Proteger el lugar, luego Avisar al 112 y finalmente Socorrer a las víctimas." },
    { u: "IPLE T3", q: "En la Reanimación Cardio Pulmonar (RCP) hay que hacer:", opts: ["10 compresiones torácicas y 1 insuflación, sucesivamente", "25 compresiones torácicas y 3 insuflaciones, sucesivamente", "30 compresiones torácicas y 2 insuflaciones, sucesivamente", "20 compresiones torácicas y 2 insuflaciones, sucesivamente"], ans: 2, exp: "El ritmo estándar de soporte vital básico (RCP) para adultos dictado por el Consejo Europeo de Resucitación es de 30 compresiones seguidas de 2 ventilaciones (insuflaciones)." },

    // --- BLOQUE CUESTIONARIO DE AUTOEVALUACIÓN (60 PREGUNTAS) ---
    { u: "IPLE T3", q: "¿Cuál es la norma fundamental en España que regula la seguridad y salud de los trabajadores?", opts: ["El Código Penal.", "La Ley 31/1995 de Prevención de Riesgos Laborales (LPRL).", "El Estatuto de los Trabajadores únicamente.", "La Ley General de la Seguridad Social."], ans: 1, exp: "La LPRL del año 1995 es el pilar de toda la normativa preventiva en nuestro país." },
    { u: "IPLE T3", q: "¿Qué texto legal regula la gestión de la prevención en las empresas y los servicios de prevención?", opts: ["RD 485/1997.", "RD 39/1997, Reglamento de los Servicios de Prevención.", "RD 614/2001.", "RD 486/1997 sobre lugares de trabajo."], ans: 1, exp: "El Real Decreto 39/1997 detalla cómo organizar la prevención en la empresa y define las auditorías y servicios de prevención." },
    { u: "IPLE T3", q: "El derecho de los trabajadores a una protección eficaz en materia de seguridad y salud supone:", opts: ["Un deber correlativo del empresario de protección.", "Una opción voluntaria para la empresa.", "Que el trabajador no tiene ninguna obligación.", "Un deber exclusivo del Estado."], ans: 0, exp: "Si el trabajador tiene derecho a estar seguro, el empresario tiene el 'deber' ineludible de garantizar esa seguridad poniendo los medios." },
    { u: "IPLE T3", q: "¿Cuál de estos es un deber del trabajador según la LPRL?", opts: ["Elaborar el plan de prevención.", "Usar correctamente los medios y equipos de protección.", "Pagar los equipos de protección individual (EPI).", "Comprar la maquinaria más segura del mercado."], ans: 1, exp: "El trabajador no diseña el plan ni paga el EPI, pero tiene el deber de usarlos correctamente y no anular los sistemas de seguridad." },
    { u: "IPLE T3", q: "Si un empresario incumple la normativa de prevención y causa un accidente, ¿qué tipo de responsabilidad puede derivarse?", opts: ["Solo administrativa.", "Administrativa, civil, penal y recargo de prestaciones.", "Únicamente una multa económica de la Inspección.", "Ninguna si el trabajador aceptó el riesgo."], ans: 1, exp: "El empresario se enfrenta a todo el peso de la ley: multas, indemnizaciones, cárcel (penal) y pagar el recargo de la pensión del accidentado." },
    { u: "IPLE T3", q: "¿Qué tipo de responsabilidad busca 'reparar el daño' mediante una indemnización económica al trabajador?", opts: ["Responsabilidad Penal.", "Responsabilidad Civil.", "Responsabilidad Administrativa.", "Responsabilidad Disciplinaria."], ans: 1, exp: "La vía civil se ocupa de resarcir el daño causado a la víctima mediante dinero (indemnización por daños y perjuicios)." },
    { u: "IPLE T3", q: "La sanción por infracciones en materia de prevención es impuesta por:", opts: ["El sindicato.", "La Autoridad Laboral, a propuesta de la Inspección de Trabajo.", "El Comité de Empresa.", "El Juez de lo Penal directamente."], ans: 1, exp: "La Inspección de Trabajo investiga y propone la sanción, y la Autoridad Laboral la impone en forma de multa administrativa." },
    { u: "IPLE T3", q: "El 'recargo de prestaciones' de la Seguridad Social consiste en un aumento de la prestación de entre un:", opts: ["10% y 20%.", "30% y 50%.", "5% y 15%.", "50% y 100%."], ans: 1, exp: "Si hay falta de medidas de seguridad, el empresario es condenado a pagar de su bolsillo entre un 30% y un 50% extra sobre la pensión del accidentado." },
    { u: "IPLE T3", q: "¿Quiénes son los representantes de los trabajadores con funciones específicas en prevención?", opts: ["Los Jefes de Equipo.", "Los Delegados de Prevención.", "El servicio médico.", "Los Inspectores de Trabajo."], ans: 1, exp: "Elegidos entre los representantes legales de los trabajadores, los delegados vigilan el cumplimiento de la seguridad en la empresa." },
    { u: "IPLE T3", q: "El Comité de Seguridad y Salud (CSS) debe constituirse obligatoriamente en empresas con:", opts: ["10 o más trabajadores.", "50 o más trabajadores.", "Solo en multinacionales.", "Más de 250 trabajadores."], ans: 1, exp: "Al alcanzar los 50 trabajadores, es obligatorio crear este órgano paritario de debate y participación en PRL." },
    { u: "IPLE T3", q: "El Comité de Seguridad y Salud es un órgano de participación:", opts: ["Exclusivo de los trabajadores.", "Paritario (mismo número de representantes de la empresa y de delegados de prevención).", "Solo para técnicos de prevención.", "Consultivo y externo a la empresa."], ans: 1, exp: "Al ser paritario y colegiado, las decisiones se toman equilibrando los votos de la empresa y de los trabajadores (50/50)." },
    { u: "IPLE T3", q: "¿Qué modalidad organizativa puede elegir una empresa de hasta 10 trabajadores si el empresario trabaja habitualmente en el centro?", opts: ["Designar a un servicio de prevención ajeno obligatoriamente.", "Asunción personal por el empresario de la actividad preventiva.", "No hacer nada en materia de prevención.", "Nombrar a un trabajador designado de forma obligatoria."], ans: 1, exp: "La ley permite que en microempresas (o hasta 25 si hay un solo centro) el propio jefe asuma la prevención, siempre que esté capacitado." },
    { u: "IPLE T3", q: "Un Servicio de Prevención Propio es obligatorio cuando la empresa tiene:", opts: ["Más de 500 trabajadores.", "Entre 250 y 500 trabajadores y desarrolla actividades peligrosas (Anexo I).", "Ambas respuestas son correctas.", "Más de 1000 trabajadores."], ans: 2, exp: "Superar los 500 empleados o tener más de 250 en sectores de alto riesgo (construcción, químicos) obliga a tener servicio de prevención en plantilla." },
    { u: "IPLE T3", q: "¿Qué es un Servicio de Prevención Ajeno (SPA)?", opts: ["Una entidad externa especializada contratada por la empresa.", "Un grupo de trabajadores de la propia empresa.", "El departamento de recursos humanos.", "La Mutua de accidentes de trabajo obligatoria."], ans: 0, exp: "Si la empresa no tiene capacidad o recursos para hacer la prevención, subcontrata a un SPA acreditado por la Administración." },
    { u: "IPLE T3", q: "¿Cuál es el primer principio de la acción preventiva según el Art. 15 de la LPRL?", opts: ["Dar instrucciones a los trabajadores.", "Evitar los riesgos.", "Comprar EPIs caros.", "Evaluar los riesgos inevitables."], ans: 1, exp: "La regla de oro: si un riesgo se puede eliminar por completo de la empresa, debe evitarse. Lo que no se pueda evitar, se evalúa." },
    { u: "IPLE T3", q: "Ante un riesgo que no se puede evitar, el siguiente paso es:", opts: ["Evaluar los riesgos que no se hayan podido evitar.", "Poner una señal de peligro.", "Despedir al trabajador.", "Obligar al uso de EPIs."], ans: 0, exp: "Aquellos riesgos que forman parte intrínseca de la actividad deben ser evaluados para determinar su magnitud y adoptar medidas de control." },
    { u: "IPLE T3", q: "Un principio de la acción preventiva es anteponer:", opts: ["La protección individual a la colectiva.", "La protección colectiva a la individual.", "El beneficio económico a la seguridad.", "La rapidez del proceso a la seguridad."], ans: 1, exp: "Siempre es mejor una medida que proteja a todos a la vez (barandilla, extractor de humo) que darle un equipo a cada persona (arnés, mascarilla)." },
    { u: "IPLE T3", q: "La técnica preventiva que actúa sobre las máquinas e instalaciones para evitar accidentes se llama:", opts: ["Higiene Industrial.", "Seguridad en el Trabajo.", "Ergonomía.", "Medicina del Trabajo."], ans: 1, exp: "La Seguridad Laboral se centra en los riesgos mecánicos y físicos que provocan accidentes de trabajo traumáticos." },
    { u: "IPLE T3", q: "¿Qué técnica preventiva se encarga de prevenir las enfermedades profesionales controlando agentes físicos, químicos y biológicos?", opts: ["Medicina del Trabajo.", "Higiene Industrial.", "Psicosociología.", "Ergonomía."], ans: 1, exp: "La Higiene evalúa el entorno de trabajo (ruido, polvo químico, virus) para que no enfermes a largo plazo." },
    { u: "IPLE T3", q: "La Ergonomía busca adaptar:", opts: ["El trabajador al puesto.", "El puesto de trabajo al trabajador.", "El salario a la peligrosidad.", "Las herramientas a la capacidad de las máquinas."], ans: 1, exp: "Se adapta el entorno, la silla, la mesa y las herramientas a la anatomía y psicología humana, no al revés." },
    { u: "IPLE T3", q: "Una red de seguridad o una barandilla se consideran medidas de:", opts: ["Protección Individual.", "Protección Colectiva.", "Prevención en origen.", "Protección Administrativa."], ans: 1, exp: "Al proteger a cualquier trabajador que pase por allí, es una medida colectiva (actúa sobre el medio, no sobre la persona)." },
    { u: "IPLE T3", q: "Los Equipos de Protección Individual (EPI) deben utilizarse:", opts: ["Siempre, aunque haya medidas colectivas.", "Cuando los riesgos no se puedan evitar o limitar por medios técnicos de protección colectiva.", "Solo si el trabajador quiere.", "Nunca en espacios cerrados."], ans: 1, exp: "El EPI es la última barrera de defensa; se usa solo si el riesgo persiste después de haber instalado protecciones colectivas y de diseño." },
    { u: "IPLE T3", q: "¿Qué color se utiliza para las señales de OBLIGACIÓN?", opts: ["Rojo.", "Azul.", "Amarillo.", "Verde."], ans: 1, exp: "Las señales azules con pictogramas blancos indican un mandato u obligación (ej. uso obligatorio de casco)." },
    { u: "IPLE T3", q: "Una señal triangular con borde negro y fondo amarillo indica:", opts: ["Prohibición.", "Advertencia.", "Información de socorro.", "Obligación."], ans: 1, exp: "El triángulo amarillo alerta de un riesgo o peligro presente en la zona (riesgo eléctrico, piso resbaladizo)." },
    { u: "IPLE T3", q: "El color VERDE en señalización se reserva para:", opts: ["Peligro-Paro.", "Señales de salvamento, socorro o situación de seguridad.", "Obligación de usar guantes.", "Equipos contra incendios."], ans: 1, exp: "Identifica salidas de emergencia, botiquines, duchas de seguridad y puntos de encuentro." },
    { u: "IPLE T3", q: "Las señales de PROHIBICIÓN tienen forma:", opts: ["Triangular.", "Redonda con borde y banda roja transversal.", "Cuadrada verde.", "Rectangular azul."], ans: 1, exp: "El círculo rojo con una barra cruzada indica que un comportamiento está prohibido (ej. Prohibido fumar)." },
    { u: "IPLE T3", q: "¿Qué indica el color rojo además de prohibición?", opts: ["Materias inflamables.", "Equipos de lucha contra incendios.", "Lavado de ojos.", "Rutas de evacuación."], ans: 1, exp: "Los extintores, mangueras (BIE) y pulsadores de alarma se señalizan con placas cuadradas o rectangulares rojas." },
    { u: "IPLE T3", q: "¿Qué documento establece el marco orgánico y funcional para prevenir y controlar riesgos sobre personas y bienes en caso de emergencia?", opts: ["El contrato laboral.", "El Plan de Autoprotección.", "El manual del extintor.", "La Evaluación de Riesgos Generales."], ans: 1, exp: "Este plan detalla cómo actuar, quién manda y cómo se evacúa el edificio si ocurre una catástrofe." },
    { u: "IPLE T3", q: "El Plan de Actuación en Emergencias debe prever:", opts: ["La evaluación, la alarma, la extinción y la evacuación.", "Solo la lista de teléfonos de emergencia.", "El aumento de sueldo por peligrosidad.", "La hora de llegada de los bomberos."], ans: 0, exp: "Contiene las pautas exactas para descubrir la emergencia, dar el aviso (alarma), luchar contra ella y desalojar." },
    { u: "IPLE T3", q: "¿Quién es el responsable de mantener actualizado el Plan de Autoprotección?", opts: ["El Delegado de Prevención.", "El titular de la actividad (el empresario).", "El bombero local.", "El técnico de mantenimiento."], ans: 1, exp: "El dueño de la empresa es el responsable legal de implantar el plan, nombrar a los equipos y hacer simulacros." },
    { u: "IPLE T3", q: "El conjunto de actuaciones destinadas a desplazar a los ocupantes a un lugar seguro se llama:", opts: ["Plan de Emergencia.", "Plan de Evacuación.", "Simulacro.", "Confinamiento preventivo."], ans: 1, exp: "Es la parte del plan dedicada exclusivamente a cómo salir ordenadamente del edificio hacia el punto de reunión." },
    { u: "IPLE T3", q: "Un 'Conato de Emergencia' es aquel que:", opts: ["Obliga a evacuar todo el edificio.", "Puede ser controlado de forma sencilla con los medios propios del local.", "Requiere la intervención de bomberos externos.", "Se ha catalogado como falsa alarma."], ans: 1, exp: "Es un incidente incipiente (como una papelera ardiendo) que los propios trabajadores pueden apagar con un extintor." },
    { u: "IPLE T3", q: "La 'Emergencia General' requiere:", opts: ["Solo un extintor.", "La actuación de todos los equipos y medios de protección y la ayuda externa.", "Que el jefe apague la luz general.", "La evacuación parcial de un solo pasillo."], ans: 1, exp: "Supera la capacidad de la empresa, exigiendo evacuación total y la llegada de bomberos y policía." },
    { u: "IPLE T3", q: "Los primeros auxilios son técnicas que se realizan de manera:", opts: ["Profesional y definitiva.", "Inmediata y no profesional.", "Quirúrgica.", "Tardía en el centro médico."], ans: 1, exp: "Se hacen en el mismo lugar del accidente por personas sin titulación médica superior, para mantener con vida a la víctima hasta que llegue la ambulancia." },
    { u: "IPLE T3", q: "¿Qué significan las siglas de la conducta PAS?", opts: ["Prevenir, Atender, Socorrer.", "Proteger, Avisar, Socorrer.", "Pagar, Avisar, Salir.", "Proteger, Actuar, Salvar."], ans: 1, exp: "Es el protocolo universal: Proteger la zona, Avisar al 112, y por último Socorrer al accidentado." },
    { u: "IPLE T3", q: "En la conducta PAS, lo primero que se debe hacer es:", opts: ["Llamar al 112.", "Proteger el lugar del accidente (hacerlo seguro).", "Tocar al herido para ver si respira.", "Irse a buscar un médico."], ans: 1, exp: "Si no haces el lugar seguro primero, corres el riesgo de convertirte en la segunda víctima (ej. entrar a un pozo tóxico sin mascarilla)." },
    { u: "IPLE T3", q: "El número de teléfono único de emergencias en la Unión Europea es:", opts: ["091.", "112.", "911.", "061."], ans: 1, exp: "El 112 coordina policía, ambulancias y bomberos en todo el territorio europeo." },
    { u: "IPLE T3", q: "La técnica de clasificación de heridos en grandes catástrofes se denomina:", opts: ["Triaje.", "Masaje.", "Desinfección.", "Evacuación prioritaria."], ans: 0, exp: "El Triaje (del francés 'trier') clasifica a las víctimas con etiquetas de colores según la gravedad para no colapsar el sistema médico." },
    { u: "IPLE T3", q: "¿Qué indica el color ROJO en un triaje?", opts: ["Fallecido.", "Extrema urgencia (prioridad 1).", "Herido leve que puede caminar.", "Ileso completamente."], ans: 1, exp: "Indica riesgo inminente de muerte (hemorragia masiva, paro respiratorio), requiere atención médica inmediata." },
    { u: "IPLE T3", q: "Un herido con tarjeta VERDE en un triaje es aquel que:", opts: ["Necesita cirugía inmediata.", "Puede caminar y su vida no corre peligro.", "Está inconsciente.", "Ha fallecido en el lugar."], ans: 1, exp: "El verde se da a víctimas leves con rasguños o crisis de ansiedad, que pueden esperar para ser atendidas." },
    { u: "IPLE T3", q: "La evaluación primaria de un accidentado consiste en comprobar, por este orden:", opts: ["Consciencia, Respiración, Pulso.", "Nombre, Edad, Dirección.", "Heridas, Fracturas, Quemaduras.", "Tensión, Temperatura, Azúcar."], ans: 0, exp: "Hay que priorizar las funciones vitales: primero ver si responde, luego si respira y por último si su corazón late." },
    { u: "IPLE T3", q: "Si un accidentado NO respira pero tiene pulso, debemos:", opts: ["Hacer la maniobra de Heimlich.", "Realizar respiraciones de rescate (boca a boca).", "No tocarle bajo ningún concepto.", "Empezar la RCP completa (masaje cardíaco)."], ans: 1, exp: "Si el corazón funciona pero los pulmones no, debemos oxigenarle artificialmente insuflando aire." },
    { u: "IPLE T3", q: "La Posición Lateral de Seguridad (PLS) se aplica a heridos que:", opts: ["Tienen una fractura de pierna.", "Están inconscientes pero respiran.", "Están sangrando por la nariz.", "Sufren una parada cardiorrespiratoria."], ans: 1, exp: "Tumbar a una persona inconsciente de lado evita que se ahogue con su propia lengua o con un vómito." },
    { u: "IPLE T3", q: "Ante una hemorragia externa, la primera medida a tomar es:", opts: ["Hacer un torniquete.", "Presión directa sobre la herida.", "Lavar con alcohol 96º.", "Dar agua al accidentado."], ans: 1, exp: "Taponar la herida presionando fuertemente con gasas es el método principal para detener el sangrado." },
    { u: "IPLE T3", q: "¿Cuándo es recomendable realizar un torniquete?", opts: ["En cualquier corte pequeño para prevenir.", "Solo en casos extremos (amputaciones o cuando la presión directa no funciona).", "Nunca, está totalmente prohibido.", "Siempre que haya sangre visible."], ans: 1, exp: "El torniquete corta totalmente el riego sanguíneo y puede causar la pérdida del miembro; es el último recurso para evitar morir desangrado." },
    { u: "IPLE T3", q: "Si un objeto está clavado en una herida, debemos:", opts: ["Quitarlo rápidamente.", "No extraerlo y fijarlo para evitar que se mueva.", "Limpiarlo con abundante agua.", "Presionar el objeto hacia adentro."], ans: 1, exp: "El objeto actúa como un tapón reteniendo la sangre; si lo extraes provocas una hemorragia incontrolable." },
    { u: "IPLE T3", q: "En una quemadura, lo primero que debemos hacer es:", opts: ["Aplicar pomadas o aceites de cocina.", "Refrigerar con agua fría del grifo durante 15-20 minutos.", "Pinchar las ampollas para que respiren.", "Vendar fuertemente la zona afectada."], ans: 1, exp: "El agua fría disipa el calor residual de los tejidos y frena el daño profundo de la piel." },
    { u: "IPLE T3", q: "Una fractura abierta es aquella en la que:", opts: ["El hueso está roto en muchos trozos internos.", "El hueso rompe la piel y sale al exterior.", "No hay dolor al mover la articulación.", "Se considera solo un esguince grave."], ans: 1, exp: "Es muy peligrosa por el alto riesgo de infección y la hemorragia asociada." },
    { u: "IPLE T3", q: "Ante una sospecha de fractura de columna o cuello:", opts: ["Se debe sentar al herido inmediatamente.", "No se debe mover al accidentado bajo ningún concepto (salvo riesgo vital).", "Se debe llevar en brazos al coche.", "Se debe poner al herido en Posición Lateral de Seguridad."], ans: 1, exp: "Mover el cuello puede seccionar la médula espinal, provocando paraplejia o la muerte." },
    { u: "IPLE T3", q: "La maniobra de Heimlich se utiliza en caso de:", opts: ["Paro cardiaco.", "Obstrucción de la vía aérea por un cuerpo extraño (atragantamiento).", "Quemadura química en el pecho.", "Hemorragia interna severa."], ans: 1, exp: "Consiste en abrazar por detrás a la víctima y presionar bruscamente la boca del estómago para expulsar el objeto." },
    { u: "IPLE T3", q: "En un atragantamiento, si la víctima tose con fuerza:", opts: ["Debemos darle golpes fuertes en la espalda.", "Debemos animarle a seguir tosiendo y no intervenir.", "Debemos tumbarla en el suelo.", "Debemos hacerle la maniobra de Heimlich inmediatamente."], ans: 1, exp: "Si tose, entra aire. Darle golpes en la espalda podría clavar el objeto más profundamente." },
    { u: "IPLE T3", q: "La Reanimación Cardiopulmonar (RCP) combina:", opts: ["30 compresiones y 2 insuflaciones.", "15 compresiones y 5 insuflaciones.", "50 compresiones continuas.", "5 compresiones y 1 insuflación."], ans: 0, exp: "Es el protocolo estándar internacional vigente (30:2)." },
    { u: "IPLE T3", q: "¿Dónde se realizan las compresiones torácicas en la RCP de un adulto?", opts: ["En el abdomen bajo.", "En el centro del pecho (esternón).", "En el lado izquierdo, justo sobre el corazón.", "En la parte alta de la espalda."], ans: 1, exp: "Las manos se entrelazan en la mitad inferior del esternón para comprimir el corazón contra la columna." },
    { u: "IPLE T3", q: "En caso de quemadura química por contacto, se debe:", opts: ["Lavar con abundante agua a chorro suave.", "Poner una venda muy apretada.", "Esperar a que el químico se seque.", "Aplicar una pomada neutralizante."], ans: 0, exp: "El arrastre con agua diluye el químico corrosivo. Debe hacerse durante 15 o 20 minutos." },
    { u: "IPLE T3", q: "Ante una lipotimia (mareo/desmayo), se recomienda:", opts: ["Darle de comer abundantemente.", "Tumbar a la persona con las piernas elevadas.", "Darle fuertes bofetadas para despertarla.", "Sentarla con la cabeza hacia atrás."], ans: 1, exp: "Levantar las piernas facilita el riego sanguíneo y el retorno venoso hacia el cerebro." },
    { u: "IPLE T3", q: "Un botiquín de empresa debe contener obligatoriamente:", opts: ["Antibióticos y jeringuillas.", "Material de cura (gasas, vendas, antisépticos) y material de autoprotección.", "Solo tiritas y aspirinas.", "Un desfibrilador en todos los casos."], ans: 1, exp: "Por ley, los botiquines no deben contener medicación oral, sino solo material para curas de primeros auxilios." },
    { u: "IPLE T3", q: "¿Qué antiséptico es el más recomendado para limpiar heridas en el botiquín?", opts: ["Alcohol de 96º.", "Clorhexidina o povidona yodada.", "Agua oxigenada únicamente.", "Mercurio cromo o alcohol de romero."], ans: 1, exp: "El alcohol quema los bordes de la herida; se recomiendan la clorhexidina (ej. Cristalmina) o la povidona yodada (Betadine)." },
    { u: "IPLE T3", q: "En una fractura de brazo, la función de férula la puede realizar:", opts: ["Una revista enrollada.", "El propio tórax del accidentado (con un cabestrillo).", "Una bufanda atada al cuello.", "Un palo de escoba atado a la pierna."], ans: 1, exp: "Amarrar el brazo lesionado contra el cuerpo inmoviliza la articulación impidiendo que la fractura empeore." },
    { u: "IPLE T3", q: "La técnica para mover a un herido si es estrictamente necesario (ej. incendio) se llama:", opts: ["Arrastre directo por las piernas.", "Maniobra de Rautek.", "Ambas son válidas según el caso.", "Carga de bombero en solitario."], ans: 2, exp: "Tanto el arrastre desde una zona segura como la maniobra de Rautek (agarrar por detrás) evitan agravar posibles lesiones cervicales." },
    { u: "IPLE T3", q: "¿Cuál es el objetivo final de los primeros auxilios?", opts: ["Sustituir la labor del médico.", "Conservar la vida, evitar complicaciones y ayudar a la recuperación.", "Hacer un informe detallado para la mutua de la empresa.", "Evitar tener que llamar a una ambulancia."], ans: 1, exp: "Mantener a la víctima con vida y sin que empeoren sus lesiones hasta que los servicios profesionales se hagan cargo." },
// --- PREGUNTAS DE LA PLATAFORMA (MOODLE) ---
    { u: "IPLE T4", q: "El orden jerárquico correcto de las normas (de mayor a menor) es:", opts: ["La Constitución española, las leyes y normas con rango de ley, reglamentos, convenio colectivo, contrato de trabajo, usos y costumbres locales y profesionales", "La Constitución, convenio colectivo, contrato de trabajo, usos y costumbres locales y profesionales, normas con rango de ley y reglamentos", "Las leyes y normas con rango de ley, la constitución, contrato de trabajo, reglamentos, convenio colectivo, usos y costumbres locales y profesionales", "Ninguna es correcta"], ans: 0, exp: "El orden jurídico establece la Constitución en la cúspide, seguida por leyes y reglamentos del Estado, los convenios colectivos, los contratos individuales y, finalmente, los usos y costumbres." },
    { u: "IPLE T4", q: "El principio in dubio pro operario:", opts: ["Es una interpretación de la norma, indica que en caso de confusión se aplicará la norma que favorezca al empresario", "Es una expresión proveniente del latín en la que se enaltece el trabajo duro", "Es una interpretación de la norma, indica que en caso de confusión se aplicará la norma que favorezca al trabajador", "Es una interpretación de la norma, indica que los trabajadores no pueden renunciar a los derechos que les otorgan las normas"], ans: 2, exp: "Es una regla de interpretación judicial que dicta que, si una norma tiene varios sentidos posibles, se debe elegir el que más beneficie al trabajador." },
    { u: "IPLE T4", q: "Dentro del derecho comunitario diferenciamos entre:", opts: ["La OIT y el ET", "El derecho interno y el derecho externo", "El derecho originario y el derecho derivado", "Las directivas, las recomendaciones, las sanciones y las euroórdenes"], ans: 2, exp: "El derecho comunitario de la UE se divide en Originario (los tratados fundacionales) y Derivado (reglamentos, directivas y decisiones)." },
    { u: "IPLE T4", q: "Señala la afirmación falsa acerca del derecho laboral:", opts: ["Ha existido desde que existe el trabajo", "Nace en el siglo XIX derivado de los problemas de la revolución industrial", "Está en continuo cambio e intenta mejorar la calidad y el bienestar en el ámbito laboral", "Sus principios sirven para interpretar la legislación laboral y cubrir los vacíos que deje"], ans: 0, exp: "El derecho laboral NO ha existido desde que existe el trabajo. El trabajo en la antigüedad (ej. esclavitud o feudalismo) no estaba regulado con derechos laborales, los cuales nacieron en el siglo XIX." },
    { u: "IPLE T4", q: "En la relación laboral entre empleador y empleado, las normas abogan por:", opts: ["Proteger por igual a empleador y empleado", "Proteger en mayor medida al empleado", "Proteger en mayor medida al empleador", "Solo establecen recomendaciones a seguir"], ans: 1, exp: "El 'Principio Protector' del derecho laboral parte de la base de que el trabajador es la parte débil y subordinada, por lo que la ley debe compensar esa desigualdad protegiéndole." },
    { u: "IPLE T4", q: "Cuando de entre los trabajadores se escoge un delegado de personal, se está ejerciendo el derecho a:", opts: ["Representación colectiva unitaria", "Representación colectiva sindical", "Representación retribuida personalizada", "Ninguna de las anteriores"], ans: 0, exp: "Los delegados de personal y el comité de empresa forman la 'representación unitaria' (representan a todos los trabajadores del centro por igual), frente a la representación sindical." },
    { u: "IPLE T4", q: "El convenio colectivo:", opts: ["Es una de las fuentes del derecho laboral", "Es un pacto alcanzado libremente", "Es el reflejo de la participación efectiva de los trabajadores", "Todas son correctas"], ans: 3, exp: "El convenio es una norma fuente del derecho laboral, nacida del acuerdo y la negociación libre entre los representantes de los trabajadores y los empresarios." },
    { u: "IPLE T4", q: "El cese de la prestación de trabajo por parte de los trabajadores para reivindicar algún conflicto o la mejora de condiciones laborales se conoce como:", opts: ["Huelga", "Cierre patronal", "Conflicto colectivo", "Festivos"], ans: 0, exp: "La huelga es el derecho fundamental de los trabajadores a parar su actividad de forma concertada para defender sus intereses." },
    { u: "IPLE T4", q: "¿Cuál de las siguientes no es una garantía de los representantes de los trabajadores?:", opts: ["Prioridad de permanencia", "Libertad de expresión en asuntos relacionados a su representación", "Están exentos de los despidos disciplinarios", "Se les concederá un número de horas al mes retribuidas para ejercer sus funciones como representante"], ans: 2, exp: "Tienen muchas protecciones contra el despido arbitrario, pero NADIE está exento de un despido disciplinario si comete faltas graves justificadas (ej. robo o agresión)." },
    { u: "IPLE T4", q: "¿Cuál es una competencia del comité de empresa?", opts: ["Vigilancia en el cumplimiento de las normas laborales, de seguridad laboral y de empleo", "Participar en la gestión de obras sociales en beneficio de los trabajadores y sus familiares", "Informar a sus representados de los temas y asuntos que repercutan en las relaciones laborales", "Todas las anteriores"], ans: 3, exp: "El comité de empresa tiene derecho a ser informado, a vigilar el cumplimiento legal y a gestionar obras sociales de la empresa." },

    // --- BLOQUE CUESTIONARIO DE AUTOEVALUACIÓN (60 PREGUNTAS) ---
    { u: "IPLE T4", q: "¿Cuál es la misión principal del Derecho del Trabajo?", opts: ["Regular exclusivamente el pago de impuestos de las empresas.", "Regular todo lo concerniente a las relaciones laborales y el vínculo entre trabajadores y empleadores.", "Controlar la vida privada de los trabajadores.", "Establecer los precios de los productos en el mercado."], ans: 1, exp: "Su función es equilibrar las relaciones entre el empresario que dirige y el trabajador subordinado." },
    { u: "IPLE T4", q: "¿En qué siglo surge el Derecho Laboral como respuesta a las problemáticas de la Revolución Industrial?", opts: ["Siglo XV.", "Siglo XIX.", "Siglo XXI.", "Siglo XVIII."], ans: 1, exp: "Surgió en el siglo XIX para poner freno a los abusos y a las condiciones inhumanas de las fábricas tras la revolución industrial." },
    { u: "IPLE T4", q: "¿Cuál es el principio que obliga a dar un amparo mayor al trabajador por su posición de inferioridad?", opts: ["Principio de competitividad.", "Principio protector.", "Principio de jerarquía absoluta.", "Principio de buena fe."], ans: 1, exp: "El Principio Protector fundamenta toda la lógica del derecho laboral: nivelar la desigualdad protegiendo al débil." },
    { u: "IPLE T4", q: "¿Qué principio establece que, en caso de duda sobre el significado de una norma, se aplicará la interpretación más favorable al trabajador?", opts: ["Principio de norma mínima.", "Principio in dubio pro operario.", "Principio de irrenunciabilidad de derechos.", "Principio de primacía de la realidad."], ans: 1, exp: "In dubio pro operario ('en caso de duda, a favor del trabajador') guía a los jueces cuando una ley es ambigua." },
    { u: "IPLE T4", q: "El principio de irrenunciabilidad de derechos implica que:", opts: ["El trabajador puede renunciar a su salario si lo desea.", "Los trabajadores no pueden renunciar a los derechos que les otorgan las normas legales y convenios.", "El empresario puede quitar días de vacaciones libremente.", "Los derechos se pueden intercambiar por días libres siempre que el jefe acepte."], ans: 1, exp: "No puedes firmar un contrato aceptando no tener vacaciones; ese pacto sería nulo de pleno derecho." },
    { u: "IPLE T4", q: "¿Qué principio indica que se aplicará la norma que, en su conjunto, sea más beneficiosa para el trabajador entre varias vigentes?", opts: ["Principio de norma más favorable.", "Principio de condición más beneficiosa.", "Principio de primacía de la realidad.", "Principio protector básico."], ans: 0, exp: "Si concurren dos normas vigentes que regulan lo mismo, se aplicará en su totalidad la que beneficie más al empleado." },
    { u: "IPLE T4", q: "El principio de 'condición más beneficiosa' significa que:", opts: ["Si se pactan condiciones mejores que las de la ley, estas deben mantenerse aunque cambie la normativa.", "Siempre hay que aplicar el contrato antes que la ley.", "El trabajador debe aceptar cualquier cambio que diga el jefe.", "Solo se aplican los beneficios en empresas con más de 50 empleados."], ans: 0, exp: "Los derechos adquiridos se respetan ('condición más beneficiosa') aunque más adelante el convenio empeore para los nuevos contratados." },
    { u: "IPLE T4", q: "Según el principio de 'norma mínima', las normas de rango superior establecen:", opts: ["El máximo que se puede pagar.", "Los mínimos infranqueables que las normas inferiores o contratos no pueden empeorar.", "Que no existen los convenios colectivos.", "Las sanciones por llegar tarde."], ans: 1, exp: "El Estatuto establece un mínimo. El convenio puede mejorar ese mínimo, pero nunca empeorarlo." },
    { u: "IPLE T4", q: "¿Qué principio prevalece cuando hay una discrepancia entre lo que dicen los documentos y lo que ocurre en la práctica?", opts: ["Principio de jerarquía.", "Principio de primacía de la realidad.", "Principio de buena fe.", "Principio in dubio pro operario."], ans: 1, exp: "Si estás como falso autónomo en los papeles pero trabajas con horario y bajo las órdenes del jefe, la realidad demuestra que eres trabajador por cuenta ajena." },
    { u: "IPLE T4", q: "¿Cuál es el orden correcto de la jerarquía normativa laboral (de mayor a menor)?", opts: ["Contrato -> Convenio -> Ley -> Constitución.", "Derecho comunitario -> Constitución -> Tratados internacionales -> Leyes -> Reglamentos -> Convenios -> Contratos.", "Usos y costumbres -> Ley -> Constitución.", "Reglamentos -> Leyes -> Constitución -> Convenios."], ans: 1, exp: "La normativa internacional y constitucional está por encima de las leyes nacionales, y estas sobre los convenios y contratos individuales." },
    { u: "IPLE T4", q: "¿Cuál es la norma suprema del ordenamiento jurídico español?", opts: ["El Estatuto de los Trabajadores.", "La Constitución Española de 1978.", "El Convenio Colectivo.", "Las directivas europeas de empleo."], ans: 1, exp: "La Constitución está en la cúspide del derecho interno y ninguna ley o contrato puede ir en su contra." },
    { u: "IPLE T4", q: "Las normas dictadas por la Unión Europea que son de obligado cumplimiento se engloban en:", opts: ["Derecho comunitario.", "Reglamentos locales.", "Usos y costumbres.", "Estatuto del Trabajo Europeo."], ans: 0, exp: "Incluye los tratados de la UE, Reglamentos (de aplicación directa) y Directivas." },
    { u: "IPLE T4", q: "¿Qué rango tienen los Convenios Colectivos en la jerarquía normativa?", opts: ["Están por encima de la Constitución.", "Están por debajo de las leyes y reglamentos, pero por encima de los contratos de trabajo.", "Son meras recomendaciones no obligatorias.", "Tienen el mismo valor legal que los usos y costumbres locales."], ans: 1, exp: "Subordinados a la ley general (Estatuto de los Trabajadores), pero se imponen sobre cualquier acuerdo individual de contrato." },
    { u: "IPLE T4", q: "¿Qué son los 'usos y costumbres locales y profesionales'?", opts: ["Normas escritas por el ayuntamiento.", "Conductas repetidas y aceptadas en una localidad o profesión que se aplican en ausencia de ley o contrato.", "Reglas que solo se aplican en Navidad.", "Acuerdos secretos entre empresarios para fijar salarios."], ans: 1, exp: "Es la fuente jurídica de menor rango, aplicable solo si no hay ley, convenio ni contrato que regule el caso." },
    { u: "IPLE T4", q: "¿Qué ley es la norma básica que regula los derechos y deberes laborales en España?", opts: ["Ley de Prevención de Riesgos.", "Real Decreto Legislativo 2/2015, del Estatuto de los Trabajadores.", "Código de Comercio.", "Constitución Europea de Derechos Fundamentales."], ans: 1, exp: "El Estatuto de los Trabajadores es la 'biblia' del Derecho Laboral en España." },
    { u: "IPLE T4", q: "¿Cuál de estas es una característica de la relación laboral ordinaria?", opts: ["Obligatoriedad.", "Voluntariedad.", "Gratuidad.", "Unilateralidad."], ans: 1, exp: "Nadie te puede obligar a trabajar en contra de tu voluntad. El trabajo es estrictamente voluntario." },
    { u: "IPLE T4", q: "En una relación laboral, ¿qué significa que sea 'por cuenta ajena'?", opts: ["Que el trabajador asume los beneficios y riesgos económicos del negocio.", "Que los frutos del trabajo y los riesgos pertenecen al empresario.", "Que el trabajador paga su propia seguridad social.", "Que se realiza siempre fuera de la empresa matriz."], ans: 1, exp: "Si produces 100 y cobras tu sueldo, la diferencia se la queda el empresario (y si la empresa pierde dinero, tú cobras tu sueldo igual)." },
    { u: "IPLE T4", q: "¿Qué implica la característica de 'dependencia' o 'subordinación'?", opts: ["Que el trabajador decide sus propias normas.", "Que el trabajador actúa dentro del ámbito de organización y dirección del empresario.", "Que el trabajador es dueño de las máquinas.", "Que el salario depende de las ventas diarias."], ans: 1, exp: "El empresario manda y dirige; el trabajador obedece sus órdenes de organización." },
    { u: "IPLE T4", q: "¿Cuál de las siguientes se considera una relación 'no laboral' o excluida?", opts: ["Un dependiente de una tienda.", "El trabajo de los funcionarios públicos (personal estatutario).", "Un soldador en una fábrica.", "Un recepcionista de hotel con contrato temporal."], ans: 1, exp: "Los funcionarios se rigen por el Derecho Administrativo (EBEP), no por el Estatuto de los Trabajadores." },
    { u: "IPLE T4", q: "Los trabajos realizados a título de amistad, benevolencia o buena vecindad son:", opts: ["Relaciones laborales ordinarias.", "Relaciones excluidas del Derecho Laboral.", "Relaciones laborales especiales.", "Contratos verbales de prueba."], ans: 1, exp: "Si le pintas la casa a un amigo gratis un domingo, no hay contrato, salario ni subordinación." },
    { u: "IPLE T4", q: "¿A qué grupo pertenecen los deportistas profesionales o los artistas en espectáculos públicos?", opts: ["Relaciones laborales ordinarias.", "Relaciones laborales especiales.", "Relaciones excluidas.", "Trabajadores por cuenta propia obligatoriamente."], ans: 1, exp: "Están en el Estatuto de los Trabajadores, pero tienen sus propios Reales Decretos específicos por la naturaleza de su labor." },
    { u: "IPLE T4", q: "¿Cuál es la edad mínima general para trabajar en España?", opts: ["14 años.", "16 años.", "18 años.", "21 años."], ans: 1, exp: "Está totalmente prohibido trabajar con menos de 16 años (salvo excepciones artísticas)." },
    { u: "IPLE T4", q: "Los menores de 18 años tienen prohibido realizar:", opts: ["Trabajos de oficina.", "Trabajos nocturnos, peligrosos o insalubres.", "Cualquier tipo de trabajo.", "Trabajos a tiempo parcial."], ans: 1, exp: "Un menor de 18 no puede hacer el turno de noche ni realizar horas extras o trabajos que perjudiquen su salud." },
    { u: "IPLE T4", q: "¿Qué capacidad para contratar tienen los menores de 16 años?", opts: ["Solo para espectáculos públicos con autorización de la autoridad laboral.", "Ninguna, bajo ningún concepto.", "Plena capacidad como un adulto.", "Pueden firmar si tienen el graduado escolar."], ans: 0, exp: "Es la única excepción legal (actores, cantantes infantiles), y requiere permiso expreso de la administración caso por caso." },
    { u: "IPLE T4", q: "Los extranjeros no comunitarios necesitan para trabajar en España:", opts: ["Solo el pasaporte.", "Autorización administrativa para trabajar y residir (permiso de trabajo).", "Una invitación de un amigo.", "Un visado de turista válido por 3 meses."], ans: 1, exp: "Un permiso de residencia y trabajo es requisito ineludible si no eres ciudadano de la UE." },
    { u: "IPLE T4", q: "¿Cuál de estos es un derecho básico del trabajador según la Constitución?", opts: ["Derecho a la libre sindicación.", "Derecho a llegar tarde una vez por semana.", "Derecho a usar el coche de la empresa para fines personales.", "Derecho a rechazar órdenes legales del empresario."], ans: 0, exp: "El derecho a afiliarse o fundar un sindicato (o a no hacerlo) es un derecho constitucional fundamental." },
    { u: "IPLE T4", q: "El derecho a la 'ocupación efectiva' implica que:", opts: ["El trabajador debe estar siempre ocupado limpiando.", "El empresario tiene el deber de proporcionar trabajo real al empleado durante su jornada.", "El trabajador puede elegir su propio horario.", "El lugar de trabajo debe tener siempre luz natural."], ans: 1, exp: "No te pueden tener sentado en una silla mirando a la pared sin darte tareas como medida de castigo." },
    { u: "IPLE T4", q: "¿Cuál es un deber laboral del trabajador?", opts: ["Negociar el convenio colectivo.", "Cumplir con las obligaciones de su puesto de conformidad a las reglas de la buena fe y diligencia.", "Inspeccionar a otras empresas.", "Contratar a su propio sustituto cuando esté enfermo."], ans: 1, exp: "Se debe trabajar con diligencia (hacerlo bien y con ganas) y de buena fe (sin robar ni sabotear a la empresa)." },
    { u: "IPLE T4", q: "El deber de 'no concurrencia desleal' significa que:", opts: ["El trabajador no puede correr en el centro de trabajo.", "El trabajador no puede trabajar para otra empresa de la competencia si causa un perjuicio.", "El trabajador debe comer fuera de la oficina.", "El trabajador no puede hablar con clientes fuera de horario."], ans: 1, exp: "Si trabajas en una panadería, no puedes abrir tu propia panadería en la acera de enfrente robándole los clientes al jefe." },
    { u: "IPLE T4", q: "¿Qué potestad tiene el empresario para organizar el trabajo?", opts: ["Poder de dirección.", "Poder de expropiación.", "Poder absoluto sin límites legales.", "Poder de mediación civil."], ans: 0, exp: "El Poder de Dirección (Ius variandi) permite al jefe dar órdenes, organizar turnos y dictar cómo se hace el trabajo." },
    { u: "IPLE T4", q: "El 'poder disciplinario' permite al empresario:", opts: ["Multar económicamente al trabajador con reducciones de sueldo.", "Sancionar los incumplimientos laborales del trabajador según la graduación de faltas.", "Despedir a cualquiera sin motivo.", "Encarcelar temporalmente al trabajador por robo."], ans: 1, exp: "Si el trabajador incumple sus deberes, el empresario puede imponer sanciones desde amonestaciones hasta el despido disciplinario." },
    { u: "IPLE T4", q: "¿Qué organismo se encarga de vigilar el cumplimiento de la normativa laboral y de seguridad social?", opts: ["El Ayuntamiento.", "La Inspección de Trabajo y Seguridad Social (ITSS).", "El Banco de España.", "La Guardia Civil exclusivamente."], ans: 1, exp: "La Inspección vigila, levanta actas de infracción y propone multas a empresas que incumplen." },
    { u: "IPLE T4", q: "¿Quiénes pueden presentar una denuncia ante la Inspección de Trabajo?", opts: ["Solo el empresario.", "Cualquier persona que tenga conocimiento de una infracción.", "Solo los sindicatos mayoritarios.", "Exclusivamente los jueces de lo social."], ans: 1, exp: "Las denuncias son confidenciales y puede interponerlas cualquier ciudadano, trabajador o sindicato que detecte un abuso legal." },
    { u: "IPLE T4", q: "La Jurisdicción Social es la encargada de:", opts: ["Juzgar delitos de tráfico.", "Resolver los conflictos que surjan entre trabajadores y empresarios en el ámbito laboral.", "Cobrar las multas de la biblioteca.", "Aprobar los presupuestos generales del Estado."], ans: 1, exp: "Los jueces de lo Social tratan despidos, reclamaciones de cantidad y vacaciones, conflictos colectivos, etc." },
    { u: "IPLE T4", q: "¿Cuál es el orden de los órganos judiciales laborales (de menor a mayor)?", opts: ["Tribunal Supremo -> Juzgados de lo Social.", "Juzgados de lo Social -> Tribunales Superiores de Justicia (TSJ) -> Audiencia Nacional -> Tribunal Supremo.", "Solo existe el Tribunal Constitucional.", "Tribunal de Cuentas -> Tribunal Superior -> Juzgado de Paz."], ans: 1, exp: "Las sentencias del Juzgado de lo Social pueden apelarse al TSJ de la comunidad y llegar en casación al Tribunal Supremo en Madrid." },
    { u: "IPLE T4", q: "¿Cómo se llama la representación elegida por los trabajadores en los centros de trabajo?", opts: ["Representación unitaria.", "Representación divina.", "Representación patronal.", "Representación jerárquica obligatoria."], ans: 0, exp: "La representación unitaria (Comité de empresa y delegados de personal) defiende los intereses de TODOS los trabajadores por igual." },
    { u: "IPLE T4", q: "En centros de trabajo de entre 11 y 49 trabajadores, la representación unitaria corre a cargo de:", opts: ["El Comité de Empresa.", "Los Delegados de Personal.", "El director de RRHH.", "El sindicato mayoritario a nivel nacional."], ans: 1, exp: "En empresas pequeñas no se forma un comité; en su lugar se eligen a 1 o 3 Delegados de Personal." },
    { u: "IPLE T4", q: "El Comité de Empresa se constituye en centros de trabajo que tengan:", opts: ["10 trabajadores o más.", "50 trabajadores o más.", "Más de 1.000 trabajadores solamente.", "Exactamente 25 trabajadores."], ans: 1, exp: "A partir del trabajador número 50, es obligatorio elegir un órgano colegiado (El Comité de Empresa)." },
    { u: "IPLE T4", q: "¿Cuántos delegados de personal corresponden a una empresa de 25 trabajadores?", opts: ["1.", "3.", "5.", "2."], ans: 0, exp: "De 11 a 30 trabajadores corresponde 1 delegado. De 31 a 49 corresponden 3." },
    { u: "IPLE T4", q: "¿Cuál es la duración del mandato de los representantes de los trabajadores?", opts: ["1 año.", "4 años.", "De por vida.", "2 años."], ans: 1, exp: "Las elecciones sindicales nombran a los representantes por un mandato fijo de cuatro años." },
    { u: "IPLE T4", q: "¿Qué es el 'crédito de horas retribuidas'?", opts: ["Un préstamo bancario para delegados.", "Un número de horas mensuales pagadas que los representantes tienen para ejercer sus funciones.", "El tiempo de descanso para el café.", "Un bono anual que se cobra en Navidad."], ans: 1, exp: "Es lo que se conoce como 'horas sindicales', un tiempo durante la jornada en el que no trabajan pero sí cobran, destinado a asesorar a sus compañeros." },
    { u: "IPLE T4", q: "La representación sindical se articula a través de:", opts: ["Las Secciones Sindicales y los Delegados Sindicales.", "Los accionistas de la empresa.", "El Comité de Seguridad y Salud únicamente.", "Las mutuas colaboradoras."], ans: 0, exp: "A diferencia de la unitaria, la representación sindical solo agrupa y defiende a los trabajadores afiliados a un sindicato concreto (ej. CCOO, UGT)." },
    { u: "IPLE T4", q: "¿Qué es un Convenio Colectivo?", opts: ["Un contrato individual de un trabajador.", "Un acuerdo escrito entre representantes de trabajadores y empresarios para regular condiciones de trabajo.", "Una revista de noticias laborales.", "Una ley aprobada por el Congreso de los Diputados."], ans: 1, exp: "Es el fruto de la negociación colectiva. Regula de forma específica salarios y jornadas de un sector o empresa concreta." },
    { u: "IPLE T4", q: "El convenio colectivo tiene 'eficacia normativa', lo que significa que:", opts: ["Obliga a todos los incluidos en su ámbito de aplicación como si fuera una ley.", "Solo obliga a quienes lo firmaron personalmente.", "Es opcional cumplirlo si el jefe no quiere.", "Solo se aplica a los afiliados al sindicato que lo firmó."], ans: 0, exp: "Se aplica a todo el mundo (eficacia general 'erga omnes'), independientemente de si estás afiliado o no al sindicato que lo negoció." },
    { u: "IPLE T4", q: "¿Qué contenido debe tener mínimamente un convenio?", opts: ["Solo el salario.", "Determinación de las partes, ámbitos (territorial, funcional, etc.), deber de paz y comisión paritaria.", "La lista de cumpleaños de los empleados.", "El tipo de vestimenta que deben usar los jefes de sección."], ans: 1, exp: "Debe dejar claro quién lo firma, a qué territorio se aplica (ej. Convenio Metal de Madrid) y crear un comité para vigilar que se cumpla." },
    { u: "IPLE T4", q: "Un conflicto laboral es 'colectivo' cuando:", opts: ["Afecta a un solo trabajador.", "Afecta a un grupo de trabajadores y tiene por objeto un interés general.", "Hay una pelea en el comedor.", "El trabajador demanda al empresario por despido improcedente."], ans: 1, exp: "Si el problema de interpretación legal afecta a toda la plantilla (ej. cálculo del plus de transporte de todos), es un conflicto colectivo." },
    { u: "IPLE T4", q: "La huelga consiste en:", opts: ["Trabajar más despacio.", "La cesación de la prestación de trabajo de forma colectiva y concertada.", "No ir a trabajar por estar enfermo.", "Dañar las instalaciones de la empresa como protesta."], ans: 1, exp: "Es un derecho fundamental; parar la producción pacíficamente para presionar al empleador a negociar." },
    { u: "IPLE T4", q: "Durante la huelga legal, el contrato de trabajo queda:", opts: ["Extinguido (despido).", "Suspendido (no se trabaja ni se cobra salario).", "Activo (se cobra igual aunque no se trabaje).", "Reemplazado por un contrato temporal."], ans: 1, exp: "No te pueden despedir por hacer huelga, pero el empresario no tiene la obligación de pagarte los días que faltes (se suspende el sueldo)." },
    { u: "IPLE T4", q: "¿Qué es el 'cierre patronal'?", opts: ["El cierre de la empresa por vacaciones.", "La clausura del centro por el empresario en caso de huelga o irregularidad colectiva grave.", "La quiebra de la empresa.", "El momento en el que el jefe se va a casa al terminar la jornada."], ans: 1, exp: "Es el derecho (muy restrictivo) del empresario a cerrar la fábrica para evitar altercados graves o daños a las instalaciones durante una huelga." },
    { u: "IPLE T4", q: "¿Cuál de estos es un método extrajudicial de solución de conflictos?", opts: ["Un juicio en el Tribunal Supremo.", "La Mediación.", "Una denuncia en la policía.", "Una demanda ante el Juzgado de lo Social."], ans: 1, exp: "La conciliación, la mediación y el arbitraje buscan evitar ir a los tribunales (son extrajudiciales)." },
    { u: "IPLE T4", q: "En el procedimiento de 'Arbitraje':", opts: ["Las partes negocian solas.", "Un tercero imparcial dicta una resolución (laudo) que es vinculante para las partes.", "El mediador solo ayuda a hablar.", "El juez dicta sentencia obligatoria."], ans: 1, exp: "Las dos partes aceptan de antemano que lo que decida el árbitro privado en el 'laudo' será de obligado cumplimiento." },
    { u: "IPLE T4", q: "La 'Conciliación' busca:", opts: ["Que un juez decida quién tiene la razón.", "Que un tercero facilite el acercamiento de posturas para lograr un acuerdo voluntario.", "Castigar al culpable del conflicto.", "Dictar un laudo arbitral obligatorio."], ans: 1, exp: "El conciliador sienta a las partes en una mesa y ayuda a que dialoguen, pero NO les impone la solución." },
    { u: "IPLE T4", q: "El principio 'in dubio pro operario' se aplica cuando:", opts: ["No hay ninguna norma.", "Existe una norma con varios significados posibles.", "El trabajador es nuevo.", "El empresario no sabe qué contrato aplicar."], ans: 1, exp: "Es exclusivamente una regla de interpretación; solo se usa si la ley existe pero es oscura y da lugar a debate." },
    { u: "IPLE T4", q: "¿Qué sucede si un contrato individual establece un salario inferior al del Convenio Colectivo?", opts: ["Es válido si el trabajador firmó.", "Es nulo en esa parte por el principio de norma mínima.", "La empresa puede hacerlo si tiene pérdidas.", "Se descuenta la diferencia en vacaciones."], ans: 1, exp: "Firmes lo que firmes, un contrato no puede pisotear el mínimo que marca el convenio. Ese pacto es papel mojado." },
    { u: "IPLE T4", q: "El Derecho del Trabajo regula relaciones que son 'personalísimas', esto significa:", opts: ["Que el trabajador puede enviar a su hermano a trabajar por él.", "Que el trabajo debe ser realizado por la persona contratada, no por otra.", "Que el jefe debe ser simpático.", "Que el contrato debe ser redactado a mano."], ans: 1, exp: "Contratan a 'Juan' por ser 'Juan'. El trabajador no puede delegar o sustituir a otra persona en su puesto." },
    { u: "IPLE T4", q: "¿Qué es la 'negociación colectiva'?", opts: ["Comprar material para la oficina en grupo.", "El proceso de diálogo entre sindicatos y patronal para alcanzar acuerdos (convenios).", "Una reunión de amigos de la fábrica.", "Un juicio con múltiples demandantes."], ans: 1, exp: "Es el derecho colectivo al diálogo y pacto de condiciones entre empresarios y representantes obreros." },
    { u: "IPLE T4", q: "El personal de alta dirección tiene una relación laboral de tipo:", opts: ["Ordinaria.", "Especial.", "Excluida.", "No laboral."], ans: 1, exp: "Los altos directivos (CEOs) tienen un régimen laboral distinto debido al grado de confianza y responsabilidad de sus decisiones." },
    { u: "IPLE T4", q: "¿Qué significa el 'deber de buena fe' en el trabajo?", opts: ["Que hay que ir a misa.", "Actuar con honradez, lealtad y sinceridad en el cumplimiento de las obligaciones.", "No decir nunca la verdad al jefe.", "Trabajar sin cobrar horas extra de forma voluntaria."], ans: 1, exp: "Significa no revelar secretos de la empresa, no faltar al respeto y no abusar de los permisos y bajas médicas." },
    { u: "IPLE T4", q: "El 'diálogo social' es la interlocución entre:", opts: ["Clientes y vendedores.", "Sindicatos, empleadores e instituciones públicas.", "Solo entre los trabajadores de la limpieza.", "El jefe y los empleados de un mismo departamento."], ans: 1, exp: "A nivel estatal, es el foro donde el Gobierno debate con los agentes sociales (CEOE, CCOO, UGT) para crear leyes laborales y ERTEs." },
    { u: "IPLE T4", q: "Un herido con tarjeta NEGRA en un triaje de emergencia es aquel que:", opts: ["Necesita ayuda urgente.", "Ha fallecido o sus lesiones son incompatibles con la vida.", "Tiene una fractura leve.", "Requiere traslado inmediato en helicóptero."], ans: 1, exp: "En una catástrofe con múltiples heridos, los médicos no dedican recursos a los fallecidos o insalvables (tarjeta negra), priorizando a los rojos (riesgo de muerte salvable)." },
// --- PREGUNTAS DE LA PLATAFORMA (MOODLE) ---
    { u: "IPLE T5", q: "Con respecto a los contratos de formación en alternancia:", opts: ["Su finalidad es cubrir temporalmente un puesto de trabajo durante el proceso de selección formativa", "La duración mínima será de tres meses y la máxima de dos años", "Admite la realización de horas extra en un 65% de las jornadas, durante el primer año", "Todas son correctas"], ans: 1, exp: "La ley establece que el contrato de formación en alternancia tiene una duración mínima de 3 meses y máxima de 2 años. Además, están terminantemente prohibidas las horas extras en este tipo de contratos." },
    { u: "IPLE T5", q: "Señala la respuesta correcta:", opts: ["Si se tiene un contrato a tiempo parcial no se pueden realizar horas extras, salvo por fuerza mayor", "La duración máxima de un contrato indefinido es de 25 años", "El contrato de trabajo temporal solo puede celebrarse a jornada parcial, aunque de manera verbal o escrita", "Ninguna es correcta"], ans: 0, exp: "En los contratos a tiempo parcial están prohibidas las horas extraordinarias, permitiéndose únicamente las horas complementarias pactadas o las horas extras por causa de fuerza mayor." },
    { u: "IPLE T5", q: "Se considera una causa de despido objetivo:", opts: ["Embriaguez habitual o toxicomanía", "Ofensas verbales o físicas a otros trabajadores", "Disminución continuada y voluntaria en el rendimiento de trabajo", "Ineptitud del trabajador conocida o sobrevenida posteriormente"], ans: 3, exp: "La ineptitud sobrevenida o conocida tras el periodo de prueba es una causa objetiva (no culposa) de despido. Las otras tres opciones (embriaguez, ofensas, bajo rendimiento) son faltas graves y justifican un despido disciplinario." },
    { u: "IPLE T5", q: "En un despido disciplinario:", opts: ["Te deben indemnizar con 20 días de salario por año trabajado", "Te deben indemnizar con 33 días de salario por año trabajado", "Se cobrará indemnización solo si el empresario no preavisa con 30 días", "No tienes derecho a indemnización"], ans: 3, exp: "El despido disciplinario se basa en un incumplimiento grave y culpable del trabajador, por lo que la ley no contempla ningún tipo de indemnización (solo el cobro del finiquito)." },
    { u: "IPLE T5", q: "En un despido colectivo:", opts: ["Deben concurrir causas económicas, técnicas, organizativas o de producción", "Debe afectar al 30% de la plantilla de manera obligatoria", "No requiere comunicación previa a los representantes de los trabajadores", "A y B son correctas"], ans: 0, exp: "El despido colectivo o ERE de extinción se fundamenta legalmente en causas ETOP (Económicas, Técnicas, Organizativas o de Producción) que justifican la necesidad de amortizar puestos de trabajo." },
    { u: "IPLE T5", q: "En un despido declarado improcedente:", opts: ["Se prohíbe readmitir al trabajador", "Se entrega un finiquito de hasta 24 mensualidades", "El empresario siempre debe pagar una indemnización de 24 días por año trabajado", "Ninguna es correcta"], ans: 3, exp: "Ninguna es correcta porque en un despido improcedente el empresario puede elegir entre readmitir al trabajador o pagar una indemnización de 33 días (no 24) por año trabajado, con un límite de 24 mensualidades." },
    { u: "IPLE T5", q: "¿Qué situación no se considera una modificación sustancial de las condiciones de trabajo?:", opts: ["Aquella que afecte a la jornada de trabajo", "Cambio a turnos rotativos", "Modificación del espacio de trabajo dentro del mismo centro", "Modificación de la cuantía del salario o del sistema de remuneración"], ans: 2, exp: "Cambiar de mesa o de planta dentro del mismo edificio entra dentro del poder de dirección ordinario del empresario y no altera sustancialmente las condiciones de vida o trabajo del empleado." },
    { u: "IPLE T5", q: "¿Cuáles son los elementos esenciales del contrato?:", opts: ["Consentimiento, objeto y causa", "Licitud, posibilidad y determinabilidad", "Partes, tiempo y categoría", "Persona física, persona jurídica y motivación"], ans: 0, exp: "Para que cualquier contrato sea jurídicamente válido (incluido el laboral), el Código Civil exige que concurran consentimiento libre, objeto cierto y causa lícita." },
    { u: "IPLE T5", q: "¿Cuál de las siguientes no es una cláusula que se puede incluir en el contrato?:", opts: ["Confidencialidad", "No competencia", "Excedencia", "Permanencia"], ans: 2, exp: "La excedencia es un derecho o situación legal de suspensión del contrato regulada en el Estatuto de los Trabajadores, no una cláusula limitativa que se firme en el contrato de inicio." },
    { u: "IPLE T5", q: "Cuando el trabajador es destinado a un centro de trabajo que le supone un cambio de residencia definitivo o acumula desplazamientos que se prolongan durante más de doce meses en un período de tres años, se denomina:", opts: ["Movilidad sustancial", "Movilización", "Desplazamiento", "Traslado"], ans: 3, exp: "El 'Traslado' es una medida de movilidad geográfica definitiva (cambio de residencia permanente o desplazamientos que superen los 12 meses en 3 años)." },

    // --- BLOQUE CUESTIONARIO DE AUTOEVALUACIÓN (60 PREGUNTAS) ---
    { u: "IPLE T5", q: "¿Qué tres elementos esenciales debe tener un contrato para ser válido?", opts: ["Salario, oficina y horario.", "Consentimiento, objeto y causa.", "Firma, sello y fecha.", "Identificación, testigos y registro notarial."], ans: 1, exp: "El Código Civil y el Estatuto de los Trabajadores exigen el libre consentimiento de las partes, un objeto lícito (el trabajo en sí) y una causa verdadera (el intercambio de trabajo por salario)." },
    { u: "IPLE T5", q: "El 'consentimiento' en un contrato implica que:", opts: ["El trabajador es menor de 14 años.", "Las partes manifiestan libremente su voluntad de contratar sin coacciones.", "El contrato debe ser siempre de color azul.", "Debe haber autorización previa del SEPE para que sea válido."], ans: 1, exp: "Ambas partes deben aceptar las condiciones voluntariamente, sin que exista intimidación, violencia o engaño." },
    { u: "IPLE T5", q: "¿A qué se refiere el 'objeto' del contrato de trabajo?", opts: ["Al dinero que se paga.", "A la prestación del servicio o actividad que el trabajador se compromete a realizar.", "Al papel físico donde se firma.", "A las herramientas que entrega la empresa al empleado."], ans: 1, exp: "El objeto del contrato laboral es la propia prestación de los servicios profesionales (el trabajo lícito, posible y determinado)." },
    { u: "IPLE T5", q: "Como regla general, ¿qué forma pueden tener los contratos de trabajo?", opts: ["Únicamente por escrito.", "Solo de palabra.", "Tanto por escrito como de palabra (verbal).", "Solo a través de medios telemáticos oficiales."], ans: 2, exp: "El Estatuto de los Trabajadores permite la forma escrita y la verbal (de palabra), aunque la inmensa mayoría de las modalidades exigen legalmente la forma escrita." },
    { u: "IPLE T5", q: "¿Qué sucede si un contrato de duración determinada no se formaliza por escrito debiendo serlo?", opts: ["El contrato se anula automáticamente.", "Se presume celebrado por tiempo indefinido y a jornada completa, salvo prueba en contrario.", "El trabajador debe ser despedido.", "La empresa recibe una advertencia pero el contrato no cambia."], ans: 1, exp: "Es una medida de protección para el trabajador: si la empresa no lo pone por escrito, la ley penaliza asumiendo que es fijo y a jornada completa." },
    { u: "IPLE T5", q: "¿Cuál es el plazo máximo para que el empresario informe por escrito al trabajador sobre los elementos esenciales del contrato si estos no figuran en el documento?", opts: ["1 semana.", "2 meses.", "1 año.", "15 días hábiles."], ans: 1, exp: "La empresa dispone de un máximo de 2 meses desde el inicio de la relación laboral para entregar la información básica de las condiciones por escrito." },
    { u: "IPLE T5", q: "¿A partir de qué edad se tiene plena capacidad para contratar como trabajador?", opts: ["16 años.", "18 años.", "21 años.", "14 años."], ans: 1, exp: "Con 18 años se alcanza la mayoría de edad y se tiene plena capacidad de obrar y firmar contratos libremente sin autorización de los padres." },
    { u: "IPLE T5", q: "¿Qué requiere un menor de 18 años y mayor de 16 para firmar un contrato si no está emancipado?", opts: ["Nada, puede firmar él solo.", "Autorización de sus padres o tutores.", "Un permiso del juez de paz.", "Un salvoconducto de la Seguridad Social."], ans: 1, exp: "Entre los 16 y los 18 años, el menor necesita el permiso expreso de sus representantes legales para trabajar (salvo que esté legalmente emancipado)." },
    { u: "IPLE T5", q: "Los menores de 16 años tienen prohibido trabajar, excepto en:", opts: ["Fábricas textiles.", "Espectáculos públicos, con autorización de la autoridad laboral.", "Reparto de comida a domicilio.", "Labores agrícolas durante el verano."], ans: 1, exp: "La única excepción a la prohibición absoluta de trabajar por debajo de los 16 años es la participación en espectáculos (teatro, cine) y siempre garantizando que no afecte a sus estudios ni a su salud." },
    { u: "IPLE T5", q: "El 'periodo de prueba' sirve para:", opts: ["Trabajar gratis durante un mes.", "Que ambas partes comprueben si la relación laboral les satisface.", "Pagar menos seguridad social durante los primeros meses.", "Obligar al empleado a hacer horas extras sin cobrarlas."], ans: 1, exp: "Es un tiempo de evaluación mutua. El empresario evalúa la aptitud del trabajador y este evalúa si las condiciones de la empresa le gustan." },
    { u: "IPLE T5", q: "Durante el periodo de prueba, ¿se puede rescindir el contrato?", opts: ["Solo si hay un preaviso de 15 días.", "Sí, por cualquiera de las partes, sin preaviso y sin derecho a indemnización.", "No, es obligatorio terminar el periodo antes de dimitir.", "Solo el trabajador puede rescindirlo, el empresario no."], ans: 1, exp: "El libre desistimiento durante la prueba implica que te puedes ir de un día para otro o te pueden echar sin dar explicaciones ni pagarte indemnización." },
    { u: "IPLE T5", q: "¿Cuál es el límite máximo del periodo de prueba para técnicos titulados según el Estatuto de los Trabajadores?", opts: ["2 meses.", "6 meses.", "1 año.", "3 meses."], ans: 1, exp: "El Estatuto marca un tope máximo de 6 meses para técnicos titulados y 2 meses para el resto de trabajadores (salvo que el convenio indique otra cosa menor)." },
    { u: "IPLE T5", q: "Tras la reforma de 2021, ¿cuál es el contrato que se presume como norma general?", opts: ["El contrato temporal.", "El contrato indefinido.", "El contrato de formación.", "El contrato a tiempo parcial."], ans: 1, exp: "La ley persigue la estabilidad en el empleo, por lo que cualquier contrato se presumirá concertado por tiempo indefinido salvo que se justifique una causa de temporalidad." },
    { u: "IPLE T5", q: "El contrato indefinido adscrito a obra en el sector de la construcción se caracteriza por:", opts: ["Terminar cuando el trabajador se cansa.", "Que al finalizar la obra, la empresa debe ofrecer una propuesta de recolocación al trabajador.", "Ser siempre de solo 3 meses.", "Convertirse automáticamente en contrato temporal tras un año."], ans: 1, exp: "Es un contrato específico de la construcción. Si se acaba la obra, la empresa debe intentar reubicar al empleado en otra obra antes de extinguir el contrato." },
    { u: "IPLE T5", q: "¿Qué contrato se utiliza para realizar trabajos de naturaleza estacional o actividades productivas intermitentes?", opts: ["Contrato eventual.", "Contrato fijo-discontinuo.", "Contrato de prácticas.", "Contrato de interinidad."], ans: 1, exp: "El fijo-discontinuo es ideal para campañas de verano, hostelería de temporada o tareas agrícolas recurrentes. El trabajador es indefinido pero solo trabaja unos meses al año." },
    { u: "IPLE T5", q: "¿Cuántos tipos de contratos de duración determinada (temporales) existen actualmente?", opts: ["Uno solo: por obra o servicio.", "Dos: por circunstancias de la producción y por sustitución.", "Diez tipos diferentes.", "Tres: obra, eventual y de interinidad."], ans: 1, exp: "Tras la última reforma laboral, los contratos temporales se redujeron drásticamente a solo dos modalidades muy estrictas." },
    { u: "IPLE T5", q: "El contrato por 'circunstancias de la producción' por incremento ocasional imprevisible tiene una duración máxima de:", opts: ["3 meses.", "6 meses (ampliable a 12 por convenio).", "2 años.", "4 años."], ans: 1, exp: "Para los picos de trabajo imprevistos (ej. un pico de pedidos no esperado), el límite legal es de 6 meses, aunque los convenios pueden estirarlo a 12 meses." },
    { u: "IPLE T5", q: "¿Cuántos días al año puede una empresa contratar de forma temporal para situaciones previsibles y de corta duración?", opts: ["30 días.", "90 días (no continuados).", "180 días.", "15 días hábiles."], ans: 1, exp: "Para campañas previsibles (como las rebajas o campañas de Navidad), la empresa tiene un tope de 90 días al año (que no pueden ser continuados) para usar este contrato temporal." },
    { u: "IPLE T5", q: "El 'contrato por sustitución' se utiliza para:", opts: ["Probar a un trabajador nuevo en un puesto de dirección.", "Sustituir a una persona con derecho a reserva del puesto de trabajo o completar jornadas reducidas.", "Realizar una obra nueva en la calle.", "Cubrir las vacaciones de toda la plantilla en verano."], ans: 1, exp: "Sustituye al antiguo contrato de interinidad. Se usa para suplir bajas médicas, excedencias con reserva de puesto o maternidades." },
    { u: "IPLE T5", q: "¿Qué se considera 'fraude de ley' en la contratación temporal?", opts: ["Contratar a alguien por 10 años.", "Utilizar un contrato temporal cuando la necesidad de la empresa es permanente.", "Pagar el salario mínimo interprofesional a un eventual.", "Hacer contratos de lunes a viernes repetidamente."], ans: 1, exp: "El fraude de ley ocurre cuando se disfraza bajo un contrato temporal un puesto que en realidad es estructural y fijo para la empresa. La sanción es hacerlo indefinido." },
    { u: "IPLE T5", q: "El 'contrato formativo en alternancia' busca:", opts: ["Que el trabajador sustituya a un jubilado por anticipado.", "Compatibilizar la actividad laboral retribuida con los procesos formativos (estudios).", "Que el trabajador haga prácticas solo después de terminar la carrera.", "Ofrecer trabajo temporal a personas sin estudios básicos."], ans: 1, exp: "Es la FP Dual o antigua formación y aprendizaje. El trabajador aprende la teoría en el instituto/centro y practica cobrando en la empresa." },
    { u: "IPLE T5", q: "¿Cuál es el límite de edad para el contrato de formación en alternancia si no hay discapacidad o exclusión social?", opts: ["25 años.", "30 años (en ciertos supuestos de certificados de profesionalidad).", "No hay límite de edad en general.", "18 años."], ans: 1, exp: "La reforma elevó el tope hasta los 30 años cuando se enmarca en la obtención de certificados de profesionalidad de niveles 1 y 2." },
    { u: "IPLE T5", q: "El 'contrato para la obtención de la práctica profesional' se puede concertar dentro de los:", opts: ["10 años siguientes a terminar los estudios.", "3 años siguientes (o 5 para personas con discapacidad).", "6 meses después de graduarse.", "5 años siguientes para la población en general."], ans: 1, exp: "Sustituye al antiguo contrato en prácticas. Se debe formalizar en los 3 años inmediatamente posteriores a la obtención del título universitario o de FP." },
    { u: "IPLE T5", q: "¿Cuál es la duración mínima y máxima del contrato de práctica profesional?", opts: ["1 mes a 6 meses.", "6 meses a 1 año.", "1 año a 2 años.", "3 meses a 6 meses."], ans: 1, exp: "Su duración no podrá ser inferior a seis meses ni exceder de un año." },
    { u: "IPLE T5", q: "¿Cuál es la duración máxima de la jornada ordinaria de trabajo en cómputo anual?", opts: ["35 horas semanales.", "40 horas semanales de promedio.", "48 horas semanales.", "37,5 horas semanales."], ans: 1, exp: "El Estatuto de los Trabajadores fija que la jornada ordinaria no superará las 40 horas semanales de trabajo efectivo en promedio anual." },
    { u: "IPLE T5", q: "Entre el final de una jornada y el comienzo de la siguiente deben transcurrir al menos:", opts: ["8 horas.", "10 horas.", "12 horas.", "14 horas."], ans: 2, exp: "Es el tiempo de descanso mínimo obligatorio diario (12 horas) para garantizar que el trabajador pueda dormir y recuperarse entre turnos." },
    { u: "IPLE T5", q: "¿Qué descanso mínimo debe tener un trabajador cuya jornada diaria continuada exceda de 6 horas?", opts: ["5 minutos.", "15 minutos (tiempo de bocadillo).", "1 hora.", "30 minutos."], ans: 1, exp: "Es el conocido 'descanso para el bocadillo'. Si la jornada supera las 6 horas seguidas, hay derecho a una pausa mínima de 15 minutos." },
    { u: "IPLE T5", q: "El descanso semanal mínimo para los trabajadores adultos es de:", opts: ["Un día completo.", "Un día y medio ininterrumpido.", "Dos días obligatorios (sábado y domingo).", "12 horas seguidas el fin de semana."], ans: 1, exp: "La ley marca un mínimo de 1,5 días de descanso semanal sin interrupción (por ejemplo, el domingo completo y la tarde del sábado o mañana del lunes)." },
    { u: "IPLE T5", q: "¿Qué se considera 'trabajo nocturno'?", opts: ["El realizado entre las 8 de la tarde y las 8 de la mañana.", "El realizado entre las 10 de la noche y las 6 de la mañana.", "Solo el que se hace los domingos por la noche.", "Cualquier turno que acabe pasada la medianoche."], ans: 1, exp: "Legalmente, el horario nocturno abarca la franja que va desde las 22:00h hasta las 06:00h del día siguiente." },
    { u: "IPLE T5", q: "Las horas extraordinarias son aquellas que:", opts: ["Se hacen durante la noche obligatoriamente.", "Exceden de la duración máxima de la jornada ordinaria de trabajo.", "Son de gran dificultad técnica o peligrosidad.", "Se hacen los fines de semana siempre."], ans: 1, exp: "Cualquier hora de trabajo efectivo que pase del tope de la jornada acordada (ej. si trabajas la hora 41 en una semana de 40h) es hora extra." },
    { u: "IPLE T5", q: "¿Cuál es el número máximo de horas extraordinarias 'comunes' que un trabajador puede hacer al año?", opts: ["40 horas.", "80 horas.", "100 horas.", "120 horas."], ans: 1, exp: "El Estatuto limita estrictamente las horas extra voluntarias a 80 horas al año para evitar abusos y fomentar nuevas contrataciones." },
    { u: "IPLE T5", q: "¿Tienen los menores de 18 años permitido realizar horas extraordinarias?", opts: ["Sí, cobrando el doble de una hora normal.", "No, está prohibido.", "Solo si los padres lo autorizan por escrito.", "Solo en verano y fines de semana."], ans: 1, exp: "La ley protege a los menores prohibiéndoles taxativamente hacer horas extras o trabajar en horario nocturno." },
    { u: "IPLE T5", q: "¿Cuántos días de vacaciones anuales retribuidas corresponden legalmente como mínimo?", opts: ["15 días naturales.", "30 días naturales (o 22 laborables).", "45 días naturales.", "20 días hábiles en todos los casos."], ans: 1, exp: "Todo trabajador tiene derecho a 30 días naturales de vacaciones pagadas al año (que equivalen a unos 22 días laborables si no se cuentan fines de semana)." },
    { u: "IPLE T5", q: "¿Se pueden compensar las vacaciones con dinero (pagarlas y no disfrutarlas)?", opts: ["Sí, si el trabajador está de acuerdo y firma un pacto.", "No, excepto si el contrato termina antes de poder disfrutarlas.", "Solo en empresas de menos de 10 trabajadores.", "Sí, siempre que se paguen al doble de su valor."], ans: 1, exp: "El derecho al descanso vacacional es irrenunciable. Solo te las pueden pagar en el finiquito si te despiden o te vas antes de haber tenido tiempo de cogerlas." },
    { u: "IPLE T5", q: "La 'movilidad funcional' dentro del mismo grupo profesional es potestad del:", opts: ["Juez de lo social.", "Empresario (poder de dirección).", "Sindicato representativo.", "Trabajador exclusivamente."], ans: 1, exp: "El jefe te puede cambiar de funciones y mandarte a otro puesto siempre que se respete tu titulación y sigas dentro de tu grupo profesional." },
    { u: "IPLE T5", q: "El 'traslado' (movilidad geográfica) implica un cambio de residencia y puede ser:", opts: ["Solo voluntario a petición del empleado.", "Individual o colectivo.", "Siempre temporal con retorno asegurado.", "Una medida únicamente aplicable a altos directivos."], ans: 1, exp: "El traslado es un cambio de domicilio definitivo que el empresario puede ordenar de forma individual o masiva (afectando a gran parte de la plantilla)." },
    { u: "IPLE T5", q: "Ante una modificación sustancial de las condiciones de trabajo que perjudique al trabajador, este puede:", opts: ["Rescindir el contrato con derecho a indemnización de 20 días por año.", "Quedarse en casa y seguir cobrando indefinidamente.", "Multar a la empresa a través del sindicato.", "Trabajar solo las horas que él considere justas."], ans: 0, exp: "Si el jefe te cambia el horario o los turnos drásticamente y eso te perjudica, puedes extinguir el contrato de forma voluntaria cobrando una indemnización como si fuera un despido objetivo." },
    { u: "IPLE T5", q: "La 'suspensión del contrato' significa que:", opts: ["El contrato se rompe para siempre y no hay marcha atrás.", "Se interrumpe temporalmente la prestación de trabajo y el pago del salario, pero el vínculo sigue existiendo.", "El trabajador pasa a ser funcionario del Estado.", "Se reducen las horas de trabajo a la mitad permanentemente."], ans: 1, exp: "Durante la suspensión (ej. una baja médica o un permiso por maternidad) el contrato queda 'en pausa': no trabajas ni el jefe te paga sueldo directo, pero tu puesto sigue ahí." },
    { u: "IPLE T5", q: "¿Cuál es una causa de suspensión del contrato con reserva de puesto?", opts: ["Nacimiento y cuidado de menor.", "Despido disciplinario procedente.", "Jubilación total del trabajador.", "Dimisión voluntaria."], ans: 0, exp: "La maternidad y paternidad (nacimiento) suspenden el contrato por 16 semanas, garantizando que recuperarás tu puesto exacto al volver." },
    { u: "IPLE T5", q: "El ERTE (Expediente de Regulación Temporal de Empleo) es una causa de:", opts: ["Extinción definitiva del contrato.", "Suspensión del contrato o reducción de jornada.", "Aumento de sueldo y promoción interna.", "Traslado forzoso a otra ciudad."], ans: 1, exp: "Un ERTE no te despide; congela tu contrato temporalmente (o te reduce las horas) porque la empresa pasa por un bache, con la intención de recuperarte después." },
    { u: "IPLE T5", q: "¿Qué es la 'extinción' del contrato de trabajo?", opts: ["El inicio del periodo de prueba en la empresa.", "La terminación definitiva de la relación laboral.", "El cambio de horario nocturno forzoso.", "La firma del finiquito para coger vacaciones."], ans: 1, exp: "La extinción es la muerte del contrato: el vínculo laboral desaparece para siempre." },
    { u: "IPLE T5", q: "Si un trabajador decide irse de la empresa por su propia voluntad (dimisión):", opts: ["Tiene derecho a una gran indemnización económica.", "Debe dar el preaviso que marque el convenio y no tiene derecho a indemnización ni desempleo inmediato.", "Puede cobrar el paro al día siguiente sin problemas.", "El empresario le puede denunciar para obligarle a quedarse."], ans: 1, exp: "La 'baja voluntaria' rompe el contrato gratis. Te vas sin indemnización y el SEPE considera que no estás en situación legal de desempleo (no cobras el paro)." },
    { u: "IPLE T5", q: "El 'despido disciplinario' se basa en:", opts: ["La falta de beneficios y quiebra inminente de la empresa.", "Un incumplimiento grave y culpable del trabajador.", "Que el trabajador se pone enfermo a menudo.", "Que el contrato temporal ha llegado a su fin."], ans: 1, exp: "Es la máxima sanción: el jefe te echa porque has cometido una falta imperdonable (robo, agresiones, desobediencia grave)." },
    { u: "IPLE T5", q: "¿Cuál de estas es una causa de despido disciplinario?", opts: ["Ineptitud del trabajador conocida después de la colocación.", "Faltas repetidas e injustificadas de asistencia o puntualidad.", "Necesidad de amortizar puestos de trabajo por crisis.", "Disminución de ventas en el sector."], ans: 1, exp: "No presentarse a trabajar sin justificación en repetidas ocasiones es un claro incumplimiento de tus obligaciones y motiva el despido disciplinario." },
    { u: "IPLE T5", q: "El 'despido objetivo' puede darse por causas:", opts: ["Económicas, técnicas, organizativas o de producción (ETOP).", "Por insultar violentamente al empresario.", "Por llegar tarde un solo día en todo el año.", "Por robo de material informático de la oficina."], ans: 0, exp: "El despido objetivo se da cuando la empresa tiene pérdidas, pierde un cliente clave, o robotiza el puesto. No es culpa tuya, es necesidad de la empresa." },
    { u: "IPLE T5", q: "¿Qué indemnización corresponde a un despido objetivo legal (procedente)?", opts: ["Ninguna indemnización.", "20 días de salario por año trabajado, con un máximo de 12 mensualidades.", "33 días por año trabajado.", "45 días por año trabajado, con máximo de 42 mensualidades."], ans: 1, exp: "La ley ampara al empresario que tiene causas ETOP permitiéndole despedir con una indemnización menor: 20 días por año." },
    { u: "IPLE T5", q: "Un 'despido colectivo' afecta a un número significativo de trabajadores y requiere:", opts: ["Solo una llamada telefónica del jefe a la plantilla.", "Un periodo de consultas con los representantes de los trabajadores.", "Que el rey firme un decreto ley especial.", "La aprobación unánime de todos los accionistas."], ans: 1, exp: "El despido colectivo (ERE) tiene un protocolo muy garantista: hay que negociar durante 30 días (periodo de consultas) para intentar evitar o reducir el número de despidos." },
    { u: "IPLE T5", q: "El 'finiquito' es el documento donde:", opts: ["Se explica el nuevo horario del trabajador eventual.", "Se saldan las cuentas pendientes (salarios, parte de pagas extras, vacaciones no disfrutadas) al terminar la relación.", "Se pide permiso oficial para irse de vacaciones de verano.", "Se firma la alta en la Seguridad Social."], ans: 1, exp: "El Documento de Saldo y Finiquito liquida económicamente el contrato. Te pagan lo que te deben hasta el último minuto trabajado." },
    { u: "IPLE T5", q: "Si el juez declara un despido como 'IMPROCEDENTE', el empresario debe optar entre:", opts: ["Readmisión o indemnización de 33 días por año trabajado (máximo 24 mensualidades).", "Cárcel para el empresario o multa a la empresa.", "No hacer nada y esperar a que el trabajador renuncie.", "Contratar al trabajador en un puesto de menor categoría."], ans: 0, exp: "Al ser improcedente (injusto legalmente), el juez obliga al jefe a readmitirte pagando los sueldos perdidos, o bien a abonarte la indemnización de 33 días." },
    { u: "IPLE T5", q: "¿Cuándo se considera un despido como 'NULO'?", opts: ["Cuando el empresario se olvida de firmar la carta de despido.", "Cuando tiene como móvil alguna de las causas de discriminación prohibidas o viola derechos fundamentales.", "Cuando la empresa tiene mucho dinero y no necesita despedir.", "Cuando se despide a alguien que lleva menos de un mes."], ans: 1, exp: "Despedir a una mujer embarazada por el hecho de estarlo o a alguien por su raza o religión viola la Constitución y provoca la nulidad del despido." },
    { u: "IPLE T5", q: "El efecto de un despido NULO es:", opts: ["Una indemnización extra de 45 días por daños morales.", "La readmisión inmediata del trabajador con abono de los salarios de tramitación.", "Que el trabajador puede elegir irse a otra empresa conservando su antigüedad.", "La suspensión temporal de la empresa de sus actividades comerciales."], ans: 1, exp: "Al ser nulo, es como si nunca hubiera existido. Vuelves a tu puesto al día siguiente y te pagan todo el sueldo que te dejaron de pagar desde el día del despido." },
    { u: "IPLE T5", q: "¿Qué son los 'salarios de tramitación'?", opts: ["Los que se pagan por realizar trámites burocráticos en una oficina.", "Los salarios dejados de percibir desde el despido hasta la sentencia (en caso de nulidad o improcedencia con readmisión).", "El sueldo que cobran los abogados y procuradores.", "El dinero que la empresa descuenta por tramitar el finiquito."], ans: 1, exp: "Es el dinero que has perdido injustamente durante los meses que duró el juicio hasta que te devolvieron el puesto de trabajo." },
    { u: "IPLE T5", q: "El contrato a 'tiempo parcial' es aquel en el que se prestan servicios durante:", opts: ["Solo 2 horas al día en horario continuado.", "Un número de horas al día, semana, mes o año inferior a la jornada de un trabajador a tiempo completo comparable.", "Siempre en horario nocturno y de fin de semana.", "Un tiempo determinado sin superar las 10 horas semanales."], ans: 1, exp: "Si el convenio marca 40 horas como jornada completa, un contrato de 39 horas ya es técnicamente un contrato a tiempo parcial." },
    { u: "IPLE T5", q: "En el contrato a tiempo parcial, las horas que exceden de la jornada pactada pero no son extras se llaman:", opts: ["Horas mágicas.", "Horas complementarias.", "Horas de regalo.", "Horas de sustitución."], ans: 1, exp: "Como no pueden hacer horas extras, se pacta una bolsa de 'horas complementarias' (hasta un 30% más) para alargar la jornada si hay picos de trabajo." },
    { u: "IPLE T5", q: "¿A quién corresponde la carga de la prueba de la veracidad de un contrato?", opts: ["Siempre al trabajador para demostrar su inocencia.", "Al empresario en la mayoría de los casos de formalidad.", "Al ayuntamiento de la localidad donde opera la empresa.", "A la Seguridad Social obligatoriamente."], ans: 1, exp: "Si hay dudas de si un contrato temporal es legal, es la empresa (empresario) quien tiene que demostrar en el juicio que la causa de temporalidad existía y era real." },
    { u: "IPLE T5", q: "La jubilación del empresario puede ser causa de extinción del contrato con derecho a:", opts: ["1 año de sueldo como bono de fidelidad.", "1 mes de salario para el trabajador.", "Nada de indemnización.", "33 días por año trabajado."], ans: 1, exp: "Si el dueño cierra el negocio porque se jubila y nadie hereda la empresa, el contrato se extingue pagando solo 1 mensualidad de indemnización a los empleados." },
    { u: "IPLE T5", q: "¿Qué plazo tiene un trabajador para impugnar un despido ante el juzgado?", opts: ["20 días hábiles.", "1 año natural.", "3 meses ininterrumpidos.", "No hay plazo, puede demandar cuando quiera."], ans: 0, exp: "El plazo es de caducidad y es cortísimo: 20 días laborables (no cuentan fines de semana ni festivos) desde que se hace efectivo el despido." },
    { u: "IPLE T5", q: "En el despido por 'fuerza mayor', la causa debe ser:", opts: ["Que el jefe no tiene ganas de trabajar más en el sector.", "Un hecho involuntario, imprevisible o inevitable (incendio, inundación) que impide el trabajo.", "Que ha bajado el precio de las acciones en bolsa.", "Una avería leve de una máquina."], ans: 1, exp: "Requiere un suceso de la naturaleza o ajeno al empresario que destruye la posibilidad física de seguir trabajando (ej. se quema la fábrica entera)." },
    { u: "IPLE T5", q: "El 'despido disciplinario' declarado PROCEDENTE da derecho a:", opts: ["33 días de indemnización por daños.", "0 euros de indemnización.", "Cobrar el doble de finiquito.", "Mantener el alta en la Seguridad Social durante tres meses."], ans: 1, exp: "Si el juez dice que el despido es procedente, confirma que cometiste una falta grave y el jefe tiene razón. Te vas a la calle sin indemnización alguna." },
    { u: "IPLE T5", q: "Un contrato celebrado en 'fraude de ley' se considera legalmente como:", opts: ["Nulo de pleno derecho con extinción inmediata.", "Indefinido y a jornada completa.", "Un contrato de voluntariado de prácticas.", "Válido si lleva firmado más de 6 meses."], ans: 1, exp: "La trampa de hacer un contrato temporal cuando no tocaba se penaliza transformando el contrato automáticamente en indefinido." },
// --- PREGUNTAS DE LA PLATAFORMA (MOODLE) ---
    { u: "IPLE T6", q: "Durante el período de prueba:", opts: ["El empresario puede despedir sin justificación ni indemnización, pero el trabajador, en caso de querer abandonar la empresa, sí debe dar preaviso", "El empresario no puede despedir sin justificación", "El empresario puede despedir sin justificación ni indemnización y el trabajador, en caso de querer abandonar la empresa, no debe dar preaviso", "En la actualidad ya no existe el período de prueba"], ans: 2, exp: "Durante el periodo de prueba existe el libre desistimiento: cualquiera de las dos partes (empresario o trabajador) puede dar por finalizado el contrato sin necesidad de justificar causa, sin preaviso y sin derecho a indemnización." },
    { u: "IPLE T6", q: "La jornada laboral:", opts: ["Establece el número de horas diarias a realizar por el trabajador", "Establece el número de horas semanales a realizar por el trabajador", "Establece el número de horas anuales a realizar por el trabajador", "Todas son correctas"], ans: 3, exp: "La jornada laboral se define legalmente estableciendo límites diarios (ej. 9h máximo), semanales (40h de promedio) y anuales, por lo que todas las afirmaciones son correctas." },
    { u: "IPLE T6", q: "Las vacaciones:", opts: ["No son un derecho constitucional", "Sirven para dar descanso a los trabajadores", "Pueden ser o no retribuidas", "Pueden sustituirse por una compensación económica"], ans: 1, exp: "Las vacaciones anuales tienen como finalidad la recuperación física y mental del trabajador. Son un derecho constitucional, siempre deben ser retribuidas y, como regla general, no pueden compensarse económicamente." },
    { u: "IPLE T6", q: "El trabajo nocturno:", opts: ["Permite la realización de 15 horas extraordinarias semanales", "Se retribuye con una cuantía menor si ocurre por fuerza mayor", "Debe darse al menos durante 3 horas o 1/3 de la jornada de 22:00 a 6:00", "Debe darse al menos durante 5 horas o 3/5 de la jornada de 00:00 a 8:00"], ans: 2, exp: "A efectos legales, se considera trabajador nocturno a aquel que invierte no menos de 3 horas de su jornada diaria de trabajo (o al menos un tercio de su jornada anual) entre las 22:00h y las 06:00h." },
    { u: "IPLE T6", q: "Quitando las excepciones, ¿cuánto tiempo mínimo debe transcurrir entre el final de una jornada y el comienzo de otra?:", opts: ["8 horas", "12 horas", "6 horas", "No existe un tiempo mínimo, depende del cómputo semanal"], ans: 1, exp: "El Estatuto de los Trabajadores establece que entre el final de una jornada y el comienzo de la siguiente mediarán, como mínimo, 12 horas ininterrumpidas." },
    { u: "IPLE T6", q: "¿Cuál de los siguientes días debe respetarse por fiesta nacional?:", opts: ["1 de enero", "1 de mayo", "12 de octubre", "Todos los anteriores"], ans: 3, exp: "El 1 de enero (Año Nuevo), el 1 de mayo (Fiesta del Trabajo) y el 12 de octubre (Fiesta Nacional de España) son festividades nacionales inamovibles." },
    { u: "IPLE T6", q: "El periodo de prueba en un contrato:", opts: ["Puede llegar a tener una duración de 6 meses para los técnicos titulados y 2 meses para el resto", "Puede llegar a tener una duración de 12 meses para los técnicos titulados y 8 meses para el resto", "Su establecimiento es obligatorio y debe aparecer por escrito en el contrato", "En la actualidad ya no existe el periodo de prueba"], ans: 0, exp: "Si el convenio colectivo no dice otra cosa, los límites del Estatuto son: máximo 6 meses para técnicos titulados y 2 meses para los demás trabajadores." },
    { u: "IPLE T6", q: "La flexibilidad laboral:", opts: ["Es equivalente al teletrabajo", "No tiene límites para el trabajador, que actúa con absoluta libertad", "Implica autogestión y propia organización del tiempo", "No suele adaptarse a las circunstancias cambiantes del trabajador"], ans: 2, exp: "La flexibilidad no es hacer lo que uno quiera sin normas, sino la capacidad de autogestionar el tiempo y adaptar el trabajo para mejorar la conciliación." },
    { u: "IPLE T6", q: "¿Cuáles son los derechos laborales en el entorno digital?:", opts: ["Acceso universal a Internet y libertad de contenidos", "Salud mental y diversidad digital", "Desconexión digital y privacidad y protección de los datos personales", "Teletrabajo y no invasión del ámbito privado"], ans: 2, exp: "Las últimas leyes reconocen específicamente el derecho a la desconexión digital fuera del horario de trabajo y la protección de la intimidad ante el uso de videovigilancia o geolocalización." },
    { u: "IPLE T6", q: "¿Cuáles es la más alta instancia dentro de los tribunales y juzgados de lo social?:", opts: ["Tribunales Superiores de Justicia", "Tribunal Supremo", "Ministerio de Trabajo", "Audiencia Nacional"], ans: 1, exp: "El Tribunal Supremo, con sede en Madrid, es el órgano jurisdiccional superior en todos los órdenes (incluido el social/laboral), cerrando el sistema judicial español." },

    // --- BLOQUE CUESTIONARIO DE AUTOEVALUACIÓN (60 PREGUNTAS) ---
    { u: "IPLE T6", q: "¿Qué se considera 'tiempo de trabajo efectivo'?", opts: ["El tiempo que el trabajador permanece en su domicilio a disposición de la empresa.", "El tiempo que el trabajador se encuentra en su puesto y realizando sus funciones.", "El tiempo de desplazamiento desde el hogar hasta el centro de trabajo.", "El tiempo de descanso para el almuerzo fuera del centro."], ans: 1, exp: "El tiempo efectivo de trabajo cuenta desde que el empleado está físicamente en su puesto asumiendo sus labores hasta que termina." },
    { u: "IPLE T6", q: "La duración máxima de la jornada ordinaria de 40 horas semanales se computa como:", opts: ["Un límite infranqueable cada semana.", "Un promedio en cómputo anual.", "Un límite que no incluye las vacaciones.", "Una obligación diaria de 8 horas exactas."], ans: 1, exp: "Las 40 horas son un promedio. Habrá semanas donde trabajes 45h y otras 35h, siempre que al finalizar el año la media no supere las 40h semanales." },
    { u: "IPLE T6", q: "Si el convenio no dice lo contrario, el número máximo de horas ordinarias diarias es de:", opts: ["8 horas.", "9 horas.", "10 horas.", "12 horas."], ans: 1, exp: "El Estatuto fija en 9 horas diarias el máximo de trabajo ordinario, aunque mediante convenio colectivo puede flexibilizarse." },
    { u: "IPLE T6", q: "¿Qué descanso mínimo debe respetarse entre jornadas para trabajadores de hostelería o actividades especiales (siempre que se compense)?", opts: ["8 horas.", "10 horas.", "12 horas.", "No hay límite si hay acuerdo."], ans: 1, exp: "El límite general es de 12 horas, pero los sectores con jornadas especiales (ej. hostelería, transporte) pueden reducirlo a 10 horas si compensan las 2 restantes en otros descansos." },
    { u: "IPLE T6", q: "¿Qué documento es obligatorio para que el empresario pueda demostrar la jornada realizada por cada trabajador?", opts: ["El contrato de trabajo.", "El registro diario de jornada (fichaje).", "La nómina mensual.", "El calendario laboral colgado en la pared."], ans: 1, exp: "Desde 2019 es obligatorio por ley que la empresa lleve un registro diario que incluya el inicio y finalización exacta de la jornada del trabajador." },
    { u: "IPLE T6", q: "¿Durante cuánto tiempo debe conservar la empresa los registros de jornada?", opts: ["1 año.", "2 años.", "4 años.", "5 años."], ans: 2, exp: "Los registros de los fichajes diarios deben ser conservados a disposición de los trabajadores y de la Inspección de Trabajo durante 4 años." },
    { u: "IPLE T6", q: "Las horas extraordinarias por 'fuerza mayor' son aquellas destinadas a:", opts: ["Terminar un pedido urgente de un cliente.", "Prevenir o reparar siniestros y daños extraordinarios y urgentes.", "Sustituir a un compañero que se ha ido de vacaciones.", "Cubrir picos de producción previstos."], ans: 1, exp: "Se realizan para evitar catástrofes (ej. se inunda la fábrica). Son obligatorias y no computan para el límite de las 80 horas extras anuales." },
    { u: "IPLE T6", q: "¿Cuál es el límite máximo de horas extraordinarias para un trabajador con contrato a tiempo parcial?", opts: ["80 horas al año.", "El mismo que un trabajador a tiempo completo.", "Proporcional a la jornada pactada.", "No pueden realizar horas extraordinarias (solo complementarias)."], ans: 3, exp: "La ley prohíbe tajantemente las horas extraordinarias en contratos a tiempo parcial (salvo causa de fuerza mayor). Solo pueden hacer 'horas complementarias'." },
    { u: "IPLE T6", q: "La compensación de horas extras con descanso debe realizarse, preferentemente, dentro de los:", opts: ["2 meses siguientes.", "4 meses siguientes.", "6 meses siguientes.", "Al final del año natural."], ans: 1, exp: "Si el convenio no dice lo contrario, las horas extra se deben compensar por tiempo de descanso retribuido dentro de los cuatro meses siguientes a su realización." },
    { u: "IPLE T6", q: "¿Es obligatorio pagar el 'tiempo de bocadillo' (descanso en jornada continuada)?", opts: ["Sí, siempre por ley.", "Solo si así se establece por convenio colectivo o contrato.", "No, nunca se paga.", "Solo si el trabajador tiene hijos."], ans: 1, exp: "El Estatuto no obliga a pagarlo; esos 15 minutos solo se consideran tiempo de trabajo efectivo (y por tanto se pagan) si el convenio o el contrato así lo indican." },
    { u: "IPLE T6", q: "Para menores de 18 años, el descanso semanal debe ser de al menos:", opts: ["1 día y medio.", "2 días ininterrumpidos.", "36 horas.", "48 horas en promedio quincenal."], ans: 1, exp: "A diferencia de los adultos (que tienen 1,5 días de descanso), los menores están más protegidos y deben descansar obligatoriamente 2 días ininterrumpidos a la semana." },
    { u: "IPLE T6", q: "¿Qué ocurre si un trabajador no disfruta sus 30 días de vacaciones antes del 31 de diciembre?", opts: ["Se le pagan obligatoriamente en la nómina de enero.", "Las pierde, salvo que la empresa o causas ajenas (baja) lo impidan.", "Se acumulan para el año siguiente automáticamente.", "Puede disfrutarlas cuando quiera en los próximos 3 años."], ans: 1, exp: "Como norma general, las vacaciones caducan a final de año. Si no las has cogido por tu cuenta, las pierdes (a menos que estuvieras de baja médica)." },
    { u: "IPLE T6", q: "Si un trabajador es despedido y no ha disfrutado sus vacaciones, la empresa debe:", opts: ["Dejarle disfrutar los días antes de que se vaya.", "Compensarlas económicamente en el finiquito.", "No hacer nada, el derecho se pierde.", "Darle un certificado para disfrutarlas en la próxima empresa."], ans: 1, exp: "Es la única excepción legal donde se permite pagar las vacaciones con dinero. Los días no disfrutados se liquidan y abonan en el finiquito final." },
    { u: "IPLE T6", q: "El calendario de vacaciones debe estar fijado con una antelación mínima de:", opts: ["15 días.", "30 días.", "2 meses.", "3 meses."], ans: 2, exp: "El trabajador tiene derecho a conocer las fechas exactas de sus vacaciones con, al menos, dos meses de antelación para poder planificar su vida personal." },
    { u: "IPLE T6", q: "¿Quién elige las fechas de las vacaciones en caso de desacuerdo?", opts: ["El empresario siempre.", "El trabajador siempre.", "El Juzgado de lo Social a través de un procedimiento sumario.", "El sindicato mayoritario."], ans: 2, exp: "Si el empresario y el trabajador no logran un acuerdo sobre las fechas, será un juez de lo Social quien decida de forma rápida, y su sentencia será irrecurrible." },
    { u: "IPLE T6", q: "¿Qué parentesco se considera de 'segundo grado' a efectos de permisos?", opts: ["Padres e hijos.", "Cónyuge.", "Abuelos, nietos y hermanos.", "Primos y tíos."], ans: 2, exp: "El primer grado son padres e hijos. El segundo grado abarca abuelos, nietos, hermanos y cuñados. Los permisos de la ley llegan hasta este segundo grado." },
    { u: "IPLE T6", q: "Por fallecimiento de un hermano, ¿cuántos días de permiso corresponden?", opts: ["2 días.", "3 días.", "4 días.", "5 días."], ans: 0, exp: "La ley concede 2 días de permiso por fallecimiento, accidente o enfermedad grave de parientes hasta el segundo grado (si necesitas desplazamiento, pueden ser 4 días)." },
    { u: "IPLE T6", q: "El permiso por lactancia de un hijo menor de 9 meses puede disfrutarse como:", opts: ["1 hora de ausencia diaria.", "Reducción de la jornada en media hora.", "Acumularlo en jornadas completas si lo permite el convenio.", "Todas las anteriores son correctas."], ans: 3, exp: "El trabajador elige cómo disfrutarlo: puede ausentarse 1 hora, entrar 30 min más tarde y salir 30 min antes, o agrupar esas horas en días libres si el convenio lo prevé." },
    { u: "IPLE T6", q: "La reducción de jornada por guarda legal implica una reducción salarial:", opts: ["Del 10% fijo.", "Proporcional a la reducción de tiempo de trabajo.", "No hay reducción salarial, se cobra lo mismo.", "Solo se reduce el salario base, no los complementos."], ans: 1, exp: "Si solicitas una reducción de jornada (entre un octavo y la mitad) para cuidar a un menor de 12 años, tu sueldo se reducirá exactamente en la misma proporción." },
    { u: "IPLE T6", q: "Un trabajador que solicita una adaptación de jornada por conciliación (Art. 34.8 ET) tiene derecho a:", opts: ["Que la empresa se la conceda sí o sí.", "Un proceso de negociación de máximo 15 días con la empresa.", "Irse a casa y trabajar cuando pueda.", "Que le paguen el internet del teletrabajo siempre."], ans: 1, exp: "Se conoce como la 'jornada a la carta'. No es un derecho automático; la empresa está obligada a abrir una negociación de 15 días y, si deniega la petición, debe justificar motivos objetivos." },
    { u: "IPLE T6", q: "¿Puede establecerse un periodo de prueba de palabra?", opts: ["Sí, si hay testigos.", "No, debe concertarse siempre por escrito.", "Solo en empresas familiares.", "Sí, si el contrato es indefinido."], ans: 1, exp: "El periodo de prueba no se presume jamás. Para que sea válido y legal, debe figurar expresamente por escrito en el contrato de trabajo." },
    { u: "IPLE T6", q: "¿Cuál es el límite del periodo de prueba para un Técnico Superior (no titulado universitario)?", opts: ["15 días.", "1 mes.", "2 meses.", "6 meses."], ans: 2, exp: "Al no ser un 'titulado de grado universitario' (cuyo límite es de 6 meses), se le aplica el tope general de 2 meses." },
    { u: "IPLE T6", q: "¿Es obligatorio dar preaviso para rescindir el contrato en periodo de prueba?", opts: ["Sí, 15 días.", "Sí, 7 días.", "No, ninguna de las partes debe dar preaviso.", "Solo el empresario debe preavisar."], ans: 2, exp: "Esa es la principal característica del periodo de prueba: se puede romper la relación laboral de forma inmediata, sin tener que preavisar." },
    { u: "IPLE T6", q: "El periodo de prueba es nulo si:", opts: ["El trabajador ya había desempeñado las mismas funciones en la empresa anteriormente.", "El salario es el SMI.", "Dura más de una semana.", "El trabajador es mayor de 45 años."], ans: 0, exp: "Si el trabajador ya demostró su aptitud haciendo esas mismas funciones antes en esa empresa, volver a ponerle un periodo de prueba es ilegal y nulo." },
    { u: "IPLE T6", q: "El 'acuerdo de teletrabajo' debe formalizarse:", opts: ["Por escrito y antes de que se inicie.", "De palabra durante el primer mes.", "Solo si el trabajador vive a más de 50 km.", "Únicamente por correo electrónico informal."], ans: 0, exp: "El teletrabajo requiere un acuerdo expreso y formal por escrito entre la empresa y el empleado, firmado antes de empezar a trabajar en remoto." },
    { u: "IPLE T6", q: "El teletrabajo es, por definición:", opts: ["Obligatorio para la empresa si el trabajador lo pide.", "Voluntario tanto para el trabajador como para el empleador.", "Reversible solo por decisión del jefe.", "Exclusivo para el sector público."], ans: 1, exp: "Nadie te puede obligar a teletrabajar, ni tú puedes imponerle el teletrabajo a la empresa. Es un pacto 100% voluntario y reversible para ambos." },
    { u: "IPLE T6", q: "El derecho a la 'desconexión digital' implica que el trabajador:", opts: ["Puede apagar el ordenador durante su jornada.", "No tiene obligación de responder comunicaciones de trabajo fuera de su horario laboral.", "No debe usar el móvil personal en la oficina.", "Puede borrar sus datos de la empresa al irse."], ans: 1, exp: "Garantiza que el empleado no está obligado a contestar emails, WhatsApps o llamadas del jefe una vez que su jornada laboral ha terminado." },
    { u: "IPLE T6", q: "La equidad en el trabajo prohíbe la discriminación por:", opts: ["Sexo, edad y religión.", "Orientación sexual e identidad de género.", "Discapacidad y origen racial.", "Todas las anteriores."], ans: 3, exp: "El artículo 14 de la Constitución y el Estatuto de los Trabajadores prohíben taxativamente cualquier discriminación laboral basada en estos motivos." },
    { u: "IPLE T6", q: "¿Qué se entiende por 'Up-skilling'?", opts: ["Despedir a los trabajadores menos formados.", "Enseñar nuevas habilidades para un puesto totalmente diferente.", "Mejorar las habilidades actuales para ser más eficaz en el mismo puesto.", "Subir de categoría profesional por antigüedad."], ans: 2, exp: "A diferencia del 'Re-skilling' (aprender algo nuevo para cambiar de profesión), el 'Up-skilling' es perfeccionarse y actualizarse dentro de tu propio oficio." },
    { u: "IPLE T6", q: "La 'salud mental' en el trabajo se gestiona principalmente a través de:", opts: ["La evaluación de riesgos psicosociales.", "Dar más vacaciones a los que estén estresados.", "Instalar máquinas de café gratuitas.", "No mandar correos los lunes."], ans: 0, exp: "Las empresas están obligadas a evaluar factores de riesgo psicosocial (como el exceso de carga o el estrés) para proteger la salud mental de la plantilla." },
    { u: "IPLE T6", q: "¿Qué es el 'SMAC'?", opts: ["Sindicato de Maestros y Administrativos de Comercio.", "Servicio de Mediación, Arbitraje y Conciliación.", "Sistema de Medida de Actividades de Control.", "Sociedad de Mantenimiento de Armarios y Cuadros."], ans: 1, exp: "Es el organismo administrativo encargado de intentar que empresa y trabajador lleguen a un acuerdo antes de ir a juicio." },
    { u: "IPLE T6", q: "¿Es obligatorio ir al SMAC antes de poner una demanda por despido?", opts: ["No, se puede ir directo al juzgado.", "Sí, es un requisito de procedibilidad obligatorio (salvo excepciones).", "Solo si el trabajador es afiliado a un sindicato.", "Solo si la empresa tiene más de 100 empleados."], ans: 1, exp: "Intentar la conciliación previa en el SMAC es un paso obligatorio por ley antes de poder presentar la demanda formal en el Juzgado de lo Social." },
    { u: "IPLE T6", q: "En el SMAC, si hay acuerdo entre las partes, el resultado se plasma en un acta de:", opts: ["Desacuerdo.", "Conciliación con avenencia.", "Conciliación sin avenencia.", "Sentencia administrativa."], ans: 1, exp: "Si ambas partes pactan una solución (avenencia), el acta del conciliador cierra el problema y tiene fuerza ejecutiva." },
    { u: "IPLE T6", q: "Si la empresa no cumple lo pactado en el SMAC, el trabajador puede:", opts: ["Poner una denuncia en la policía.", "Solicitar la ejecución directa ante el Juzgado de lo Social.", "Empezar una huelga él solo.", "No puede hacer nada, el acta no obliga a nada."], ans: 1, exp: "El acuerdo firmado en el SMAC tiene la misma fuerza que una sentencia. Si el jefe no paga, pides al juez que embargue las cuentas de la empresa." },
    { u: "IPLE T6", q: "¿Cómo se llama el órgano que juzga despidos en primera instancia?", opts: ["Tribunal Supremo.", "Audiencia Nacional.", "Juzgado de lo Social.", "Tribunal Superior de Justicia."], ans: 2, exp: "Los Juzgados de lo Social son los tribunales de primera línea que resuelven los conflictos individuales laborales (despidos, nóminas, etc.)." },
    { u: "IPLE T6", q: "La Audiencia Nacional tiene competencia en conflictos colectivos cuando:", opts: ["Afectan a una sola provincia.", "El ámbito de afectación es superior al de una Comunidad Autónoma.", "La empresa es de titularidad estatal.", "El conflicto es con el Ministerio de Trabajo."], ans: 1, exp: "Si el problema (ej. la negociación de un ERE) afecta a centros de trabajo de la empresa en Madrid y en Barcelona, el caso lo juzga directamente la Audiencia Nacional." },
    { u: "IPLE T6", q: "El recurso que se interpone contra las sentencias de los Juzgados de lo Social se llama:", opts: ["Recurso de casación.", "Recurso de suplicación.", "Recurso de amparo.", "Recurso de alzada."], ans: 1, exp: "Si pierdes en el Juzgado de lo Social, puedes apelar al Tribunal Superior de Justicia de tu Comunidad a través del Recurso de Suplicación." },
    { u: "IPLE T6", q: "El plazo de 20 días hábiles para impugnar un despido empieza a contar desde:", opts: ["El día que el trabajador decide denunciar.", "El día siguiente a la fecha de efectos del despido.", "El día que recibe la carta, aunque sea domingo.", "El mes siguiente al despido."], ans: 1, exp: "Si te despiden hoy, tu reloj de 20 días hábiles para presentar la papeleta en el SMAC arranca mañana." },
    { u: "IPLE T6", q: "En un juicio laboral, el trabajador puede defenderse:", opts: ["Solo con un abogado.", "Por sí mismo o representado por abogado, graduado social o procurador.", "Solo a través de su representante sindical.", "Debe contratar obligatoriamente a un notario."], ans: 1, exp: "La jurisdicción social es muy flexible; no necesitas pagar a un abogado obligatoriamente para juicios de primera instancia, puedes ir tú mismo." },
    { u: "IPLE T6", q: "¿Quién tiene la 'carga de la prueba' en un juicio por despido disciplinario?", opts: ["El trabajador, para demostrar que es inocente.", "El empresario, para demostrar que los hechos de la carta son ciertos.", "El sindicato.", "El Juez mediante una investigación propia."], ans: 1, exp: "En el derecho laboral español, es el jefe quien debe demostrar con pruebas sólidas que tú robaste o incumpliste (el trabajador se presume inocente)." },
    { u: "IPLE T6", q: "Los festivos que no se disfrutan por caer en domingo:", opts: ["Se pierden.", "Se trasladan obligatoriamente al lunes siguiente o se compensan.", "Se pagan el triple.", "No existen festivos los domingos."], ans: 1, exp: "Las fiestas nacionales o autonómicas que coinciden con un domingo se pasan por ley al lunes siguiente para no perder el día de descanso." },
    { u: "IPLE T6", q: "El permiso de 15 días por matrimonio también se aplica a:", opts: ["Parejas de hecho (tras la última reforma legal).", "Amigos que viven juntos.", "Divorcios.", "Solo a matrimonios religiosos."], ans: 0, exp: "Las últimas actualizaciones del Estatuto han equiparado a las parejas de hecho debidamente registradas, otorgándoles también los 15 días de permiso." },
    { u: "IPLE T6", q: "El descanso de 15 minutos en jornada de más de 6 horas se considera tiempo de trabajo:", opts: ["Siempre.", "Nunca.", "Solo si el convenio lo establece expresamente.", "Si el jefe es amable."], ans: 2, exp: "La famosa 'pausa del bocadillo' no se paga ni cuenta como trabajo efectivo a no ser que tu contrato o convenio diga lo contrario." },
    { u: "IPLE T6", q: "Las horas extraordinarias son voluntarias para el trabajador, salvo que:", opts: ["El jefe se lo pida por favor.", "Estén pactadas en contrato o convenio, o sean por fuerza mayor.", "La empresa tenga pérdidas.", "Sea lunes."], ans: 1, exp: "No te pueden obligar a hacer horas extra a menos que las hayas firmado previamente en tu contrato o haya un riesgo inminente de siniestro (fuerza mayor)." },
    { u: "IPLE T6", q: "¿Qué significa que una jornada sea 'irregular'?", opts: ["Que el trabajador no tiene contrato.", "Que las horas se distribuyen de forma desigual a lo largo del año (unos días más, otros menos).", "Que el horario cambia cada 5 minutos.", "Que se trabaja sin luz."], ans: 1, exp: "La empresa puede, avisando con 5 días, hacerte trabajar 9 horas un día de mucho trabajo y compensártelo trabajando 7 horas otro día de poco volumen." },
    { u: "IPLE T6", q: "El límite de 80 horas extras anuales es para:", opts: ["Horas de fuerza mayor.", "Horas extraordinarias comunes.", "Horas nocturnas.", "Horas de formación."], ans: 1, exp: "El tope anual de 80h se aplica a las horas extras normales y voluntarias. Las horas por fuerza mayor no cuentan para este límite." },
    { u: "IPLE T6", q: "¿Qué es un 'graduado social'?", opts: ["Alguien que ha terminado la ESO.", "Un profesional experto en Derecho del Trabajo y Seguridad Social facultado para representar en juicios laborales.", "Un trabajador social de un hospital.", "Un inspector de hacienda."], ans: 1, exp: "Son juristas especializados exclusivamente en el ámbito laboral y de Seguridad Social, pudiendo actuar en los juicios de lo Social igual que un abogado." },
    { u: "IPLE T6", q: "El derecho a las vacaciones caduca:", opts: ["Al mes del despido.", "Al terminar el año natural (salvo excepciones por baja médica).", "Nunca.", "A los 10 años."], ans: 1, exp: "Las vacaciones nacen y mueren en el año natural (el 31 de diciembre caducan). Solo si estabas de baja por embarazo o enfermedad prolongada se permite guardarlas." },
    { u: "IPLE T6", q: "¿Qué permiso dura 'el tiempo indispensable'?", opts: ["Matrimonio.", "Mudanza.", "Cumplimiento de un deber inexcusable (ej. votar o ir a un juicio).", "Nacimiento de hijo."], ans: 2, exp: "No hay un número de días fijo para esto; tienes derecho a ausentarte exactamente las horas que necesites para ir a testificar al juzgado o votar, y luego debes volver." },
    { u: "IPLE T6", q: "La jornada nocturna está prohibida para:", opts: ["Mayores de 45 años.", "Mujeres embarazadas siempre.", "Menores de 18 años.", "Trabajadores a tiempo parcial."], ans: 2, exp: "El Estatuto de los Trabajadores prohíbe radicalmente emplear a menores de edad en el turno de noche o dejar que hagan horas extra." },
    { u: "IPLE T6", q: "La 'avenencia' en un acto de conciliación significa:", opts: ["Pelea.", "Acuerdo entre las partes.", "Que el juez ha llegado tarde.", "Que no hay pruebas."], ans: 1, exp: "Un acta 'con avenencia' indica que el empresario y el trabajador han logrado llegar a un pacto económico y amistoso en el SMAC, cerrando el pleito." },
    { u: "IPLE T6", q: "Las sentencias de la Audiencia Nacional se recurren ante:", opts: ["El TSJ.", "El Tribunal Supremo.", "El Ministerio de Justicia.", "El Rey."], ans: 1, exp: "Al ser la Audiencia Nacional un órgano central para toda España, sus sentencias solo pueden ser revisadas por el más alto tribunal, el Supremo." },
    { u: "IPLE T6", q: "El permiso por mudanza es de:", opts: ["1 día natural.", "1 día laborable.", "2 días.", "3 días."], ans: 0, exp: "La ley otorga un único día libre retribuido por traslado de domicilio habitual." },
    { u: "IPLE T6", q: "¿Se puede teletrabajar el 100% de la jornada?", opts: ["No, el máximo es el 50%.", "Sí, si así se acuerda por escrito.", "Solo los funcionarios.", "Solo si la empresa no tiene oficina física."], ans: 1, exp: "La Ley de Trabajo a Distancia permite desde teletrabajo parcial hasta el remoto 100%, siempre que haya acuerdo mutuo por escrito." },
    { u: "IPLE T6", q: "El trabajador nocturno no puede realizar:", opts: ["Horas extraordinarias (salvo excepciones de fuerza mayor).", "Descansos.", "Turnos de tarde.", "Ninguna tarea peligrosa."], ans: 0, exp: "Debido a la dureza fisiológica del turno de noche, la ley prohíbe que estos trabajadores alarguen su jornada haciendo horas extraordinarias." },
    { u: "IPLE T6", q: "¿Qué jurisdicción es 'gratuita' para el trabajador en sus instancias básicas?", opts: ["Civil.", "Penal.", "Social.", "Mercantil."], ans: 2, exp: "Los pleitos en los Juzgados de lo Social están exentos de tasas judiciales para los trabajadores y sindicatos, garantizando que no cueste dinero reclamar tus derechos." },
    { u: "IPLE T6", q: "El periodo de prueba interrumpe su cómputo por:", opts: ["Vacaciones.", "Baja por enfermedad (si hay acuerdo).", "Huelga.", "Formación."], ans: 1, exp: "Si caes enfermo durante la prueba, el reloj de los días se pausa y continuará contando cuando vuelvas, pero solo si se pactó así en el contrato." },
    { u: "IPLE T6", q: "En el trabajo a turnos, la rotación es:", opts: ["Obligatoria para todos los empleados siempre.", "Una forma de organizar el trabajo donde los empleados ocupan sucesivamente los mismos puestos.", "Solo para enfermeros.", "Una técnica de gimnasia laboral."], ans: 1, exp: "Implica que varios empleados cubren el mismo puesto a lo largo de las 24h, rotando sus horarios de mañana, tarde y noche." },
    { u: "IPLE T6", q: "¿Cuántos domingos de descanso mínimo al mes establece la ley?", opts: ["Uno.", "Dos.", "Ninguno (el descanso puede ser en cualquier día de la semana).", "Todos."], ans: 2, exp: "La ley dice que el descanso semanal será 'preferentemente' en domingo, pero no es obligatorio. Muchos sectores como comercio u hostelería descansan un martes o miércoles." },
    { u: "IPLE T6", q: "La sentencia judicial debe ser siempre:", opts: ["De palabra.", "Motivada (explicar las razones legales).", "Secreta.", "Solo para el empresario."], ans: 1, exp: "El juez no puede fallar porque sí. La sentencia debe estar fundamentada y argumentar qué leyes aplica para dar la razón a una parte u a otra." },
// --- PREGUNTAS DE LA PLATAFORMA (MOODLE) ---
    { u: "IPLE T7", q: "La capacidad de una persona para comprender sus propias características, es decir, sus intereses, valores, motivaciones, habilidades y destrezas, se denomina:", opts: ["Autoconocimiento", "Inventario de intereses", "Exploración de actividades", "Instinto"], ans: 0, exp: "El autoconocimiento es el pilar básico de la orientación laboral: conocer qué se te da bien, qué te gusta y cuáles son tus valores para enfocar tu carrera." },
    { u: "IPLE T7", q: "El Inventario de Intereses de Holland:", opts: ["También es conocido como «Teoría de los Tipos de Personalidad Vocacional»", "Clasifica a las personas y los ambientes de trabajo en seis tipos", "Es una batería de preguntas que evalúan las preferencias y aversiones del individuo", "Todas son correctas"], ans: 3, exp: "El modelo RIASEC de Holland agrupa las personalidades en 6 tipos (Realista, Investigador, Artístico, Social, Emprendedor y Convencional) mediante cuestionarios específicos." },
    { u: "IPLE T7", q: "Las motivaciones:", opts: ["Son factores internos que impulsan a una persona a actuar y alcanzar sus metas", "Son factores externos que impulsan a una persona a actuar y alcanzar sus metas", "Son factores internos y externos que impulsan a una persona a actuar y alcanzar sus metas", "Permiten descubrir nuevas áreas de interés y enriquecerse"], ans: 2, exp: "La motivación tiene una vertiente intrínseca (lo que nos nace de dentro, como la vocación) y una extrínseca (el salario, el reconocimiento social)." },
    { u: "IPLE T7", q: "Se pueden conocer las habilidades a través de:", opts: ["Inventarios de habilidades", "Autoevaluación de competencias", "Evaluaciones de desempeño", "Todas son correctas"], ans: 3, exp: "Existen múltiples herramientas de recursos humanos y psicología para medir y evaluar de forma objetiva las habilidades de un candidato o trabajador." },
    { u: "IPLE T7", q: "Los atributos innatos o desarrollados que forman parte de la personalidad de un individuo se denominan:", opts: ["Competencias personales", "Cualidades personales", "Competencias sociales", "Preferencias profesionales"], ans: 1, exp: "Las cualidades (como ser paciente, meticuloso o extrovertido) son rasgos de la personalidad y el carácter." },
    { u: "IPLE T7", q: "Las habilidades adquiridas que pueden desarrollarse y mejorarse con el tiempo, imprescindibles para desempeñar cada puesto de trabajo, se denominan:", opts: ["Competencias personales", "Cualidades personales", "Competencias sociales", "Preferencias profesionales"], ans: 0, exp: "Las competencias (como saber usar Excel, liderar equipos o hablar inglés) se aprenden y se entrenan con la práctica." },
    { u: "IPLE T7", q: "Existen tres tipos de objetivos profesionales:", opts: ["Personales, empresariales y grupales", "Logísticos, específicos y estratégicos", "A corto, a medio y a largo plazo", "Específicos, de proyecto de carrera y evaluativos"], ans: 2, exp: "En la planificación de la carrera profesional, las metas se dividen temporalmente en corto, medio y largo plazo." },
    { u: "IPLE T7", q: "Una de las vías de acceso a los Ciclos Formativos de Grado Superior es:", opts: ["Disponer del título de Técnico, al haber superado los estudios de Grado Medio", "Poseer un título de Bachillerato", "Tener aprobada la prueba de acceso a los CFGS", "Todas son correctas"], ans: 3, exp: "El sistema educativo español permite acceder a la FP de Grado Superior desde Bachillerato, promocionando desde un Grado Medio o superando una prueba oficial." },
    { u: "IPLE T7", q: "Tras la Declaración de Bolonia de 1999, los estudios universitarios quedaron divididos en dos niveles:", opts: ["Estudios de grado y estudios de posgrado", "Grados Medios y Grados Superiores", "Máster y Doctorado", "Estudios europeos y estudios internacionales"], ans: 0, exp: "El Plan Bolonia unificó el Espacio Europeo de Educación Superior estructurándolo en Grado (4 años por norma general) y Posgrado (Máster y Doctorado)." },
    { u: "IPLE T7", q: "La autoestima:", opts: ["No tiene relevancia en el contexto de la búsqueda de empleo", "Es el factor que determina las habilidades técnicas específicas", "Es la percepción subjetiva y la valoración emocional que una persona tiene de sí misma", "Puede ser educativa, personal o laboral"], ans: 2, exp: "La autoestima es cómo nos valoramos a nosotros mismos, siendo un factor clave (psicológico) para afrontar con éxito entrevistas de trabajo y nuevos retos." },

    // --- BLOQUE CUESTIONARIO DE AUTOEVALUACIÓN: SEGURIDAD SOCIAL (70 PREGUNTAS) ---
    { u: "IPLE T7", q: "¿Cómo se define el salario según el Estatuto de los Trabajadores?", opts: ["Solo el dinero que se recibe en la cuenta bancaria.", "El conjunto de percepciones económicas, en dinero o en especie, recibidas como contraprestación por los servicios laborales.", "Únicamente la parte fija que figura en el contrato.", "Los pagos que hace la empresa para compensar gastos de transporte."], ans: 1, exp: "El salario abarca absolutamente todo lo que el trabajador recibe por trabajar, ya sea en dinero (transferencia) o en especie (coche de empresa, vales de comida)." },
    { u: "IPLE T7", q: "¿Cuál es el periodo máximo legal para el pago de las retribuciones periódicas?", opts: ["Una semana.", "Quince días.", "Un mes.", "Tres meses."], ans: 2, exp: "El Estatuto de los Trabajadores prohíbe que el pago del salario se demore más de un mes (habitualmente se cobra a final o principio de mes)." },
    { u: "IPLE T7", q: "¿Qué parte del salario es inembargable, excepto para el pago de pensiones alimenticias?", opts: ["El salario bruto total.", "El Salario Mínimo Interprofesional (SMI).", "El 50% de la nómina.", "Solo los complementos salariales."], ans: 1, exp: "Para garantizar la supervivencia del deudor, la ley impide embargar el sueldo por debajo del SMI vigente; solo los tramos que superen ese SMI se embargan por porcentajes." },
    { u: "IPLE T7", q: "¿Qué es el Salario Mínimo Interprofesional (SMI)?", opts: ["El salario que decide el empresario según la valía del trabajador.", "La cuantía mínima que debe percibir un trabajador a tiempo completo sin distinción de profesión.", "Un índice para calcular las becas de estudio.", "El sueldo medio de los funcionarios."], ans: 1, exp: "El Gobierno fija anualmente este tope legal por debajo del cual es ilegal pagar a un trabajador a jornada completa." },
    { u: "IPLE T7", q: "¿Qué organismo protege la percepción de salarios e indemnizaciones pendientes de pago por insolvencia de la empresa?", opts: ["El Banco de España.", "El FOGASA (Fondo de Garantía Salarial).", "La Inspección de Trabajo.", "El SMAC."], ans: 1, exp: "Si tu empresa quiebra y no te puede pagar la nómina o el finiquito, el FOGASA asume esa deuda (con ciertos límites legales) para que no te quedes sin nada." },
    { u: "IPLE T7", q: "El IPREM (Indicador Público de Renta de Efectos Múltiples) se utiliza principalmente para:", opts: ["Calcular el salario base.", "Servir de referencia para la concesión de ayudas, subvenciones o el subsidio de desempleo.", "Determinar el coste de los despidos.", "Sustituir al SMI en los contratos de alta dirección."], ans: 1, exp: "Es un índice creado en 2004 para que las becas, ayudas sociales y topes del paro no dependieran del SMI (que sube más rápido)." },
    { u: "IPLE T7", q: "¿Cómo se denomina el valor total antes de aplicar deducciones en la nómina?", opts: ["Salario neto.", "Salario líquido.", "Total devengado (o salario bruto).", "Base de cotización."], ans: 2, exp: "El devengo es la suma total de todo lo que has generado en el mes (salario base + extras) antes de que Hacienda y la Seguridad Social te retengan su parte." },
    { u: "IPLE T7", q: "Las 'percepciones salariales' se caracterizan por:", opts: ["Compensar gastos de herramientas.", "Retribuir directamente el trabajo efectivo o los periodos de descanso computables.", "Estar exentas de cotización siempre.", "Ser únicamente pagos en especie."], ans: 1, exp: "Pagan el trabajo en sí (salario base, plus de nocturnidad, horas extras) a diferencia de las extra-salariales que solo compensan gastos." },
    { u: "IPLE T7", q: "¿Cuál de estos es un ejemplo de percepción NO salarial?", opts: ["El salario base.", "Las gratificaciones extraordinarias (pagas extras).", "El plus de transporte o dietas.", "El plus de nocturnidad."], ans: 2, exp: "El plus de transporte te compensa por el gasto de autobús/gasolina para ir al trabajo, no retribuye tu labor directa, por lo que es extra-salarial." },
    { u: "IPLE T7", q: "El salario líquido a percibir es el resultado de:", opts: ["Total devengado + Deducciones.", "Salario base - IRPF.", "Total devengado - Total a deducir.", "Base de cotización - Seguridad Social."], ans: 2, exp: "Es el dinero 'neto' real que te ingresan en tu cuenta del banco tras restar todas las retenciones y cuotas." },
    { u: "IPLE T7", q: "¿Qué son las bases de cotización?", opts: ["El dinero que el trabajador se lleva a casa.", "Cantidades calculadas sobre las retribuciones para aplicar los porcentajes de cuotas a la SS.", "Los impuestos directos que se pagan al ayuntamiento.", "El límite de horas extra permitidas."], ans: 1, exp: "Son la cifra bruta sobre la cual se calculan (multiplicando por un porcentaje) los impuestos que financian la sanidad, el paro y las pensiones." },
    { u: "IPLE T7", q: "En la nómina, la aportación del trabajador a la Seguridad Social incluye habitualmente:", opts: ["Contingencias comunes, desempleo y formación profesional.", "Solo contingencias profesionales.", "IRPF y multas de tráfico.", "El pago del seguro médico privado."], ans: 0, exp: "El trabajador paga su parte (deducciones) para financiar enfermedades comunes, el paro (desempleo) y los cursos del SEPE (FP)." },
    { u: "IPLE T7", q: "El IRPF es un impuesto de carácter:", opts: ["Fijo para todos los trabajadores (10%).", "Progresivo (paga más quien más gana) y se retiene como pago a cuenta.", "Voluntario si el trabajador no quiere pagarlo.", "Exclusivo de las empresas de más de 50 empleados."], ans: 1, exp: "La empresa actúa como recaudadora de Hacienda; te retiene el % de IRPF mes a mes según tu nivel de ingresos para la Declaración de la Renta." },
    { u: "IPLE T7", q: "¿Quién tiene la obligación de ingresar tanto su cuota como la del trabajador en la Seguridad Social?", opts: ["El propio trabajador personalmente.", "El empresario.", "El Ministerio de Hacienda.", "El sindicato mayoritario."], ans: 1, exp: "El empleador retiene el dinero de tu nómina y, junto con la cuota patronal, ingresa el total mes a mes en la Tesorería de la Seguridad Social." },
    { u: "IPLE T7", q: "Las horas extraordinarias por fuerza mayor tienen un tipo de cotización:", opts: ["Mucho más alto que las comunes.", "Más reducido que las comunes.", "Idéntico al salario base.", "Están exentas de cotización."], ans: 1, exp: "Para no penalizar el trabajo de emergencia (ej. apagar un incendio), la Seguridad Social grava estas horas extra con un porcentaje mucho menor." },
    { u: "IPLE T7", q: "¿Qué es la Asistencia Sanitaria de la Seguridad Social?", opts: ["Un pago en dinero cuando estás enfermo.", "Prestación de servicios médicos y farmacéuticos para conservar o restablecer la salud.", "Una ayuda para comprar material de oficina.", "Solo para accidentes de tráfico."], ans: 1, exp: "Es el derecho a ir al centro de salud, ser operado gratis en un hospital público y obtener recetas con descuento." },
    { u: "IPLE T7", q: "La Incapacidad Temporal (IT) es la situación en la que el trabajador está impedido para trabajar y recibe asistencia sanitaria por un periodo máximo de:", opts: ["6 meses.", "365 días (prorrogables por otros 180).", "5 años.", "2 meses."], ans: 1, exp: "La baja médica dura un máximo de un año, aunque un tribunal médico puede prorrogarla 6 meses más si prevé curación." },
    { u: "IPLE T7", q: "En una enfermedad común, ¿quién paga la prestación entre el día 4 y el 15 de la baja?", opts: ["La Seguridad Social.", "El empresario.", "No se cobra nada.", "La mutua con fondos públicos."], ans: 1, exp: "La ley hace responsable a la empresa de abonar la baja (el 60% de la base) durante esos días concretos. A partir del día 16, paga el INSS/Mutua." },
    { u: "IPLE T7", q: "¿A partir de qué día de baja por enfermedad común se empieza a cobrar la prestación?", opts: ["Desde el primer día.", "Desde el segundo día.", "Desde el cuarto día.", "Desde el día 20."], ans: 2, exp: "En una enfermedad común (ej. una gripe), los 3 primeros días no se cobra nada (salvo que el convenio de la empresa lo mejore)." },
    { u: "IPLE T7", q: "Si la baja es por accidente de trabajo o enfermedad profesional, se cobra desde el primer día el:", opts: ["60% de la base reguladora.", "75% de la base reguladora.", "100% de la base reguladora.", "50% de la base reguladora."], ans: 1, exp: "La ley protege más si el daño viene del trabajo: cobras desde el día 1 un 75% (y muchas empresas lo complementan hasta el 100%)." },
    { u: "IPLE T7", q: "¿Cuál es la duración actual del permiso por nacimiento y cuidado de menor para cada progenitor?", opts: ["6 semanas.", "12 semanas.", "16 semanas.", "20 semanas."], ans: 2, exp: "Tanto la madre biológica como el otro progenitor tienen derecho a 16 semanas pagadas e intransferibles." },
    { u: "IPLE T7", q: "De las 16 semanas por nacimiento, ¿cuántas son obligatorias disfrutarlas inmediatamente después del parto?", opts: ["Ninguna.", "2 semanas.", "6 semanas.", "10 semanas."], ans: 2, exp: "Las seis primeras semanas tras el parto son de descanso obligatorio ininterrumpido a jornada completa para ambos progenitores." },
    { u: "IPLE T7", q: "La prestación por nacimiento y cuidado de menor consiste en un subsidio equivalente al:", opts: ["75% de la base reguladora.", "100% de la base reguladora.", "SMI únicamente.", "60% de la base reguladora."], ans: 1, exp: "Durante tu baja de maternidad/paternidad, la Seguridad Social asume el 100% de tu base de cotización (cobras tu sueldo íntegro)." },
    { u: "IPLE T7", q: "¿En qué consiste la prestación por 'riesgo durante el embarazo'?", opts: ["En una baja por estar enferma durante la gestación.", "En la suspensión del contrato cuando el puesto de trabajo influye negativamente en la salud de la embarazada y no hay otro puesto compatible.", "En un permiso para ir a revisiones médicas.", "En una ayuda económica para comprar ropa de bebé."], ans: 1, exp: "No estás enferma, pero si tu trabajo implica riesgo (ej. cargar peso, radiación) y el jefe no te puede cambiar de puesto, la mutua te suspende el contrato pagándote el 100%." },
    { u: "IPLE T7", q: "La prestación por cuidado de menores afectados por cáncer u otra enfermedad grave permite una reducción de jornada de al menos:", opts: ["El 10%.", "El 25%.", "El 50%.", "El 5%."], ans: 2, exp: "La reducción será como mínimo de la mitad de la jornada (50%) para poder cuidar al niño hospitalizado o en tratamiento grave." },
    { u: "IPLE T7", q: "La incapacidad permanente que inhabilita al trabajador para su profesión habitual, pero le permite dedicarse a otra distinta, es:", opts: ["Incapacidad permanente parcial.", "Incapacidad permanente total.", "Incapacidad permanente absoluta.", "Gran invalidez."], ans: 1, exp: "Por ejemplo, un albañil con la espalda rota no puede seguir en la obra (IP Total), pero sí podría ser recepcionista." },
    { u: "IPLE T7", q: "¿Qué grado de incapacidad inhabilita al trabajador para TODA profesión u oficio?", opts: ["Parcial.", "Total.", "Absoluta.", "Temporal."], ans: 2, exp: "La Invalidez Permanente Absoluta te retira del mercado laboral por completo, y se cobra una pensión vitalicia del 100% de tu base." },
    { u: "IPLE T7", q: "La 'Gran Invalidez' se reconoce cuando el trabajador incapacitado:", opts: ["Puede trabajar en cualquier sitio.", "Necesita la asistencia de otra persona para los actos más esenciales de la vida.", "Tiene más de 65 años.", "Solo ha cotizado 5 años."], ans: 1, exp: "Es el grado máximo (tetraplejias, cegueras graves); se cobra la pensión absoluta más un plus económico para poder pagar a un cuidador." },
    { u: "IPLE T7", q: "La jubilación contributiva requiere haber cotizado un mínimo de:", opts: ["5 años.", "10 años.", "15 años (siendo 2 de ellos dentro de los 15 años anteriores).", "35 años obligatoriamente."], ans: 2, exp: "Es la 'carencia genérica': necesitas al menos 15 años cotizados en tu vida para tener derecho a una pensión de jubilación mínima." },
    { u: "IPLE T7", q: "¿Qué es la 'jubilación parcial'?", opts: ["Jubilarse solo los fines de semana.", "Compatibilizar el disfrute de la pensión con un contrato a tiempo parcial y la reducción de la jornada.", "Jubilarse 5 años antes de la edad legal sin cobrar nada.", "Solo para trabajadores autónomos."], ans: 1, exp: "Te retiras a medias: trabajas la mitad del tiempo cobrando de la empresa, y la otra mitad del tiempo cobras la pensión de jubilación." },
    { u: "IPLE T7", q: "¿Qué prestación reciben los hijos del fallecido menores de 21 años (o mayores con discapacidad)?", opts: ["Pensión de viudedad.", "Pensión de orfandad.", "Auxilio por defunción.", "Subsidio de defunción."], ans: 1, exp: "La pensión de orfandad protege a los huérfanos económicamente dependientes del fallecido." },
    { u: "IPLE T7", q: "El 'Auxilio por defunción' es una cuantía fija destinada a:", opts: ["Pagar las vacaciones de la familia.", "Hacer frente a los gastos del sepelio.", "Sustituir el salario del mes.", "Pagar la hipoteca del fallecido."], ans: 1, exp: "Es una pequeña ayuda económica en pago único de la Seguridad Social para ayudar a cubrir los altos costes de un entierro o incineración." },
    { u: "IPLE T7", q: "Las 'lesiones permanentes no incapacitantes' dan derecho a:", opts: ["Una pensión vitalicia mensual.", "Una indemnización a tanto alzado (un solo pago) según baremo.", "Tres años de vacaciones pagadas.", "La readmisión obligatoria en el puesto anterior."], ans: 1, exp: "Si pierdes un dedo trabajando, eso no te impide seguir trabajando, pero cobras una indemnización única oficial por la mutilación sufrida." },
    { u: "IPLE T7", q: "El Ingreso Mínimo Vital (IMV) es una prestación de tipo:", opts: ["Contributiva (necesita años cotizados).", "No contributiva (dirigida a prevenir el riesgo de pobreza y exclusión).", "Exclusiva para trabajadores en activo.", "Solo para extranjeros."], ans: 1, exp: "No necesitas haber trabajado nunca para cobrarlo; se financia con impuestos generales para asegurar una supervivencia básica a los más vulnerables." },
    { u: "IPLE T7", q: "Para acceder a la prestación contributiva por desempleo, ¿qué periodo mínimo se debe haber cotizado en los últimos 6 años?", opts: ["6 meses.", "12 meses (360 días).", "24 meses.", "5 años."], ans: 1, exp: "Para tener derecho a 'cobrar el paro' legal debes acumular un mínimo de 360 días cotizados antes del despido." },
    { u: "IPLE T7", q: "¿Cuál es la duración mínima de la prestación por desempleo si se han cotizado 360 días?", opts: ["2 meses.", "4 meses (120 días).", "6 meses.", "1 año."], ans: 1, exp: "La regla es 4 meses de paro por cada año cotizado. Al llegar al mínimo de 1 año (360 días), obtienes 120 días de prestación." },
    { u: "IPLE T7", q: "¿Cuál es la duración máxima de la prestación por desempleo?", opts: ["1 año.", "18 meses.", "2 años (720 días).", "De forma indefinida."], ans: 2, exp: "El tope máximo del paro contributivo es de 24 meses (2 años), y para alcanzarlo hace falta haber cotizado de forma ininterrumpida durante al menos 6 años." },
    { u: "IPLE T7", q: "Durante los primeros 180 días de paro, se cobra el:", opts: ["50% de la base reguladora.", "70% de la base reguladora.", "100% de la base reguladora.", "60% de la base reguladora."], ans: 1, exp: "Los primeros 6 meses de prestación el SEPE te abona el 70% de tu base de cotización de los últimos meses." },
    { u: "IPLE T7", q: "A partir del día 181, la cuantía de la prestación por desempleo pasa a ser el:", opts: ["70%.", "60%.", "50%.", "40%."], ans: 1, exp: "Tras los seis meses iniciales, el importe de la prestación baja del 70% al 60% para fomentar la búsqueda activa de empleo." },
    { u: "IPLE T7", q: "¿Cuál de estas situaciones permite cobrar el paro?", opts: ["Baja voluntaria (dimisión).", "Despido por parte de la empresa.", "No superar el periodo de prueba por decisión del trabajador.", "Estar de vacaciones."], ans: 1, exp: "Para cobrar el paro debes estar en 'Situación Legal de Desempleo'. Si te vas tú voluntariamente de la empresa, no te corresponde." },
    { u: "IPLE T7", q: "El subsidio por desempleo está destinado a personas que:", opts: ["No han trabajado nunca.", "Han agotado el paro contributivo o no han cotizado lo suficiente y tienen carencia de rentas.", "Ganan más de 3.000 euros al mes.", "Tienen un contrato indefinido."], ans: 1, exp: "Es el nivel asistencial (la 'ayuda'). Ampara a quien ya agotó sus dos años de paro normal o no llegó a cotizar los 360 días, siempre que no tenga ingresos propios." },
    { u: "IPLE T7", q: "¿Cuál es el requisito de rentas para cobrar el subsidio por desempleo?", opts: ["No tener ahorros.", "No tener rentas superiores al 75% del SMI (excluida la parte proporcional de pagas extras).", "Tener ingresos inferiores a 2.000 euros.", "Estar en el umbral de pobreza extrema."], ans: 1, exp: "Para demostrar la 'carencia de rentas' no puedes ganar por tu cuenta o por otros ingresos más del 75% del Salario Mínimo." },
    { u: "IPLE T7", q: "¿Qué cuantía se cobra generalmente en el subsidio por desempleo?", opts: ["El 100% del SMI.", "El 80% del IPREM.", "El 50% de la base reguladora.", "1.000 euros fijos."], ans: 1, exp: "El importe estándar de los subsidios (los famosos 480 euros mensuales actuales aproximadamente) se calcula aplicando el 80% al valor del IPREM vigente." },
    { u: "IPLE T7", q: "El subsidio por desempleo para mayores de 52 años tiene la ventaja de que:", opts: ["Solo dura un mes.", "Cotiza para la jubilación.", "No requiere buscar empleo.", "Se cobra el doble."], ans: 1, exp: "Es el subsidio más beneficioso porque dura hasta que alcanzas la edad de jubilación y el SEPE sigue cotizando a la Seguridad Social por ti para no mermar tu pensión." },
    { u: "IPLE T7", q: "Si un trabajador ha cotizado solo 4 meses y tiene responsabilidades familiares, ¿puede cobrar algo?", opts: ["No, nada.", "Sí, el subsidio por cotización insuficiente.", "Sí, el paro contributivo de 2 años.", "Solo el IMV."], ans: 1, exp: "Si tienes cargas familiares, puedes cobrar el subsidio habiendo cotizado tan solo 3, 4 o 5 meses." },
    { u: "IPLE T7", q: "El sistema de la Seguridad Social en España se basa en el principio de:", opts: ["Individualismo puro.", "Solidaridad financiera y unidad de caja.", "Capitalización privada obligatoria.", "Beneficio empresarial."], ans: 1, exp: "Solidaridad intergeneracional (los que trabajan ahora pagan las pensiones de los jubilados de ahora) y todos los ingresos van a una 'caja única' común del Estado." },
    { u: "IPLE T7", q: "¿Quiénes están obligatoriamente incluidos en el Sistema de la Seguridad Social?", opts: ["Solo los trabajadores por cuenta ajena.", "Españoles y extranjeros que residan y/o ejerzan su actividad en España.", "Únicamente los ciudadanos de la Unión Europea.", "Solo las personas enfermas."], ans: 1, exp: "Cualquier persona que trabaje legalmente en territorio nacional (autónomos o empleados, españoles o foráneos) cotiza y pertenece al sistema." },
    { u: "IPLE T7", q: "El Régimen General de la Seguridad Social incluye a:", opts: ["Trabajadores autónomos.", "Trabajadores por cuenta ajena del sector industrial y servicios.", "Estudiantes con seguro escolar únicamente.", "Funcionarios militares."], ans: 1, exp: "Es el régimen más amplio. Integra a la inmensa mayoría de asalariados que tienen nómina en la empresa privada." },
    { u: "IPLE T7", q: "El RETA es el régimen especial para:", opts: ["Mineros del carbón.", "Trabajadores Autónomos.", "Empleados de hogar.", "Artistas de circo."], ans: 1, exp: "Régimen Especial de Trabajadores Autónomos: ampara a los trabajadores por cuenta propia y societarios." },
    { u: "IPLE T7", q: "¿Qué se entiende por 'Contingencias Comunes'?", opts: ["Accidentes ocurridos trabajando.", "Alteraciones de la salud que no tienen relación directa con el trabajo (enfermedad común o accidente no laboral).", "El pago de las horas extra.", "Los riesgos de incendio en la oficina."], ans: 1, exp: "Ejemplos: fracturarse la pierna esquiando el domingo (accidente no laboral) o coger una neumonía vírica (enfermedad común)." },
    { u: "IPLE T7", q: "El INSS (Instituto Nacional de la Seguridad Social) se encarga de:", opts: ["Gestionar las prestaciones económicas (pensiones, bajas, etc.).", "Buscar trabajo a los desempleados.", "Inspeccionar las medidas de seguridad de las máquinas.", "Cobrar las multas de tráfico."], ans: 0, exp: "El INSS es la 'ventanilla' que te aprueba la jubilación, la viudedad o el pago de una baja de larga duración." },
    { u: "IPLE T7", q: "La Tesorería General de la Seguridad Social (TGSS) tiene como función:", opts: ["Operar a los enfermos.", "La recaudación de cuotas, afiliaciones, altas y bajas.", "Decidir quién se jubila.", "Redactar los convenios colectivos."], ans: 1, exp: "Es la 'caja fuerte' del sistema: te asigna tu número de SS, da de alta a tu empresa y recauda el dinero de los seguros sociales de tu nómina." },
    { u: "IPLE T7", q: "El SEPE (Servicio Público de Empleo Estatal) gestiona:", opts: ["La tarjeta sanitaria.", "Las prestaciones y subsidios por desempleo.", "El IRPF.", "La seguridad en las minas."], ans: 1, exp: "El antiguo INEM se encarga de todo lo relacionado con el cobro del paro, subsidios y cursos de formación ocupacional." },
    { u: "IPLE T7", q: "¿Qué es una Mutua Colaboradora con la Seguridad Social?", opts: ["Una asociación de trabajadores para ir de viaje.", "Entidades privadas sin ánimo de lucro que gestionan contingencias profesionales y parte de las comunes.", "Una compañía de seguros de coche.", "El departamento médico del sindicato."], ans: 1, exp: "Son asociaciones de empresarios, tuteladas por el Estado, que asumen la atención y el pago de los accidentes laborales de sus trabajadores (Fremap, Asepeyo...)." },
    { u: "IPLE T7", q: "El plazo para comunicar el alta de un trabajador en la Seguridad Social es:", opts: ["Hasta 5 días después de empezar.", "Previo al inicio de la prestación de servicios (hasta 60 días antes).", "Cuando termine el periodo de prueba.", "No hay plazo, es voluntario."], ans: 1, exp: "El alta debe hacerse SIEMPRE antes de que el empleado empiece a trabajar. Darle de alta después del inicio supone una falta grave." },
    { u: "IPLE T7", q: "¿Qué nombre recibe la cantidad líquida que el trabajador percibe en su cuenta?", opts: ["Devengo total.", "Remuneración bruta.", "Neto a cobrar o líquido a percibir.", "Base imponible."], ans: 2, exp: "Es el importe numérico que cierra la nómina por abajo, resultante de descontar al devengo (bruto) las deducciones de IRPF y SS." },
    { u: "IPLE T7", q: "Las 'percepciones en especie' (ej. uso de coche de empresa) tienen un límite máximo del:", opts: ["10% de las percepciones salariales.", "30% de las percepciones salariales.", "50% de las percepciones salariales.", "No tienen límite."], ans: 1, exp: "La ley topa el salario en especie para garantizar que, como mínimo, recibas el 70% de tu sueldo en 'dinero contante y sonante' para poder subsistir." },
    { u: "IPLE T7", q: "¿Qué concepto de la nómina NO cotiza a la Seguridad Social (generalmente)?", opts: ["El salario base.", "La antigüedad.", "Los gastos de locomoción (dentro de los límites legales).", "El plus de peligrosidad."], ans: 2, exp: "Las dietas, gastos de locomoción e indemnizaciones extra-salariales están exentos de cotizar y de tributar por no ser un ingreso de riqueza directa, sino el reembolso de un gasto." },
    { u: "IPLE T7", q: "El 'devengo' en la nómina hace referencia a:", opts: ["Lo que se quita del sueldo.", "Los derechos económicos que el trabajador adquiere por su trabajo (lo que 'gana').", "La fecha en la que se paga.", "El nombre de la empresa."], ans: 1, exp: "Agrupa todos los conceptos por los que la empresa te paga (base, antigüedad, incentivos, etc.) conformando tu sueldo bruto." },
    { u: "IPLE T7", q: "¿Cuál de las siguientes es una deducción obligatoria en la nómina?", opts: ["El pago del gimnasio de la empresa.", "La retención del IRPF.", "La suscripción a una revista técnica.", "El préstamo personal del jefe."], ans: 1, exp: "Retener la cuota obrera de la Seguridad Social y el IRPF a cuenta de Hacienda son dos deducciones legales ineludibles por la empresa." },
    { u: "IPLE T7", q: "¿Qué es el 'periodo de carencia' en una prestación?", opts: ["El tiempo que se tarda en cobrar tras la solicitud.", "El tiempo mínimo de cotización previa exigido para tener derecho a la prestación.", "El periodo de vacaciones no disfrutadas.", "El tiempo de espera en el médico."], ans: 1, exp: "Es la 'cotización mínima' que el sistema te exige para poder protegerte (ej. para cobrar jubilación, la carencia son 15 años)." },
    { u: "IPLE T7", q: "En caso de accidente no laboral, la prestación de IT requiere haber cotizado:", opts: ["180 días en los últimos 5 años.", "No se exige periodo previo de cotización.", "12 meses.", "5 años."], ans: 0, exp: "(*Nota*: Según las respuestas de este test oficial corresponde la opción 'A', aunque legalmente esta carencia específica de 180 días aplica a la 'enfermedad común', siendo los accidentes libres de carencia)." },
    { u: "IPLE T7", q: "En caso de accidente de TRABAJO, la prestación de IT requiere:", opts: ["180 días cotizados.", "No se exige periodo de carencia (cotización previa).", "360 días cotizados.", "Tener más de 30 años."], ans: 1, exp: "Al derivar de un daño producido por culpa de la empresa o del trabajo, la Seguridad Social te protege de forma absoluta desde el primer segundo en que eres contratado, sin importar si no tenías meses cotizados antes." },
    { u: "IPLE T7", q: "¿Qué porcentaje de la base reguladora se cobra en una Incapacidad Permanente TOTAL?", opts: ["100%.", "55% (con posibilidad de aumentar al 75% si se cumplen ciertos requisitos de edad).", "20%.", "33%."], ans: 1, exp: "Al poder buscar otro trabajo diferente, cobras un 55% de tu pensión normal; a partir de los 55 años, si no encuentras empleo, ese porcentaje se eleva un 20% extra (75%)." },
    { u: "IPLE T7", q: "El subsidio por desempleo de nivel asistencial se abona mensualmente por periodos de:", opts: ["1 mes.", "6 meses prorrogables.", "Todo el año de una vez.", "Solo los meses de verano."], ans: 1, exp: "Generalmente, los subsidios se conceden de 6 en 6 meses. Si el beneficiario mantiene la carencia de ingresos, debe renovarlo al final de cada semestre." },
    { u: "IPLE T7", q: "¿Cuál es el número de teléfono para solicitar el IMV o información de pensiones?", opts: ["112.", "060 o los números específicos del INSS.", "No hay teléfono, solo presencial.", "El teléfono del ayuntamiento."], ans: 1, exp: "El Gobierno cuenta con líneas oficiales unificadas (como el 060 de la AGE) y teléfonos propios de la Seguridad Social para estos trámites asistenciales." },
    { u: "IPLE T7", q: "La base de cotización por contingencias profesionales incluye:", opts: ["Solo el salario base.", "La base de contingencias comunes más las horas extraordinarias.", "El IRPF únicamente.", "El valor de la ropa de trabajo."], ans: 1, exp: "Para calcularla, tomamos la Base de Contingencias Comunes del mes (BCC) y le sumamos obligatoriamente el importe que hayamos cobrado por horas extras ese mes." },
    { u: "IPLE T7", q: "¿Qué ocurre si un trabajador no está dado de alta en la Seguridad Social en el momento de un accidente laboral?", opts: ["No tiene derecho a nada.", "Se considera 'alta de pleno derecho' y el empresario será responsable de las prestaciones con recargo.", "El trabajador debe pagar los gastos médicos.", "La empresa se cierra automáticamente."], ans: 1, exp: "La ley asume que el trabajador debía estar de alta y asume su protección (Alta de pleno derecho). El empresario infractor se enfrentará a penas civiles y penales, y a pagar el coste sanitario de su propio bolsillo." },
    { u: "IPLE T7", q: "La tarjeta sanitaria europea permite recibir asistencia médica en:", opts: ["Todo el mundo.", "Los países de la Unión Europea, Espacio Económico Europeo y Suiza.", "Solo en España y Portugal.", "Únicamente en hospitales privados de Londres."], ans: 1, exp: "Si viajas a Francia o Alemania, esta tarjeta gratuita certifica tu derecho a recibir asistencia sanitaria en hospitales públicos con las mismas coberturas que los locales." },
    { u: "IPLE T7", q: "El 'salario en especie' nunca puede ser superior al:", opts: ["10% del salario total.", "30% de las percepciones salariales.", "50% de la base reguladora.", "100% de la nómina."], ans: 1, exp: "Por mucho que te den vales restaurante o coche de empresa, al menos el 70% de tu sueldo debe ingresarse en efectivo." },
// --- PREGUNTAS DE LA PLATAFORMA (MOODLE) ---
    { u: "IPLE T8", q: "La capacidad de una persona para comprender sus propias características, es decir, sus intereses, valores, motivaciones, habilidades y destrezas, se denomina:", opts: ["Autoconocimiento", "Inventario de intereses", "Exploración de actividades", "Instinto"], ans: 0, exp: "El autoconocimiento es el pilar básico de la orientación laboral: conocer qué se te da bien, qué te gusta y cuáles son tus valores para enfocar tu carrera." },
    { u: "IPLE T8", q: "El Inventario de Intereses de Holland:", opts: ["También es conocido como «Teoría de los Tipos de Personalidad Vocacional»", "Clasifica a las personas y los ambientes de trabajo en seis tipos", "Es una batería de preguntas que evalúan las preferencias y aversiones del individuo", "Todas son correctas"], ans: 3, exp: "El modelo RIASEC de Holland agrupa las personalidades en 6 tipos (Realista, Investigador, Artístico, Social, Emprendedor y Convencional) mediante cuestionarios específicos." },
    { u: "IPLE T8", q: "Las motivaciones:", opts: ["Son factores internos que impulsan a una persona a actuar y alcanzar sus metas", "Son factores externos que impulsan a una persona a actuar y alcanzar sus metas", "Son factores internos y externos que impulsan a una persona a actuar y alcanzar sus metas", "Permiten descubrir nuevas áreas de interés y enriquecerse"], ans: 2, exp: "La motivación tiene una vertiente intrínseca (lo que nos nace de dentro, como la vocación) y una extrínseca (el salario, el reconocimiento social)." },
    { u: "IPLE T8", q: "Se pueden conocer las habilidades a través de:", opts: ["Inventarios de habilidades", "Autoevaluación de competencias", "Evaluaciones de desempeño", "Todas son correctas"], ans: 3, exp: "Existen múltiples herramientas de recursos humanos y psicología para medir y evaluar de forma objetiva las habilidades de un candidato o trabajador." },
    { u: "IPLE T8", q: "Los atributos innatos o desarrollados que forman parte de la personalidad de un individuo se denominan:", opts: ["Competencias personales", "Cualidades personales", "Competencias sociales", "Preferencias profesionales"], ans: 1, exp: "Las cualidades (como ser paciente, meticuloso o extrovertido) son rasgos de la personalidad y el carácter." },
    { u: "IPLE T8", q: "Las habilidades adquiridas que pueden desarrollarse y mejorarse con el tiempo, imprescindibles para desempeñar cada puesto de trabajo, se denominan:", opts: ["Competencias personales", "Cualidades personales", "Competencias sociales", "Preferencias profesionales"], ans: 0, exp: "Las competencias (como saber usar Excel, liderar equipos o hablar inglés) se aprenden y se entrenan con la práctica." },
    { u: "IPLE T8", q: "Existen tres tipos de objetivos profesionales:", opts: ["Personales, empresariales y grupales", "Logísticos, específicos y estratégicos", "A corto, a medio y a largo plazo", "Específicos, de proyecto de carrera y evaluativos"], ans: 2, exp: "En la planificación de la carrera profesional, las metas se dividen temporalmente en corto, medio y largo plazo." },
    { u: "IPLE T8", q: "Una de las vías de acceso a los Ciclos Formativos de Grado Superior es:", opts: ["Disponer del título de Técnico, al haber superado los estudios de Grado Medio", "Poseer un título de Bachillerato", "Tener aprobada la prueba de acceso a los CFGS", "Todas son correctas"], ans: 3, exp: "El sistema educativo español permite acceder a la FP de Grado Superior desde Bachillerato, promocionando desde un Grado Medio o superando una prueba oficial." },
    { u: "IPLE T8", q: "Tras la Declaración de Bolonia de 1999, los estudios universitarios quedaron divididos en dos niveles:", opts: ["Estudios de grado y estudios de posgrado", "Grados Medios y Grados Superiores", "Máster y Doctorado", "Estudios europeos y estudios internacionales"], ans: 0, exp: "El Plan Bolonia unificó el Espacio Europeo de Educación Superior estructurándolo en Grado (4 años por norma general) y Posgrado (Máster y Doctorado)." },
    { u: "IPLE T8", q: "La autoestima:", opts: ["No tiene relevancia en el contexto de la búsqueda de empleo", "Es el factor que determina las habilidades técnicas específicas", "Es la percepción subjetiva y la valoración emocional que una persona tiene de sí misma", "Puede ser educativa, personal o laboral"], ans: 2, exp: "La autoestima es cómo nos valoramos a nosotros mismos, siendo un factor clave (psicológico) para afrontar con éxito entrevistas de trabajo y nuevos retos." },

    // --- BLOQUE CUESTIONARIO DE AUTOEVALUACIÓN: POTENCIAL Y AUTO-ORIENTACIÓN (70 PREGUNTAS) ---
    { u: "IPLE T8", q: "¿Qué es el autoconocimiento en el ámbito profesional?", opts: ["Conocer a fondo la historia de la empresa donde se quiere trabajar.", "La capacidad de una persona para comprender sus propios intereses, valores, motivaciones, habilidades y destrezas.", "El estudio de los salarios medios de un sector determinado.", "La memorización del currículum vitae."], ans: 1, exp: "El autoconocimiento es el paso número uno de la auto-orientación: saber con precisión quién eres y qué puedes aportar profesionalmente." },
    { u: "IPLE T8", q: "¿Cómo se definen los 'Intereses'?", opts: ["Factores que impulsan a una persona a actuar.", "Actividades, temas o áreas que captan la atención y motivan a aprender y participar en ellas.", "Títulos académicos obtenidos de forma oficial.", "El sueldo mínimo que un trabajador está dispuesto a aceptar."], ans: 1, exp: "Los intereses son aquellas áreas que te despiertan curiosidad y ganas de formarte por simple afición o vocación." },
    { u: "IPLE T8", q: "¿Qué herramienta se menciona específicamente para evaluar los intereses profesionales?", opts: ["El Test de Cooper.", "El Inventario de Intereses de Holland.", "El Diagrama de Gantt.", "El análisis PESTEL."], ans: 1, exp: "El test o inventario de Holland es el estándar mundial para identificar perfiles profesionales (Realista, Investigador, Artístico...)." },
    { u: "IPLE T8", q: "Los factores internos y externos que impulsan a una persona a actuar y alcanzar sus metas son:", opts: ["Las habilidades.", "Las motivaciones.", "Las destrezas.", "Los hitos."], ans: 1, exp: "La motivación es el 'motor' de la conducta, ya sea para conseguir un sueldo (externo) o sentir realización personal (interno)." },
    { u: "IPLE T8", q: "¿Cuál de los siguientes es un método para la evaluación de las motivaciones?", opts: ["Pruebas de velocidad física.", "Cuestionarios de motivación, diarios de reflexión y entrevistas de retroalimentación.", "Exámenes de matemáticas avanzadas.", "Análisis de la competencia de mercado."], ans: 1, exp: "Las motivaciones se miden psicológicamente mediante herramientas reflexivas y tests diseñados para ello." },
    { u: "IPLE T8", q: "¿Qué diferencia fundamental hay entre 'Habilidades' y 'Destrezas'?", opts: ["No hay diferencia, son términos idénticos.", "Las habilidades son innatas y las destrezas siempre se compran.", "Las habilidades son capacidades adquiridas por educación/experiencia y las destrezas son habilidades específicas mejoradas con la práctica.", "Las destrezas solo se aplican en trabajos manuales."], ans: 2, exp: "Las habilidades son generales, mientras que las destrezas son habilidades que has pulido a un nivel experto base a mucha práctica." },
    { u: "IPLE T8", q: "¿Cómo se evalúan las destrezas según el temario?", opts: ["Mediante sorteo público.", "A través de pruebas de competencia, simulaciones, prácticas y autoevaluaciones.", "Únicamente mediante la revisión de títulos universitarios.", "Preguntando a los vecinos."], ans: 1, exp: "La destreza se demuestra 'haciendo', por lo que la mejor forma de evaluarla es poner al candidato ante una situación simulada o real de trabajo." },
    { u: "IPLE T8", q: "¿Cuál es el objetivo final de realizar una evaluación de intereses, motivaciones y destrezas?", opts: ["Conseguir un aumento de sueldo inmediato.", "La elaboración de un Plan de Acción.", "Poder criticar a otros profesionales.", "Dejar de estudiar definitivamente."], ans: 1, exp: "El autodiagnóstico no tiene sentido si no deriva en un Plan de Acción concreto que marque los pasos a seguir para alcanzar tus metas." },
    { u: "IPLE T8", q: "¿Qué son las 'Cualidades Personales'?", opts: ["Títulos de posgrado.", "Atributos innatos o desarrollados que forman parte de la personalidad (ej. responsabilidad, resiliencia).", "El tipo de coche que conduce el trabajador.", "La ropa que se usa en la entrevista."], ans: 1, exp: "Son tus rasgos de carácter: ser puntual, paciente, comunicativo, proactivo o resiliente." },
    { u: "IPLE T8", q: "La 'Resiliencia' se define como la capacidad de:", opts: ["Mandar sobre los demás con autoridad.", "Adaptarse positivamente a situaciones adversas o periodos de dolor emocional.", "Aprender 10 idiomas en un año.", "Instalar sistemas domóticos complejos."], ans: 1, exp: "La resiliencia es la flexibilidad psicológica para 'rebotar' y salir fortalecido ante un fracaso, despido o crisis." },
    { u: "IPLE T8", q: "¿Qué son las 'Competencias Personales'?", opts: ["Características físicas del trabajador.", "Habilidades adquiridas que pueden desarrollarse y mejorarse con el tiempo.", "La rivalidad entre compañeros de oficina.", "El historial de multas de tráfico."], ans: 1, exp: "A diferencia de las cualidades (que son más innatas), las competencias son 100% fruto del entrenamiento y el aprendizaje." },
    { u: "IPLE T8", q: "Las competencias personales pueden dividirse en:", opts: ["Rápidas y lentas.", "Técnicas (hard skills) e interpersonales (soft skills).", "Caras y baratas.", "Públicas y privadas."], ans: 1, exp: "El mercado laboral las divide entre 'duras' (saber contabilidad, programar) y 'blandas' (comunicarse, trabajar en equipo)." },
    { u: "IPLE T8", q: "¿Qué integran las 'Competencias Sociales'?", opts: ["Conocimientos, comportamientos y actitudes sociales que influyen en cómo actuamos con otros.", "Solo el número de seguidores en redes sociales.", "La capacidad de trabajar de forma aislada sin hablar con nadie.", "El conocimiento de leyes internacionales."], ans: 0, exp: "Son las destrezas que nos permiten relacionarnos de forma efectiva y armónica con compañeros, jefes y clientes." },
    { u: "IPLE T8", q: "¿Cuál de estas es una cualidad personal relevante mencionada en la síntesis?", opts: ["La altura física.", "La proactividad y la autoconfianza.", "El color de ojos.", "La caligrafía."], ans: 1, exp: "Tener iniciativa (proactividad) y creer en ti mismo (autoconfianza) son de las cualidades más valoradas por los seleccionadores." },
    { u: "IPLE T8", q: "¿Qué representan las 'Preferencias Profesionales'?", opts: ["Lo que el jefe quiere que hagamos.", "Inclinaciones y elecciones que una persona realiza respecto a aspectos específicos que le atraen de su carrera.", "La lista de empresas que pagan mejor.", "El horario de salida más temprano posible."], ans: 1, exp: "Tus preferencias marcan qué tipo de trabajo te hace feliz: ¿trabajar al aire libre o en oficina? ¿en equipo o solo?" },
    { u: "IPLE T8", q: "Los 'Objetivos Profesionales' deben ser:", opts: ["Imposibles de alcanzar para motivar más.", "Metas específicas y medibles que proporcionan dirección y propósito.", "Secretos para que nadie nos los robe.", "Únicamente metas económicas a corto plazo."], ans: 1, exp: "Deben ser realistas, cuantificables y tener un plazo de tiempo definido (método SMART)." },
    { u: "IPLE T8", q: "La autoevaluación emocional y subjetiva que una persona tiene de sí misma es:", opts: ["El autoconocimiento técnico.", "La autoestima.", "El currículum.", "La asertividad."], ans: 1, exp: "La autoestima es fundamental porque dictamina cuánto valor crees que aportas a una empresa." },
    { u: "IPLE T8", q: "En la búsqueda de empleo, una autoestima baja puede provocar:", opts: ["Un exceso de ofertas de trabajo.", "Dificultades para enfrentarse a obstáculos y presentarse de forma efectiva al mercado.", "Una mejor relación con los entrevistadores.", "Que el proceso sea más rápido."], ans: 1, exp: "Una baja autoestima te hace dudar de tus capacidades, vendiéndote peor en las entrevistas y aceptando condiciones inferiores." },
    { u: "IPLE T8", q: "¿Qué se entiende por 'Hitos' en el desarrollo profesional?", opts: ["Errores graves cometidos en el pasado.", "Eventos o logros significativos que tienen un impacto notable en el desarrollo de la persona.", "Los días de vacaciones acumulados.", "Las herramientas de mano que usa un electricista."], ans: 1, exp: "Terminar la carrera, conseguir tu primer contrato fijo o liderar un proyecto con éxito son 'hitos' (milestones) de tu carrera." },
    { u: "IPLE T8", q: "Identificar los hitos personales sirve para:", opts: ["Olvidar el pasado.", "Reconocer patrones de éxito y áreas de crecimiento profesional.", "Rellenar los huecos vacíos del currículum con mentiras.", "Compararse negativamente con los demás."], ans: 1, exp: "Te ayuda a ver de dónde vienes, qué has conseguido hasta ahora y qué camino lógico debes seguir." },
    { u: "IPLE T8", q: "¿Cuál es el objetivo principal de la Formación Profesional para el empleo?", opts: ["Entretener a los trabajadores en sus horas libres.", "Promover una formación que dé respuesta a las necesidades de empresas y trabajadores y favorezca la economía del conocimiento.", "Sustituir a la educación universitaria por completo.", "Ofrecer cursos exclusivamente manuales."], ans: 1, exp: "Busca cerrar la brecha entre lo que las personas saben hacer y lo que el mercado laboral realmente demanda de manera práctica." },
    { u: "IPLE T8", q: "¿A quién va dirigida la formación profesional para el empleo?", opts: ["Solo a trabajadores en activo.", "Solo a personas desempleadas.", "Tanto a trabajadores ocupados como desocupados.", "Exclusivamente a menores de 25 años."], ans: 2, exp: "Existen cursos de recualificación tanto para gente en el paro como para actualizar a los que ya tienen un empleo." },
    { u: "IPLE T8", q: "¿Qué título se requiere para acceder directamente a un Ciclo Formativo de Grado Medio?", opts: ["Título de Bachillerato.", "Título de Educación Secundaria Obligatoria (ESO).", "Título de Grado Universitario.", "No se requiere ningún título."], ans: 1, exp: "La vía directa por excelencia al Grado Medio es estar en posesión del título de la ESO." },
    { u: "IPLE T8", q: "¿A qué edad mínima se puede realizar la prueba de acceso a un Ciclo de Grado Medio si no se tiene el título de ESO?", opts: ["15 años.", "16 años.", "17 años.", "18 años."], ans: 2, exp: "Se requiere tener 17 años cumplidos en el año de celebración de la prueba para poder presentarse." },
    { u: "IPLE T8", q: "Tras finalizar un Ciclo Formativo de Grado Medio, ¿cuál de estas es una opción válida?", opts: ["Acceder directamente a un Doctorado.", "Estudiar un ciclo de FP de Grado Superior.", "Ser nombrado director general de una multinacional automáticamente.", "No existe ninguna opción de estudio posterior."], ans: 1, exp: "Tener un título de Técnico (Grado Medio) te permite acceder de forma directa a los Ciclos Formativos de Grado Superior." },
    { u: "IPLE T8", q: "Para acceder a un Ciclo Formativo de Grado Superior se requiere, entre otros:", opts: ["El título de Técnico (Grado Medio) o Bachillerato.", "Haber trabajado 10 años en el sector.", "Tener más de 30 años.", "El título de Graduado Escolar antiguo solamente."], ans: 0, exp: "Las dos vías académicas directas principales son disponer de Bachillerato o de un ciclo de Grado Medio previo." },
    { u: "IPLE T8", q: "¿Qué es un 'Curso de Especialización Profesional'?", opts: ["Un curso de idiomas básico.", "Una formación destinada a profundizar en áreas específicas tras obtener un título de Técnico o Técnico Superior.", "Un curso para aprender a usar el correo electrónico.", "Una formación obligatoria para todos los ciudadanos."], ans: 1, exp: "Son los 'másteres' de la FP: cursos cortos muy técnicos que requieren tener un título previo para poder acceder (ej. especialización en robótica o ciberseguridad)." },
    { u: "IPLE T8", q: "Tras un Ciclo de Grado Superior, se puede acceder a:", opts: ["Únicamente al mercado laboral.", "Estudios universitarios (con posibilidad de convalidaciones).", "Solamente a otro Grado Superior igual.", "La jubilación anticipada."], ans: 1, exp: "El título de Técnico Superior te abre las puertas directas a la universidad sin pasar por Selectividad (EBAU) y permite convalidar créditos ECTS de la carrera." },
    { u: "IPLE T8", q: "¿Existe la posibilidad de convalidar módulos de Grado Medio con materias de Bachillerato?", opts: ["No, nunca.", "Sí, está previsto en la normativa.", "Solo si el centro es privado.", "Solo en la Comunidad de Madrid."], ans: 1, exp: "La normativa educativa permite puentes y convalidaciones entre las asignaturas cursadas en la FP y materias análogas del Bachillerato." },
    { u: "IPLE T8", q: "La formación profesional para el empleo busca el desarrollo de una economía basada en:", opts: ["El sector primario únicamente.", "El conocimiento.", "La importación masiva.", "El azar."], ans: 1, exp: "La formación continua de los trabajadores promueve una economía del conocimiento, innovación y alto valor añadido." },
    { u: "IPLE T8", q: "El 'Plan de Acción' es el resultado de:", opts: ["Un sorteo.", "El proceso de autoconocimiento y evaluación de competencias.", "Una orden directa del SEPE.", "La lectura de un periódico."], ans: 1, exp: "El Plan es la estrategia escrita que haces tras haber analizado qué sabes hacer y qué te falta para lograr tu objetivo." },
    { u: "IPLE T8", q: "¿Qué característica debe tener un objetivo profesional para ser útil?", opts: ["Ser vago y general.", "Ser inalcanzable.", "Ser específico y medible (SMART).", "Ser copiado de un compañero."], ans: 2, exp: "Un objetivo válido debe ser Específico, Medible, Alcanzable, Relevante y con un límite de Tiempo (filosofía SMART)." },
    { u: "IPLE T8", q: "La 'Auto-orientación laboral' comienza con:", opts: ["La firma de un contrato.", "El autoconocimiento.", "El despido de una empresa.", "La compra de un ordenador."], ans: 1, exp: "No puedes trazar un rumbo profesional si no sabes dónde te encuentras ahora mismo (autoconocimiento)." },
    { u: "IPLE T8", q: "¿Qué influye en la capacidad para adaptarse a un mercado laboral en constante cambio?", opts: ["Solo la suerte.", "El análisis de las cualidades y competencias personales.", "El tipo de sangre del trabajador.", "La ubicación geográfica de la casa del trabajador."], ans: 1, exp: "Saber de qué herramientas dispones psicológicamente (resiliencia, adaptabilidad) te permite ajustar tu perfil a los cambios del mercado." },
    { u: "IPLE T8", q: "Un 'diario de reflexión' es una herramienta útil para evaluar:", opts: ["La velocidad de mecanografía.", "Las motivaciones.", "El nivel de inglés técnico.", "La presión arterial."], ans: 1, exp: "Anotar lo que te inspira y lo que te frustra cada día te ayuda a detectar patrones y definir tus verdaderas motivaciones profesionales." },
    { u: "IPLE T8", q: "¿Cuál es la principal diferencia entre cualidad y competencia?", opts: ["Ninguna.", "La cualidad es parte de la personalidad (ser); la competencia es una habilidad desarrollada (saber hacer).", "La cualidad es solo para jefes.", "La competencia es ilegal."], ans: 1, exp: "La cualidad es cómo eres de forma innata (ej. ser meticuloso), y la competencia es aquello que has aprendido a hacer (ej. tornear metales)." },
    { u: "IPLE T8", q: "La iniciativa y la autoconfianza se clasifican como:", opts: ["Títulos académicos.", "Cualidades personales.", "Defectos de fábrica.", "Requisitos legales."], ans: 1, exp: "Forman parte de tus fortalezas psicológicas o cualidades." },
    { u: "IPLE T8", q: "Para realizar la prueba de acceso a Ciclos de Grado Superior se requiere tener al menos:", opts: ["17 años.", "18 años.", "19 años.", "21 años."], ans: 2, exp: "El requisito de edad mínima en España para poder realizar la prueba de acceso a Grado Superior es tener 19 años cumplidos." },
    { u: "IPLE T8", q: "Si un estudiante tiene el título de Técnico Superior, puede acceder a la Universidad:", opts: ["No, es imposible.", "Sí, directamente y con reserva de plazas en algunos casos.", "Solo si aprueba de nuevo la ESO.", "Solo a universidades extranjeras."], ans: 1, exp: "La FP de Grado Superior es llave de acceso directo a estudios universitarios afines, contando en las notas de corte con cupos reservados." },
    { u: "IPLE T8", q: "¿Qué se entiende por 'itinerario formativo'?", opts: ["El camino que sigue el autobús al instituto.", "La secuencia de estudios y capacitaciones que una persona sigue para alcanzar su meta profesional.", "La lista de libros de texto de un curso.", "El mapa de la ciudad."], ans: 1, exp: "Es el mapa u hoja de ruta que trazas marcando qué cursos y certificaciones necesitas ir sacando en el futuro." },
    { u: "IPLE T8", q: "Una de las opciones tras el Grado Superior es iniciar otro Ciclo de Grado Superior. En este caso:", opts: ["Hay que empezar desde cero absoluto.", "Se pueden convalidar algunos módulos ya superados.", "Solo se puede si el anterior se suspendió.", "Está prohibido por ley."], ans: 1, exp: "Ciertas asignaturas comunes como 'Formación y Orientación Laboral' o módulos técnicos afines se pueden convalidar directamente." },
    { u: "IPLE T8", q: "La formación profesional pretende que el aprendizaje sea:", opts: ["Puramente teórico.", "A lo largo de toda la vida (lifelong learning).", "Solo durante la adolescencia.", "Un castigo."], ans: 1, exp: "El 'aprendizaje a lo largo de la vida' es el paradigma actual: nunca se deja de estudiar y reciclar conocimientos." },
    { u: "IPLE T8", q: "¿Cómo actúan las competencias sociales en el trabajo?", opts: ["No tienen ninguna relevancia.", "Influyen en cómo interactuamos con otras personas y trabajamos en equipo.", "Sirven para que el jefe nos dé más vacaciones.", "Permiten hackear sistemas informáticos."], ans: 1, exp: "Determinan tu inteligencia emocional y social en la oficina, algo vital para mantener un buen clima de trabajo." },
    { u: "IPLE T8", q: "El respeto y la empatía son ejemplos de:", opts: ["Competencias sociales y actitudes.", "Conocimientos de física cuántica.", "Obligaciones fiscales.", "Software de gestión."], ans: 0, exp: "Son la base de las 'soft skills' interpersonales para evitar el conflicto." },
    { u: "IPLE T8", q: "Una persona con buena 'auto-orientación' es capaz de:", opts: ["Predecir el futuro de la bolsa.", "Tomar decisiones informadas alineadas con sus aspiraciones.", "Trabajar sin cobrar.", "No cometer nunca errores."], ans: 1, exp: "Un profesional bien auto-orientado sabe cuándo cambiar de trabajo, qué formación elegir y no depende de otros para decidir su futuro." },
    { u: "IPLE T8", q: "La 'evaluación de competencias actuales' se conoce también como:", opts: ["Examen final.", "Autodiagnóstico.", "Auditoría externa.", "Currículum ciego."], ans: 1, exp: "Hacer un balance personal honesto de tus puntos fuertes y débiles antes de buscar trabajo." },
    { u: "IPLE T8", q: "¿Qué busca detectar el Inventario de Holland?", opts: ["Enfermedades raras.", "Tipologías de personalidad y su ajuste a entornos laborales.", "La velocidad de reacción ante un incendio.", "El nivel de ahorro bancario."], ans: 1, exp: "Trata de emparejar tu carácter (ej. tipo Emprendedor) con la familia profesional en la que más encajarías y serías feliz." },
    { u: "IPLE T8", q: "El éxito profesional hoy en día depende de:", opts: ["Solo los contactos familiares.", "La combinación de formación, experiencia, cualidades y competencias.", "Únicamente el azar.", "Tener el título más caro."], ans: 1, exp: "No basta con tener solo un buen título; se requiere también de buena actitud, habilidades sociales y experiencia." },
    { u: "IPLE T8", q: "¿Cuál es un beneficio 'tangible' de la formación profesional?", opts: ["La felicidad absoluta.", "La adquisición de destrezas técnicas demandadas por el mercado.", "Soñar con el trabajo.", "Tener muchos amigos en clase."], ans: 1, exp: "Aprender a usar una máquina concreta te otorga una ventaja palpable e inmediata a la hora de buscar trabajo." },
    { u: "IPLE T8", q: "Un objetivo 'medible' significa que:", opts: ["Es muy largo.", "Se puede comprobar si se ha alcanzado mediante datos o hechos.", "Pesa muchos kilos.", "Se mide con una regla de madera."], ans: 1, exp: "Ejemplo: En lugar de decir 'mejorar mi inglés', un objetivo medible es 'Conseguir el certificado B2 oficial en diciembre'." },
    { u: "IPLE T8", q: "Las 'soft skills' son:", opts: ["Programas de ordenador fáciles de usar.", "Habilidades interpersonales y sociales.", "Herramientas de construcción de plástico.", "Técnicas de programación en C++."], ans: 1, exp: "El liderazgo, la creatividad o la resolución de problemas son 'habilidades blandas' o sociales." },
    { u: "IPLE T8", q: "Las 'hard skills' se refieren a:", opts: ["Habilidades de comunicación emocional.", "Conocimientos técnicos y específicos de una profesión.", "La dureza física del trabajador.", "El carácter difícil de un jefe."], ans: 1, exp: "El cálculo de nóminas, soldar tuberías o reparar motores son 'habilidades duras' y específicas." },
    { u: "IPLE T8", q: "La 'adaptabilidad' es una cualidad esencial debido a:", opts: ["Que las oficinas son pequeñas.", "El mercado laboral en constante cambio y evolución tecnológica.", "Que hay que cambiar de ropa a menudo.", "La normativa de incendios."], ans: 1, exp: "Con la entrada de la inteligencia artificial y la automatización, solo los perfiles que se adapten a los cambios sobrevivirán laboralmente." },
    { u: "IPLE T8", q: "¿Qué es la 'asertividad'?", opts: ["Estar siempre de acuerdo con el jefe.", "Expresar opiniones y derechos de forma clara y respetuosa sin ser agresivo ni pasivo.", "Gritar más fuerte que los demás.", "No decir nunca nada."], ans: 1, exp: "Saber decir 'no' a un exceso de carga de trabajo de manera educada pero firme es un ejemplo de asertividad." },
    { u: "IPLE T8", q: "El Plan de Acción debe incluir:", opts: ["Solo los sueños de la infancia.", "Pasos concretos, recursos necesarios y plazos para alcanzar metas profesionales.", "Una lista de la compra.", "Los nombres de los futuros hijos."], ans: 1, exp: "El plan es tu hoja de ruta calendarizada para que tus metas no se queden en meras ilusiones." },
    { u: "IPLE T8", q: "La formación profesional 'dual' se caracteriza por:", opts: ["Estudiar dos idiomas a la vez.", "Combinar la formación en el centro educativo con el aprendizaje en una empresa.", "Tener dos profesores en clase.", "Hacer el examen dos veces."], ans: 1, exp: "Es el modelo donde el alumno compagina las clases teóricas con prácticas reales y evaluables directamente en una empresa contratante." },
    { u: "IPLE T8", q: "El título de 'Técnico Superior' se obtiene tras cursar:", opts: ["Un Grado Medio.", "Un Grado Superior.", "La Universidad.", "La ESO."], ans: 1, exp: "Es la titulación académica oficial que otorga la FP de Grado Superior." },
    { u: "IPLE T8", q: "Las 'convalidaciones' permiten:", opts: ["No pagar la matrícula.", "No cursar módulos que ya se han superado en otras formaciones equivalentes.", "Aprobar sin estudiar nada de nada.", "Cambiar de nombre el título."], ans: 1, exp: "Evita que tengas que repetir materias comunes (como FOL o Empresa) si ya las aprobaste en un ciclo anterior." },
    { u: "IPLE T8", q: "Un trabajador desocupado puede acceder a formación profesional:", opts: ["No, es solo para los que trabajan.", "Sí, a través de programas de formación para el empleo.", "Solo si tiene menos de 20 años.", "Solo si vive en una gran ciudad."], ans: 1, exp: "Existen cursos INEM/SEPE gratuitos diseñados expresamente para que las personas en paro adquieran nuevas destrezas y encuentren trabajo." },
    { u: "IPLE T8", q: "La 'identificación de fortalezas' es parte de:", opts: ["La entrevista de despido.", "El autoconocimiento.", "El pago de la nómina.", "La limpieza del taller."], ans: 1, exp: "Reconocer qué se te da mejor que al resto de candidatos te permite enfocarte y brillar en los procesos de selección." },
    { u: "IPLE T8", q: "El mercado laboral actual valora especialmente la capacidad de:", opts: ["No cambiar nunca de opinión.", "Aprendizaje continuo (re-skilling y up-skilling).", "Quedarse quieto.", "Ignorar la tecnología."], ans: 1, exp: "Las empresas buscan empleados que sean capaces de reinventarse y aprender a utilizar herramientas nuevas rápidamente." },
    { u: "IPLE T8", q: "El 'Proyecto Profesional' es:", opts: ["Un dibujo de una casa.", "El diseño de la propia carrera profesional a corto, medio y largo plazo.", "El nombre de una asignatura solamente.", "Un contrato de alquiler."], ans: 1, exp: "Tener tu proyecto profesional definido es saber hacia dónde diriges tus esfuerzos en el mercado de trabajo." },
    { u: "IPLE T8", q: "Para acceder a la Universidad desde la FP de Grado Superior:", opts: ["Hay que hacer de nuevo la ESO.", "Se puede acceder directamente a grados relacionados.", "Está prohibido por ley desde 2021.", "Hay que pagar una multa."], ans: 1, exp: "La FP Superior abre la puerta a la educación universitaria, y dependiendo de las materias, puede eximirte de hacer la fase general de Selectividad." },
    { u: "IPLE T8", q: "Las simulaciones y prácticas en empresas sirven para evaluar:", opts: ["La paciencia.", "Las destrezas reales en el entorno de trabajo.", "La calidad de la comida del comedor.", "El color de los cables."], ans: 1, exp: "Es la única forma de demostrar cómo te desenvuelves bajo presión real en un taller u oficina." },
    { u: "IPLE T8", q: "¿Qué significa 'orientación laboral'?", opts: ["Saber dónde está el norte.", "El proceso de ayuda para que el individuo gestione su carrera y busque empleo de forma eficiente.", "Seguir las órdenes de los padres siempre.", "Leer el horóscopo del trabajo."], ans: 1, exp: "La labor del orientador laboral es brindar información, consejos y herramientas para facilitar la inserción de una persona en el mercado." },
    { u: "IPLE T8", q: "La responsabilidad es considerada una:", opts: ["Destreza técnica manual.", "Cualidad personal.", "Herramienta informática.", "Marca de ropa de seguridad."], ans: 1, exp: "Al igual que la honestidad o la puntualidad, la responsabilidad es una cualidad moral del carácter del trabajador." },
    { u: "IPLE T8", q: "La evaluación de competencias sociales se puede realizar mediante:", opts: ["Dinámicas de grupo y observación de la interacción.", "Exámenes escritos de gramática.", "Pruebas de levantamiento de pesas.", "Radiografías de tórax."], ans: 0, exp: "Poniendo a varios candidatos a debatir juntos, el evaluador puede comprobar su asertividad, capacidad de escucha y liderazgo." },
    { u: "IPLE T8", q: "¿Qué es el SEPE?", opts: ["Un tipo de sensor de presión.", "El Servicio Público de Empleo Estatal.", "Un software de diseño 3D.", "El Sindicato de Estudiantes de Primaria."], ans: 1, exp: "El SEPE es el organismo estatal encargado de las políticas de empleo y las prestaciones por desempleo en España." },
    { u: "IPLE T8", q: "La 'motivación extrínseca' es aquella que viene de:", opts: ["El interior de la persona (satisfacción propia).", "Factores externos como el salario, premios o reconocimiento.", "Los planetas.", "El pasado lejano."], ans: 1, exp: "Lo 'extrínseco' es externo al trabajador: un bonus de dinero a fin de mes, una medalla al empleado del mes o una subida de rango." },
    { u: "IPLE T8", q: "¿Cuál es el primer paso para cambiar de carrera profesional según el modelo de auto-orientación?", opts: ["Renunciar al trabajo sin pensar.", "Realizar un proceso de autoconocimiento y análisis del mercado.", "Comprar un billete de avión.", "Borrar todas las redes sociales."], ans: 1, exp: "Nadie debe dar un salto al vacío sin antes evaluar sus propias fortalezas y comprobar si el mercado demanda la profesión a la que quiere cambiar." },
// --- PREGUNTAS DE LA PLATAFORMA (MOODLE) ---
    { u: "IPLE T9", q: "El aprendizaje permanente proporciona:", opts: ["Capacidad de adaptación a los cambios tecnológicos", "Mejora de la empleabilidad", "Satisfacción y motivación laboral", "Todas son correctas"], ans: 3, exp: "El 'Lifelong learning' o aprendizaje a lo largo de la vida dota al profesional de todas estas ventajas, haciéndolo más competitivo, adaptable y realizado en su trabajo." },
    { u: "IPLE T9", q: "Señala cuál de las siguientes no es una habilidad blanda:", opts: ["Asertividad", "Empatía", "Liderazgo", "Análisis de datos"], ans: 3, exp: "El 'análisis de datos' es una competencia técnica, medible y específica de una profesión, por lo que se considera una habilidad dura (Hard Skill)." },
    { u: "IPLE T9", q: "Establecer un horario de estudio y cumplirlo siempre, en la medida de lo posible, se considera:", opts: ["Networking", "Educación formal", "Autodisciplina", "Habilidad dura"], ans: 2, exp: "La autodisciplina es la habilidad personal de marcarse unas reglas (como un horario) y tener la fuerza de voluntad para cumplirlas de forma constante." },
    { u: "IPLE T9", q: "El modelo económico y laboral basado en trabajos temporales o de corta duración y el aumento de los trabajadores independientes, que ha redefinido las estructuras laborales tradicionales, se denomina:", opts: ["Economía gig", "Responsabilidad Social Corporativa", "Transformación digital", "Teletrabajo freelance"], ans: 0, exp: "La 'Economía gig' (o economía de pequeños encargos) es el modelo laboral basado en trabajos puntuales, temporales y autónomos (ej. repartidores de plataformas, diseñadores por proyecto)." },
    { u: "IPLE T9", q: "La capacidad de adaptación implica:", opts: ["La puesta en práctica de ciertas estrategias que ayuden a mejorar la comunicación efectiva", "Modificar y ajustar respuestas, acciones o enfoques en función de nuevas situaciones o condiciones cambiantes", "Renunciar a la empleabilidad en favor de una mayor flexibilidad laboral", "Todas son correctas"], ans: 1, exp: "Adaptarse significa tener la flexibilidad mental y operativa para cambiar tu forma de hacer las cosas cuando el entorno, la tecnología o las normas cambian." },
    { u: "IPLE T9", q: "¿Cuál de las siguientes no es una característica de los empleados resilientes?:", opts: ["Pasividad", "Optimismo realista", "Control emocional", "Autoconciencia"], ans: 0, exp: "La resiliencia implica acción y superación ante la adversidad. La pasividad (no hacer nada y dejarse llevar) es todo lo contrario a ser un profesional resiliente." },
    { u: "IPLE T9", q: "Con respecto a la identidad digital:", opts: ["También es conocida como identidad 1.0", "Se compone únicamente por los perfiles en redes sociales", "Los empleadores y reclutadores la utilizan cada vez más para evaluar a los candidatos", "Ninguna es correcta"], ans: 2, exp: "La huella digital de un candidato (lo que publica, comenta o comparte en Internet) es revisada rutinariamente por los equipos de Recursos Humanos antes de contratar a alguien." },
    { u: "IPLE T9", q: "Para la gestión de la privacidad y seguridad digital:", opts: ["No es necesario revisar las configuraciones de privacidad en las cuentas de redes sociales", "Hay que evitar usar un gestor de contraseñas, ya que no dan credenciales seguras", "La autenticación de dos factores resta una capa de seguridad", "Ninguna es correcta"], ans: 3, exp: "Todas las afirmaciones son falsas. Es vital revisar la privacidad, usar gestores de contraseñas seguros y activar siempre la autenticación de dos factores (2FA)." },
    { u: "IPLE T9", q: "La herramienta estratégica que ayuda a los profesionales a estructurar y dirigir su crecimiento y evolución en el ámbito laboral se denomina:", opts: ["Plan de Desarrollo Individual (PDI)", "Mapa de Habilidades", "Entorno de Desarrollo y Análisis (EDA)", "Autoconocimiento estratégico"], ans: 0, exp: "El PDI es el documento u hoja de ruta donde el profesional plasma sus metas a corto, medio y largo plazo y los pasos que dará para conseguirlas." },
    { u: "IPLE T9", q: "El Entorno Personal de Aprendizaje:", opts: ["Es perjudicial para tomar el control y la gestión del propio aprendizaje", "Se centra en la contribución a la organización (participación en proyectos de RSC y programas de mentoría)", "Es un sistema compuesto por diversos elementos (herramientas, fuentes de información, personas y actividades)", "Ninguna es correcta"], ans: 2, exp: "El EPA (o PLE en inglés) es el ecosistema único que cada persona se crea para aprender (su red de contactos, sus blogs favoritos, herramientas de software, etc.)." },

    // --- BLOQUE CUESTIONARIO DE AUTOEVALUACIÓN (70 PREGUNTAS) ---
    { u: "IPLE T9", q: "¿Qué supone el aprendizaje permanente según las diapositivas?", opts: ["Estudiar solo hasta obtener el título oficial.", "Buscar activamente oportunidades para crecer, mejorar y avanzar en la carrera profesional.", "Depender exclusivamente de los cursos que pague la empresa.", "Memorizar manuales técnicos una sola vez."], ans: 1, exp: "El aprendizaje permanente implica una actitud proactiva durante toda la vida laboral para no quedarse obsoleto." },
    { u: "IPLE T9", q: "El aprendizaje permanente permite al profesional:", opts: ["Trabajar menos horas al día.", "Tomar el control de su propio destino profesional.", "Jubilarse antes de tiempo.", "Ignorar los cambios tecnológicos."], ans: 1, exp: "Quien se forma continuamente no depende de las decisiones de su empresa, ya que siempre será valioso en el mercado laboral." },
    { u: "IPLE T9", q: "¿Cuál es un beneficio del aprendizaje continuo mencionado en el temario?", opts: ["Reducción del salario base.", "Mejora de la empleabilidad y capacidad de adaptación.", "Aislamiento social del trabajador.", "Disminución de la creatividad."], ans: 1, exp: "Aprender cosas nuevas te hace más empleable (atractivo para las empresas) y te prepara para afrontar cualquier cambio técnico." },
    { u: "IPLE T9", q: "¿Qué son las 'Habilidades Duras' (Hard Skills)?", opts: ["La resistencia física ante el esfuerzo.", "Conocimientos específicos y competencias técnicas relacionadas con las tareas del puesto.", "La capacidad de contar chistes en la oficina.", "La amabilidad con los clientes."], ans: 1, exp: "Son las competencias técnicas puras, como saber utilizar un programa de diseño o conocer la legislación fiscal." },
    { u: "IPLE T9", q: "Las 'Habilidades Blandas' (Soft Skills) se refieren a:", opts: ["El uso de software de edición de textos.", "Competencias relacionadas con la interacción interpersonal y la comunicación.", "El conocimiento de leyes físicas.", "La fuerza muscular del empleado."], ans: 1, exp: "Son las habilidades sociales y emocionales que permiten trabajar en equipo, comunicar bien y resolver conflictos." },
    { u: "IPLE T9", q: "¿Qué ejemplo corresponde a una habilidad dura para un técnico de laboratorio?", opts: ["Trabajo en equipo.", "Conocimiento de protocolos de seguridad química.", "Empatía con los compañeros.", "Gestión del estrés."], ans: 1, exp: "El conocimiento de química y seguridad en el laboratorio es una destreza técnica específica (Hard Skill)." },
    { u: "IPLE T9", q: "¿Cuál de estas es una habilidad blanda esencial en el entorno laboral actual?", opts: ["Programación en Python.", "Resolución de problemas y comunicación efectiva.", "Manejo de un osciloscopio.", "Soldadura industrial."], ans: 1, exp: "La capacidad para resolver problemas y hacerse entender (comunicación) son soft skills muy cotizadas." },
    { u: "IPLE T9", q: "El desarrollo de competencias a lo largo de la vida es un proceso que requiere:", opts: ["Solo suerte.", "Compromiso y proactividad por parte del individuo.", "Únicamente la asistencia a clase.", "Que el gobierno obligue a estudiar."], ans: 1, exp: "Nadie puede obligarte a aprender; requiere de tu propio esfuerzo, curiosidad y compromiso personal." },
    { u: "IPLE T9", q: "¿Qué permite la 'colaboración interdisciplinar'?", opts: ["Aprender solo lo de tu propia especialidad.", "Trabajar con profesionales de diferentes áreas para obtener nuevas perspectivas y habilidades.", "Competir con otros departamentos para ver quién es mejor.", "Reducir el número de empleados en la empresa."], ans: 1, exp: "Mezclar a ingenieros, diseñadores y economistas en un mismo equipo enriquece el proyecto aportando visiones complementarias." },
    { u: "IPLE T9", q: "El 'Networking' se define como:", opts: ["La instalación de cables de red en la oficina.", "Construir y mantener una red de contactos profesionales.", "El uso de redes sociales solo para ocio personal.", "La reparación de servidores informáticos."], ans: 1, exp: "Es el arte de tejer una red de contactos sólida que pueda ayudarte en el futuro a encontrar empleo, socios o clientes." },
    { u: "IPLE T9", q: "¿Cuál es el primer paso para la efectividad del aprendizaje autónomo?", opts: ["Comprar el ordenador más caro.", "Establecimiento de metas claras.", "Irse de vacaciones.", "Pedir un aumento de sueldo."], ans: 1, exp: "Si vas a aprender por tu cuenta, lo primero es saber exactamente qué quieres conseguir (fijar la meta)." },
    { u: "IPLE T9", q: "Las metas en el aprendizaje autónomo deben estar alineadas con:", opts: ["Los intereses y objetivos profesionales del individuo.", "Lo que digan los anuncios de la televisión.", "Únicamente los deseos de los familiares.", "El azar."], ans: 0, exp: "De nada sirve formarte en algo si no encaja con lo que realmente te gusta y con el camino profesional que has elegido." },
    { u: "IPLE T9", q: "La gestión del tiempo en el estudio implica:", opts: ["Estudiar 24 horas seguidas una vez al mes.", "Crear un horario o cronograma que dedique tiempo regular al aprendizaje.", "No planificar nada para ser más espontáneo.", "Estudiar solo cuando no haya nada que ver en Netflix."], ans: 1, exp: "Requiere planificación: agendar unas horas a la semana fijas y respetarlas para crear un hábito de estudio." },
    { u: "IPLE T9", q: "¿Por qué es recomendable utilizar una variedad de recursos de aprendizaje?", opts: ["Para gastar más dinero.", "Para obtener diferentes perspectivas y enriquecer el conocimiento (libros, cursos, vídeos, etc.).", "Porque es obligatorio por ley.", "Para confundirse con tanta información."], ans: 1, exp: "Combinar podcasts, artículos, vídeos y foros te permite entender un mismo concepto desde diferentes ángulos." },
    { u: "IPLE T9", q: "La fase de 'Reflexión y Evaluación' en el aprendizaje autónomo sirve para:", opts: ["Criticar a los profesores.", "Analizar lo aprendido, identificar áreas de mejora y ajustar la estrategia.", "Olvidar lo estudiado rápidamente.", "Compararse negativamente con otros."], ans: 1, exp: "Es pararse a pensar si el método de estudio está funcionando o si necesitas cambiar de enfoque." },
    { u: "IPLE T9", q: "¿Qué caracteriza al entorno laboral actual?", opts: ["La estabilidad absoluta y la falta de cambios.", "La globalización, la digitalización y el cambio constante.", "La vuelta a los procesos manuales del siglo XIX.", "Que no se requiere ninguna formación técnica."], ans: 1, exp: "Vivimos en la era de la información, donde todo fluye rápido, los mercados son globales y la tecnología evoluciona a diario (entornos VUCA)." },
    { u: "IPLE T9", q: "La habilidad de 'Adaptación' se define como la capacidad de:", opts: ["Mantenerse rígido ante las peticiones del jefe.", "Cambiar la forma de actuar en respuesta a nuevas demandas o métodos de trabajo.", "Quejarse de cada cambio tecnológico.", "Hacer siempre lo mismo durante 40 años."], ans: 1, exp: "Consiste en no frustrarse cuando las cosas cambian, sino moldear tu forma de trabajar a las nuevas exigencias." },
    { u: "IPLE T9", q: "¿Qué implica la 'Flexibilidad' laboral?", opts: ["Poder tocarse los pies con las manos.", "Ajustar planes, horarios y roles según las necesidades del momento.", "No tener ningún tipo de horario ni responsabilidad.", "Que el trabajador decida el salario de la empresa."], ans: 1, exp: "Un empleado flexible puede asumir hoy una tarea de diseño y mañana una de gestión sin que le suponga un trauma." },
    { u: "IPLE T9", q: "La capacidad de sobreponerse a situaciones límite y adversidades en el trabajo se llama:", opts: ["Pasividad.", "Resiliencia.", "Impaciencia.", "Negación."], ans: 1, exp: "Es el resorte psicológico que te permite caer, asimilar el golpe (ej. un proyecto fracasado) y volver a levantarte con fuerza." },
    { u: "IPLE T9", q: "Un trabajador resiliente es capaz de:", opts: ["Rendirse al primer fallo técnico.", "Mantener la productividad y el bienestar frente a desafíos y crisis.", "Culpar siempre a los demás de los errores.", "Trabajar sin descanso hasta enfermar."], ans: 1, exp: "No se hunde ante un ERE o una crisis, sino que mantiene la calma, busca soluciones y sigue aportando valor." },
    { u: "IPLE T9", q: "¿Qué es la 'Identidad Digital' o Identidad 2.0?", opts: ["El número del DNI escaneado.", "El conjunto de información sobre un individuo disponible en línea y su rastro digital.", "Una clave secreta para entrar en la empresa.", "El nombre de usuario del correo electrónico únicamente."], ans: 1, exp: "Es tu 'yo' virtual: todo lo que publicas, los likes que das, tus fotos y tus comentarios forman tu identidad en Internet." },
    { u: "IPLE T9", q: "¿Qué elementos construyen nuestra identidad digital profesional?", opts: ["Solo las fotos de las vacaciones.", "Perfiles en redes profesionales (LinkedIn), blogs, comentarios y publicaciones.", "El historial de compras en el supermercado.", "El color de la carcasa del móvil."], ans: 1, exp: "Las aportaciones en foros de tu sector, los artículos que compartes o tu currículum online forjan tu reputación profesional." },
    { u: "IPLE T9", q: "Un comportamiento adecuado en redes sociales es fundamental porque:", opts: ["Las empresas pueden revisar nuestra huella digital antes de contratarnos.", "Ayuda a ganar seguidores para ser 'influencer'.", "Evita que el ordenador se llene de virus.", "Permite navegar más rápido por Internet."], ans: 0, exp: "Los seleccionadores buscan tu nombre en Google para ver qué tipo de persona eres antes de ofrecerte un contrato." },
    { u: "IPLE T9", q: "La participación en foros y comunidades virtuales permite:", opts: ["Perder el tiempo durante la jornada laboral.", "Demostrar experiencia, aprender de otros y mejorar la visibilidad profesional.", "Insultar a la competencia de forma anónima.", "Descargar música ilegalmente."], ans: 1, exp: "Si aportas soluciones en un foro de programación, por ejemplo, los demás te verán como un experto y ganarás reputación." },
    { u: "IPLE T9", q: "¿Qué es el Entorno Personal de Aprendizaje (EPA)?", opts: ["El pupitre físico del estudiante.", "Un sistema de herramientas, fuentes y personas que ayudan a gestionar el propio aprendizaje.", "Un programa que se instala en el ordenador para aprobar exámenes.", "El departamento de formación de una empresa."], ans: 1, exp: "Tu EPA es todo aquello que utilizas para aprender a tu manera: tus contactos de Twitter, canales de YouTube, blogs de referencia, etc." },
    { u: "IPLE T9", q: "El EPA ayuda a las personas a:", opts: ["Delegar su aprendizaje en el jefe.", "Tomar el control y gestión de su propio proceso educativo.", "Estudiar menos contenido.", "Aprobar sin necesidad de leer."], ans: 1, exp: "Fomenta la autonomía: tú decides qué lees, a quién sigues y qué herramientas utilizas para nutrirte intelectualmente." },
    { u: "IPLE T9", q: "¿Cuál es un componente clave de un EPA?", opts: ["Solo los libros de texto.", "Herramientas digitales, recursos, contenidos y redes de colaboración.", "Únicamente el teléfono móvil.", "La televisión del salón."], ans: 1, exp: "Está compuesto por las fuentes donde lees la información, las herramientas donde creas contenido y la red donde lo compartes (PLN)." },
    { u: "IPLE T9", q: "La fase de 'Comunicación y Colaboración' en el EPA implica:", opts: ["No hablar con nadie para concentrarse mejor.", "Interactuar con otros profesionales para intercambiar conocimientos.", "Enviar correos masivos de publicidad (spam).", "Usar el chat solo para temas personales."], ans: 1, exp: "De nada sirve consumir información si no la discutes, rebates o compartes con otros expertos de tu Personal Learning Network." },
    { u: "IPLE T9", q: "¿Qué es el Plan de Desarrollo Individual (PDI)?", opts: ["Una lista de deseos para la Navidad.", "Una herramienta estratégica para estructurar y dirigir el crecimiento profesional.", "El contrato firmado con la empresa.", "Un informe de errores del pasado."], ans: 1, exp: "Es un documento vivo en el que escribes a dónde quieres llegar profesionalmente y el paso a paso detallado para conseguirlo." },
    { u: "IPLE T9", q: "El propósito del PDI es alcanzar metas profesionales a:", opts: ["Solo a corto plazo (mañana).", "Corto, medio y largo plazo.", "Solo cuando el trabajador se vaya a jubilar.", "Cuando el jefe lo ordene."], ans: 1, exp: "Cubre toda la línea temporal: desde qué curso harás este mes, hasta qué puesto directivo aspiras a tener en 5 años." },
    { u: "IPLE T9", q: "¿Cuál es la primera fase del PDI?", opts: ["Establecimiento de objetivos.", "Evaluación introspectiva (autodiagnóstico).", "Compra de material escolar.", "Celebración del éxito."], ans: 1, exp: "Antes de planificar nada, tienes que pararte a analizar fríamente cuáles son tus puntos fuertes y en qué fallas actualmente." },
    { u: "IPLE T9", q: "En la fase de 'Establecimiento de Objetivos' del PDI, estos deben ser:", opts: ["Imposibles de medir.", "Claros y específicos.", "Los mismos para todos los trabajadores.", "Muy genéricos y vagos."], ans: 1, exp: "Si el objetivo no es específico (método SMART), será imposible saber si lo has cumplido o no." },
    { u: "IPLE T9", q: "¿Qué incluye el 'Cronograma' en un PDI?", opts: ["La lista de precios de los cursos.", "La asignación de plazos para cada objetivo y acción.", "El menú del comedor de la empresa.", "Los nombres de los profesores."], ans: 1, exp: "Es el calendario: ponerle fecha límite a cada acción para evitar procrastinar y posponer tu formación indefinidamente." },
    { u: "IPLE T9", q: "La fase de 'Estrategias de Aprendizaje' define:", opts: ["El salario que se quiere cobrar.", "Cómo se van a adquirir las competencias (cursos, mentoría, práctica).", "El color del título que se va a obtener.", "Dónde se van a guardar los libros."], ans: 1, exp: "Responde a la pregunta de '¿Cómo lo voy a hacer?': buscando un tutor, matriculándome en un máster, viendo tutoriales..." },
    { u: "IPLE T9", q: "La 'Evaluación del Progreso' en el PDI debe ser:", opts: ["Una vez en la vida.", "Periódica y continua para realizar ajustes.", "Solo si el jefe lo pide.", "Inexistente para no desmotivarse."], ans: 1, exp: "El plan debe revisarse cada x meses para ver si estás cumpliendo los plazos o si necesitas cambiar de táctica." },
    { u: "IPLE T9", q: "¿Por qué es necesario realizar ajustes en el PDI?", opts: ["Porque el plan original siempre está mal.", "Para adaptarse a cambios en el mercado, nuevas tecnologías o metas personales.", "Para perder el tiempo en papeleo.", "Porque los planes no sirven de nada."], ans: 1, exp: "Si a mitad de tu plan surge una nueva tecnología (como la Inteligencia Artificial), debes ajustar tu PDI para aprender a usarla." },
    { u: "IPLE T9", q: "El 'feedback' o retroalimentación de colegas y mentores sirve para:", opts: ["Discutir en la oficina.", "Revelar áreas de mejora o nuevas competencias necesarias.", "Saber quién es el más popular.", "Ignorar las opiniones ajenas."], ans: 1, exp: "A veces uno no ve sus propios fallos. Un colega o jefe te puede señalar qué 'soft skill' te falta pulir." },
    { u: "IPLE T9", q: "Si llega un desafío imprevisto que bloquea el plan, se debe:", opts: ["Abandonar el plan para siempre.", "Cambiar la estrategia o enfoque para superar el obstáculo.", "Seguir haciendo lo mismo aunque no funcione.", "Quejarse al departamento de recursos humanos."], ans: 1, exp: "La resiliencia en la planificación consiste en buscar una ruta alternativa cuando la ruta principal se corta." },
    { u: "IPLE T9", q: "¿Qué estrategia ayuda a adaptar el plan correctamente?", opts: ["Hacer todas las tareas a la vez sin orden.", "Restablecer el orden de prioridad de las metas según relevancia y urgencia.", "Dejar de formarse.", "Borrar el cronograma."], ans: 1, exp: "Si surge algo más importante que requiere tu atención inmediata, reordenas las prioridades y pospones lo menos urgente." },
    { u: "IPLE T9", q: "Explorar nuevas fuentes de formación como seminarios o talleres es parte de:", opts: ["El mantenimiento correctivo.", "La actualización constante del plan de desarrollo.", "El tiempo de ocio obligatorio.", "La evaluación de riesgos eléctricos."], ans: 1, exp: "Te permite estar siempre expuesto a las últimas tendencias y mantener tu PDI dinámico e innovador." },
    { u: "IPLE T9", q: "¿Qué significa 'Up-skilling'?", opts: ["Aprender una profesión totalmente distinta.", "Mejorar las habilidades actuales para ser más eficaz en el puesto actual.", "Subir de piso en el edificio de la empresa.", "Comprar herramientas de mejor calidad."], ans: 1, exp: "Consiste en perfeccionar lo que ya sabes hacer. (Ej: Eres programador en Java y haces un curso para ser programador avanzado de Java)." },
    { u: "IPLE T9", q: "¿Qué es el 'Re-skilling'?", opts: ["Volver a estudiar lo que ya se sabe.", "Adquirir nuevas competencias para desempeñar un puesto o rol diferente.", "Limpiar las habilidades que no se usan.", "Cambiar de marca de ordenador."], ans: 1, exp: "Es el reciclaje profesional completo: la empresa cierra tu sección y te forma en otra cosa totalmente distinta para no despedirte." },
    { u: "IPLE T9", q: "La 'autoevaluación' permite al profesional:", opts: ["Ser su propio jefe legalmente.", "Identificar fortalezas y debilidades de forma honesta.", "Ponerse la nota que quiera en el examen.", "Evitar el control de la empresa."], ans: 1, exp: "Es el proceso de mirarse al espejo profesionalmente sin autoengaños para saber exactamente qué te falta por aprender." },
    { u: "IPLE T9", q: "El aprendizaje permanente contribuye a la 'Innovación' porque:", opts: ["Obliga a usar robots.", "Aporta nuevas ideas y formas más eficientes de trabajar.", "Hace que las máquinas no se rompan.", "Reduce el coste del material de oficina."], ans: 1, exp: "Quien se forma continuamente descubre atajos, nuevas herramientas y mejoras que luego puede implantar en su empresa." },
    { u: "IPLE T9", q: "Una 'competencia transversal' es aquella que:", opts: ["Solo sirve para un tipo de tornillo.", "Es útil en múltiples situaciones, puestos y sectores profesionales.", "Se aprende cruzando los brazos.", "Solo conocen los directivos."], ans: 1, exp: "Como saber hablar en público o gestionar equipos: te servirá igual si trabajas en una fábrica, en un banco o en un hospital." },
    { u: "IPLE T9", q: "La satisfacción laboral aumenta con el aprendizaje continuo porque:", opts: ["Se tiene más tiempo libre.", "El trabajador se siente más competente y valorado.", "No hay que hacer exámenes.", "La empresa regala libros."], ans: 1, exp: "Dominar tu trabajo reduce la ansiedad y aumenta la autoconfianza, lo que te hace disfrutar mucho más del día a día." },
    { u: "IPLE T9", q: "¿Qué es la 'Huella Digital'?", opts: ["La marca que deja el dedo en la pantalla.", "El rastro de datos e información que dejamos al usar Internet.", "Un sistema de seguridad biométrico.", "La marca de un sensor de presión."], ans: 1, exp: "Son las 'migas de pan' que dejas en la red: comentarios en foros, fotos subidas, registros en páginas o búsquedas que has hecho." },
    { u: "IPLE T9", q: "Gestionar la huella digital implica:", opts: ["No usar nunca Internet.", "Ser consciente y cuidadoso con la información que publicamos.", "Borrar todo el historial cada hora.", "Usar un nombre falso siempre."], ans: 1, exp: "Significa pensar dos veces antes de subir una foto o un comentario incendiario que pueda perjudicar tu reputación profesional en el futuro." },
    { u: "IPLE T9", q: "La 'Curaduría de Contenidos' en el aprendizaje autónomo consiste en:", opts: ["Escribir libros nuevos.", "Seleccionar, organizar y filtrar la información más relevante de la red.", "Copiar y pegar todo lo que se encuentra.", "Leer solo el primer resultado de Google."], ans: 1, exp: "En Internet hay exceso de información (infoxicación). El 'curador' separa la información basura de las fuentes realmente útiles y fiables." },
    { u: "IPLE T9", q: "¿Cuál es un recurso de apoyo mencionado en el PDI?", opts: ["El manual de instrucciones del coche.", "Mentores, supervisores, colegas y capacitación formal.", "La lista de la compra de casa.", "Un mapa de la ciudad."], ans: 1, exp: "Tu plan de desarrollo no tienes por qué hacerlo solo; apoyarte en expertos, profesores o compañeros veteranos acelera tu aprendizaje." },
    { u: "IPLE T9", q: "El PDI es un documento de carácter:", opts: ["Estático (no se cambia nunca).", "Dinámico y flexible.", "Secreto e ilegal.", "Exclusivo para estudiantes de bachillerato."], ans: 1, exp: "Es un plan vivo. Debe poder tacharse, modificarse y adaptarse a medida que vas cumpliendo metas o cambias de intereses." },
    { u: "IPLE T9", q: "Un objetivo profesional 'alcanzable' es aquel que:", opts: ["Requiere superpoderes.", "Es realista considerando los recursos y el tiempo disponible.", "Se logra en menos de un segundo.", "Depende solo de la suerte."], ans: 1, exp: "Proponerse 'ser el CEO de Google mañana' no es un objetivo alcanzable. Debe estar proporcionado a tus posibilidades reales actuales." },
    { u: "IPLE T9", q: "La 'gestión de recursos' en el EPA incluye:", opts: ["Guardar folios en el cajón.", "Identificar y utilizar plataformas de cursos, bibliotecas digitales y redes.", "Ahorrar luz en la oficina.", "Pedir dinero al banco."], ans: 1, exp: "Consiste en saber exactamente en qué páginas web o en qué programas debes buscar la información cuando necesitas aprender algo nuevo." },
    { u: "IPLE T9", q: "La adaptabilidad tecnológica es crucial debido a:", opts: ["Que los ordenadores son bonitos.", "La rápida obsolescencia y aparición de nuevas herramientas digitales.", "Que hay que gastar el presupuesto de la empresa.", "La normativa de reciclaje de cables."], ans: 1, exp: "Lo que sabes usar hoy puede que no sirva dentro de 3 años, por lo que debes estar dispuesto a cambiar de herramientas sin frustrarte." },
    { u: "IPLE T9", q: "El 'aprendizaje basado en la práctica' se conoce como:", opts: ["Teoría pura.", "Learning by doing.", "Pasividad educativa.", "Olvido sistemático."], ans: 1, exp: "Aprender haciendo. Es la filosofía de que asimilas mucho mejor los conceptos si te equivocas aplicando la teoría en proyectos reales." },
    { u: "IPLE T9", q: "La identidad digital profesional puede ayudar a:", opts: ["Ocultar errores del pasado.", "Atraer oportunidades laborales y reclutadores.", "Hackear cuentas de redes sociales.", "Navegar sin conexión."], ans: 1, exp: "Un perfil de LinkedIn bien cuidado y con aportaciones valiosas atrae a los cazatalentos (headhunters) sin que tengas que enviar tú el currículum." },
    { u: "IPLE T9", q: "¿Qué es un 'Mentor'?", opts: ["Un programa de inteligencia artificial.", "Una persona con experiencia que guía y aconseja a otra en su desarrollo.", "Un inspector de hacienda.", "Un sensor de temperatura avanzado."], ans: 1, exp: "Es un figura clave: un profesional veterano que te toma bajo su tutela para transmitirte su sabiduría y evitar que cometas los mismos errores que él." },
    { u: "IPLE T9", q: "Las 'comunidades de práctica' son:", opts: ["Grupos de amigos que salen de fiesta.", "Grupos de personas que comparten un interés o profesión y aprenden juntas.", "Departamentos cerrados de una empresa.", "Clubes de lectura de novelas de ficción."], ans: 1, exp: "Son foros (online o presenciales) donde gente del mismo gremio se reúne voluntariamente para intercambiar trucos, dudas y experiencias." },
    { u: "IPLE T9", q: "El autodiagnóstico inicial del PDI sirve para:", opts: ["Saber qué nota se va a sacar en el examen.", "Conocer el punto de partida y las necesidades reales de formación.", "Pedir la baja médica.", "Comprar ropa de trabajo nueva."], ans: 1, exp: "Te da el 'punto A' en tu mapa. Solo sabiendo exactamente qué te falta, puedes trazar la ruta hacia el 'punto B' (tu objetivo)." },
    { u: "IPLE T9", q: "La 'motivación intrínseca' nace de:", opts: ["Las ganas de cobrar un premio.", "El interés personal y la satisfacción de aprender por uno mismo.", "El miedo al despido.", "Las órdenes de los padres."], ans: 1, exp: "Es el fuego interno. Aprendes a tocar un instrumento o a programar simplemente porque te apasiona y te realiza, no porque te paguen por ello." },
    { u: "IPLE T9", q: "El EPA es un sistema:", opts: ["Cerrado y proporcionado por el estado.", "Abierto y personalizado por cada individuo.", "Que solo funciona con conexión por cable.", "Exclusivo para ingenieros informáticos."], ans: 1, exp: "No hay dos Entornos Personales de Aprendizaje iguales. Cada persona configura sus favoritos, sus suscripciones y sus redes según le gusta aprender." },
    { u: "IPLE T9", q: "¿Qué supone 'tomar el control del destino profesional'?", opts: ["Mandar en la empresa desde el primer día.", "Ser proactivo en la formación y búsqueda de oportunidades.", "No hacer caso a las leyes laborales.", "Trabajar solo de autónomo."], ans: 1, exp: "Significa que no esperas a que la empresa te organice un curso o te ascienda, sino que tú mismo te formas y buscas tú las oportunidades de mejorar." },
    { u: "IPLE T9", q: "La flexibilidad ante el cambio de rol dentro de una empresa requiere:", opts: ["Enfado y resistencia.", "Una actitud abierta y disposición a aprender nuevas funciones.", "Dimisión inmediata.", "No decir nada a nadie."], ans: 1, exp: "Si la empresa elimina tu departamento, la flexibilidad te permite reciclarte ('re-skilling') y aceptar con actitud positiva el cambio a un puesto nuevo." },
    { u: "IPLE T9", q: "Las herramientas de organización (como calendarios digitales) son parte del:", opts: ["Mantenimiento predictivo.", "Eje de gestión del tiempo en el aprendizaje autónomo.", "Riesgo ergonómico.", "Sistema de incendios."], ans: 1, exp: "El Google Calendar, Trello o Notion son vitales para agendar tus horas de estudio y gestionar que cumplas los plazos de tu PDI." },
    { u: "IPLE T9", q: "El 'equilibrio entre corto y largo plazo' en el PDI significa:", opts: ["No hacer nada hoy para hacerlo todo dentro de diez años.", "Combinar acciones inmediatas con metas que requieren años de preparación.", "Trabajar solo media jornada.", "Estudiar solo los fines de semana."], ans: 1, exp: "Mientras trabajas en un proyecto enorme (ej. sacar una carrera en 4 años), vas cumpliendo pequeños hitos semanales (ej. aprobar una asignatura)." },
    { u: "IPLE T9", q: "La formación interdisciplinar mejora la 'resolución de problemas' porque:", opts: ["Se tienen más herramientas y enfoques diferentes para abordar un desafío.", "Se conoce el nombre de todos los empleados.", "Se puede culpar a otros departamentos.", "Se gasta menos papel."], ans: 0, exp: "Al tener conocimientos de varias ramas (ej. saber de diseño y también de psicología), tu cerebro puede aportar soluciones creativas y fuera de lo común." },
    { u: "IPLE T9", q: "Linkedin es una herramienta fundamental para:", opts: ["Ver vídeos de gatitos.", "El networking y la gestión de la identidad digital profesional.", "Comprar componentes electrónicos baratos.", "Jugar en línea con amigos."], ans: 1, exp: "Es la red social profesional por excelencia, diseñada para exponer tu currículum, logros y conectar con empresas y colegas del sector." },
    { u: "IPLE T9", q: "¿Qué es la 'obsolescencia de competencias'?", opts: ["Cuando una herramienta se oxida.", "Cuando los conocimientos de un profesional dejan de ser útiles o válidos por el avance tecnológico.", "Cuando un trabajador cumple 65 años.", "Cuando se borra el programa del PLC."], ans: 1, exp: "Al igual que a los móviles se les acaba la vida útil, si un contable solo sabe hacer cuentas a mano, sus competencias quedarán obsoletas frente al que sabe usar software financiero." },
    { u: "IPLE T9", q: "La resiliencia contribuye al 'bienestar en el trabajo' porque:", opts: ["El trabajador nunca tiene problemas.", "Ayuda a gestionar el estrés y a recuperarse de los contratiempos.", "Permite dormir en la oficina.", "Aumenta los días de vacaciones."], ans: 1, exp: "Un trabajador resiliente no se amarga profundamente ante una bronca del jefe o un error grave, lo que protege enormemente su salud mental a largo plazo." },
    { u: "IPLE T9", q: "El objetivo final de la Unidad 9 es que el profesional sea:", opts: ["Un experto en una sola cosa para siempre.", "Competente, adaptable y comprometido con su desarrollo continuo.", "Capaz de trabajar sin usar ninguna herramienta digital.", "El que más títulos tenga colgados en la pared."], ans: 1, exp: "Busca formar al 'profesional del futuro': alguien que, más allá de sus conocimientos técnicos iniciales, tenga la actitud y las herramientas para no dejar de evolucionar." }
];
